    private final ThreadLocal<JsonNode> turnAuthoringManifest = new ThreadLocal<>();
    private final ThreadLocal<JsonNode> turnDataProfile = new ThreadLocal<>();

    public AiOrchestratorResponse generatePatch(
            AiOrchestratorRequest request,
            String requestBaseUrl,
            String tenantId,
            String userId,
            String environment) {
        long observationStartedAt = System.nanoTime();
        String resolvedUserPrompt = resolveUserPrompt(request);
        if (resolvedUserPrompt == null || resolvedUserPrompt.isBlank()) {
            return error("Prompt vazio.");
        }
        request.setUserPrompt(resolvedUserPrompt);
        interactionLogger.logDiagnostic(request, "request_timeline", buildRequestTimelineSnapshot(request));
        UUID observationId = captureObservation(
                request,
                tenantId,
                userId,
                environment,
                resolvedUserPrompt);

        AiMemoryContext memoryContext = null;
        try {
            AiContextDTO context = contextService.buildContext(
                    request.getComponentId(),
                    request.getComponentType(),
                    request.getAiMode(),
                    request.getRequireSchema(),
                    request.getCurrentState(),
                    request.getResourcePath(),
                    request.getSchemaContext());

            if (context.getComponentDefinition() == null) {
                AiOrchestratorResponse response = unknownComponentError(request);
                applyObservationMetadata(response, observationId);
                markObservationAdmission(observationId, "unknown_component", response.getCode(), response.getMessage());
                markObservationCompleted(observationId, response, observationStartedAt);
                return response;
            }

            JsonNode currentState = context.getCurrentState();
            JsonNode authoringManifest = normalizeAuthoringManifest(
                    context.getComponentId(),
                    extractAuthoringManifest(context.getComponentDefinition()));
            List<AiCapability> configCapabilities = extractCapabilities(context.getComponentDefinition());
            List<AiCapability> componentCapabilities = extractComponentCapabilities(context.getComponentDefinition());
            JsonNode componentContext = extractComponentContextPack(context.getComponentDefinition());
            JsonNode authoringContract = resolveAuthoringContract(
                    request.getContextHints(),
                    context,
                    authoringManifest);
            authoringManifest = augmentAuthoringManifestFromRuntimeContract(
                    context.getComponentId(),
                    authoringManifest,
                    authoringContract);
            turnAuthoringManifest.set(authoringManifest);
            turnDataProfile.set(request.getDataProfile());
            AiOrchestratorResponse admissionResponse = assistantAdmissionService != null
                    ? assistantAdmissionService.evaluate(
                            request,
                            authoringContract,
                            authoringManifest,
                            configCapabilities,
                            componentCapabilities,
                            componentContext)
                    : null;
            if (admissionResponse != null) {
                applyObservationMetadata(admissionResponse, observationId);
                markObservationAdmission(
                        observationId,
                        resolveAdmissionOutcome(admissionResponse),
                        admissionResponse.getCode(),
                        admissionResponse.getMessage());
                markObservationCompleted(observationId, admissionResponse, observationStartedAt);
                return admissionResponse;
            }
            markObservationAdmission(observationId, "allowed", null, null);

            AiThread thread = threadService.resolveThread(
                    request,
                    tenantId,
                    userId,
                    environment,
                    resolvedUserPrompt);
            memoryContext = messageService.prepareTurn(
                    thread,
                    request,
                    resolvedUserPrompt);
            linkObservation(observationId, memoryContext);
            AiOrchestratorResponse cachedResponse = memoryContext != null
                    ? memoryContext.getCachedResponse()
                    : null;
            if (cachedResponse != null) {
                messageService.applyMemoryMetadata(cachedResponse, memoryContext);
                applyObservationMetadata(cachedResponse, observationId);
                linkObservation(observationId, memoryContext);
                markObservationCompleted(observationId, cachedResponse, observationStartedAt);
                return cachedResponse;
            }
            String modelPrompt = buildPromptWithMemory(resolvedUserPrompt, memoryContext);
            String planningPrompt = resolveCurrentTurnPlanningPrompt(resolvedUserPrompt, memoryContext);

            List<String> warnings = new ArrayList<>();
            if (authoringManifest != null && authoringManifest.isObject()) {
                warnings.add("authoring-manifest-contract-used");
            }
            if (COMPONENT_ID_TABLE.equals(request.getComponentId())) {
                warnings.add("table-local-text-routing-disabled-before-llm");
            }

            AiCallConfig frontendConfig = resolveFrontendCallConfig(tenantId, userId, environment);
            frontendConfig = withRagRelease(frontendConfig, request.getRagReleaseId());
            EmbeddingService.EmbeddingCallConfig embeddingConfig =
                    resolveEmbeddingCallConfig(tenantId, userId, environment);

        AiOrchestratorResponse pageBuilderPreviewResponse = tryHandlePageBuilderLocalEditorialAuthoring(
                request,
                context,
                tenantId,
                userId,
                environment);
        if (pageBuilderPreviewResponse != null) {
            return finalizeResponse(pageBuilderPreviewResponse, memoryContext);
        }

        AiOrchestratorResponse createFlowResponse = tryHandleCreateFlow(
                request,
                context,
                embeddingConfig,
                tenantId,
                environment);
        if (createFlowResponse != null) {
            return finalizeResponse(createFlowResponse, memoryContext);
        }

        AiOrchestratorResponse templateIntentResponse =
                tryHandleTemplateCreateIntent(request, context, frontendConfig);
        if (templateIntentResponse != null) {
            return finalizeResponse(templateIntentResponse, memoryContext);
        }

        TemplateSelection templateSelection = resolveTemplateVariant(request, context, embeddingConfig);
        if (templateSelection.template != null) {
            context.setTemplate(templateSelection.template);
        }
        if (templateSelection.warnings != null && !templateSelection.warnings.isEmpty()) {
            warnings.addAll(templateSelection.warnings);
        }
        if (log.isDebugEnabled()) {
            log.debug(
                    "[AiOrchestratorService] Context loaded componentId={} template={} hasDefinition={}",
                    context.getComponentId(),
                    context.getTemplate() != null ? context.getTemplate().getComponentId() : "none",
                    context.getComponentDefinition() != null);
        }

        AiOrchestratorResponse templateResponse = tryHandleTemplateFlow(
                request,
                context,
                embeddingConfig,
                tenantId,
                environment);
        if (templateResponse != null) {
            if (!warnings.isEmpty()) {
                templateResponse.setWarnings(warnings);
            }
            return finalizeResponse(templateResponse, memoryContext);
        }

        boolean requireSchema = context.isRequireSchema();
        AiSchemaContext schemaContext = context.getSchemaContext();
        JsonNode resolvedSchema = null;

        if (requireSchema) {
            SchemaResolution schemaResolution = resolveSchema(
                    request,
                    context,
                    requestBaseUrl,
                    embeddingConfig,
                    tenantId,
                    environment);
            if (schemaResolution.response != null) {
                return finalizeResponse(schemaResolution.response, memoryContext);
            }
            schemaContext = schemaResolution.schemaContext;
            resolvedSchema = schemaResolution.schema;
        }

        String runtimeMetadata = truncateBlock(
                "runtime_metadata",
                safeMetadata(formatRuntimeMetadata(
                        request.getDataProfile(),
                        request.getSchemaFields(),
                        request.getRuntimeState(),
                        request.getContextHints())),
                maxRuntimeMetadataChars);
        List<ColumnDescriptor> uiColumnDescriptors = extractColumnDescriptors(currentState);
        List<ColumnDescriptor> columnDescriptors = mergeColumnDescriptors(uiColumnDescriptors, request.getDataProfile());
        List<String> columnNames = extractColumnNames(columnDescriptors);
        List<String> availableFields = mergeAvailableFields(columnNames, request.getDataProfile());
        String fieldTypeHints = buildFieldTypeHints(request.getDataProfile());
        List<String> columnOptions = buildColumnOptions(columnDescriptors);
        List<String> inputKeys = extractObjectKeys(currentState, "inputs");
        List<String> outputKeys = extractObjectKeys(currentState, "outputs");

        String ragHints = ragContextService.buildRagHints(
                request.getUserPrompt(),
                componentContext,
                context.getTemplate() != null ? context.getTemplate().getTemplateMeta() : null,
                embeddingConfig);
        ragHints = appendOptionalPromptBlock(
                ragHints,
                domainCatalogPromptContext(
                        request.getUserPrompt(),
                        request.getContextHints(),
                        tenantId,
                        environment));
        String ragHintsBlock = truncateBlock(
                "rag_hints",
                safeMetadata(ragHints),
                maxRagHintsChars);
        List<ComponentAction> componentActions = extractComponentActions(componentContext);
        boolean isTable = COMPONENT_ID_TABLE.equals(request.getComponentId());
        Set<String> allowedActionTypes = resolveAllowedActionTypes(componentActions, isTable);
        List<String> columnResolverKeys = isTable
                ? resolveFieldResolverKeys(componentContext, "columns[].field")
                : List.of();
        List<ContextOption> baseFormatOptions = isTable
                ? resolveOptionsForPath(componentContext, configCapabilities, "columns[].format")
                : List.of();
        SelectedFormatSelection selectedFormat = extractSelectedFormatFromHints(request.getContextHints());
        SelectedRendererSelection selectedRenderer = extractSelectedRendererFromHints(request.getContextHints());
        List<ContextOption> formatOptions = isTable
                ? augmentFormatOptionsForPrompt(
                        baseFormatOptions,
                        request.getUserPrompt(),
                        selectedFormat != null ? selectedFormat.targetField : null)
                : List.of();
        ArrayNode targetCandidates = !isTable
                ? buildTargetCandidates(componentContext, currentState)
                : objectMapper.createArrayNode();
        List<String> targetOptions = !isTable
                ? buildTargetOptions(targetCandidates)
                : List.of();
        List<String> configCategories = extractCategoryNames(configCapabilities);
        List<String> componentCategories = extractCategoryNames(componentCapabilities);
        if (request.getSuggestedPatch() != null && !request.getSuggestedPatch().isNull()) {
            return finalizeResponse(applySuggestedPatch(
                    request.getSuggestedPatch(),
                    currentState,
                    request.getComponentId(),
                    warnings,
                    configCapabilities,
                    componentCapabilities,
                    componentContext), memoryContext);
        }

        AiOrchestratorResponse contextHintPatch = tryApplyContextHintPatch(
                request.getContextHints(),
                currentState,
                request.getComponentId(),
                warnings,
                configCapabilities,
                componentCapabilities,
                componentContext);
        if (contextHintPatch != null) {
            return finalizeResponse(contextHintPatch, memoryContext);
        }

        if (selectedFormat != null && !isBlank(selectedFormat.value)) {
            JsonNode selectedPatch = buildFormatPatchFromSelection(
                    selectedFormat,
                    null,
                    columnDescriptors,
                    columnResolverKeys);
            if (selectedPatch != null) {
                JsonNode selectedPlan = buildComponentEditPlanFromPatch(
                        request.getComponentId(),
                        selectedPatch,
                        authoringManifest,
                        warnings);
                if (selectedPlan != null && selectedPlan.isObject()) {
                    ObjectNode planResult = objectMapper.createObjectNode();
                    planResult.set("componentEditPlan", selectedPlan);
                    planResult.put(
                            "explanation",
                            buildSelectedFormatReviewMessage(selectedFormat, columnDescriptors));
                    warnings.add("format-option-selected-context-hint-manifest-backed");
                    return finalizeResponse(
                            componentEditPlanResponse(planResult, request, warnings, authoringManifest),
                            memoryContext);
                }
                warnings.add("Formato selecionado aplicado via contexto estruturado.");
                return finalizeResponse(applySuggestedPatch(
                        selectedPatch,
                        currentState,
                        request.getComponentId(),
                        warnings,
                        configCapabilities,
                        componentCapabilities,
                        componentContext,
                        true), memoryContext);
            }
        }

        String selectedResponseMode = selectAuthoringResponseMode(
                planningPrompt,
                authoringContract,
                request,
                frontendConfig);
        if (shouldResolveSelectedRecordFilterCandidateDecision(selectedResponseMode)) {
            JsonNode selectedRecordsRuntimeFilterPatchFromSemanticHints =
                    buildSelectedRecordsRuntimeFilterPatchFromSemanticContextHints(request, authoringManifest);
            if (selectedRecordsRuntimeFilterPatchFromSemanticHints != null
                    && selectedRecordsRuntimeFilterPatchFromSemanticHints.isObject()) {
                selectedRecordsRuntimeFilterPatchFromSemanticHints = appendTableRuntimeExportIfRequested(
                        selectedRecordsRuntimeFilterPatchFromSemanticHints,
                        request,
                        authoringManifest,
                        "filtered");
                warnings.add("table-runtime-filter gerado a partir de decisao semantica de clarification.");
                return finalizeResponse(
                        tableRuntimeOperationResponse(
                                selectedRecordsRuntimeFilterPatchFromSemanticHints,
                                request,
                                warnings,
                                "Vou aplicar o filtro com base nas linhas selecionadas."),
                        memoryContext);
            }
            AiOrchestratorResponse selectedRecordFilterCandidateDecision =
                    resolveSelectedRecordFilterCandidateDecision(
                            planningPrompt,
                            request,
                            authoringManifest,
                            frontendConfig,
                            warnings);
            if (selectedRecordFilterCandidateDecision != null) {
                return finalizeResponse(selectedRecordFilterCandidateDecision, memoryContext);
            }
        } else {
            warnings.add("selected-record-filter-candidate-resolver-skipped-by-response-mode:"
                    + selectedResponseMode);
        }
        if ("consult".equals(selectedResponseMode)) {
            AiOrchestratorResponse response = info(answerQuestion(
                    resolvedUserPrompt,
                    currentState,
                    request,
                    frontendConfig,
                    authoringContract));
            AiIntentClassification consultIntent = classifyConsultIntentSafely(
                    planningPrompt,
                    availableFields,
                    inputKeys,
                    outputKeys,
                    configCategories,
                    componentCategories,
                    runtimeMetadata,
                    fieldTypeHints,
                    authoringContract,
                    request,
                    frontendConfig,
                    warnings);
            if (consultIntent != null) {
                consultIntent = normalizeIntent(
                        consultIntent,
                        request != null ? request.getContextHints() : null,
                        request != null ? request.getUserPrompt() : null,
                        columnDescriptors,
                        columnResolverKeys,
                        availableFields,
                        columnOptions,
                        configCategories,
                        componentCategories,
                        isTable,
                        warnings);
            }
            JsonNode selectedRecordsRuntimeFilterPatchFromConsultIntent =
                    buildSelectedRecordsRuntimeFilterPatchFromIntent(
                            consultIntent,
                            request,
                            authoringManifest);
            if (selectedRecordsRuntimeFilterPatchFromConsultIntent != null
                    && selectedRecordsRuntimeFilterPatchFromConsultIntent.isObject()) {
                selectedRecordsRuntimeFilterPatchFromConsultIntent = appendTableRuntimeExportIfRequested(
                        selectedRecordsRuntimeFilterPatchFromConsultIntent,
                        request,
                        authoringManifest,
                        "filtered");
                warnings.add("table-runtime-filter gerado a partir de decisao semantica consultiva.");
                return finalizeResponse(
                        tableRuntimeOperationResponse(
                                selectedRecordsRuntimeFilterPatchFromConsultIntent,
                                request,
                                warnings,
                                "Vou aplicar o filtro com base nas linhas selecionadas."),
                        memoryContext);
            }
            JsonNode tableRuntimeExportPatchFromConsultIntent = buildTableRuntimeExportPatchFromIntent(
                    consultIntent,
                    request,
                    authoringManifest);
            if (tableRuntimeExportPatchFromConsultIntent != null
                    && tableRuntimeExportPatchFromConsultIntent.isObject()) {
                warnings.add("table-runtime-export gerado a partir de decisao semantica consultiva.");
                return finalizeResponse(
                        tableRuntimeOperationResponse(
                                tableRuntimeExportPatchFromConsultIntent,
                                request,
                                warnings,
                                "Vou exportar os dados solicitados da tabela."),
                        memoryContext);
            }
            String governedFormatAnswer = answerTableFormatCapabilityQuestion(
                    request != null ? request.getUserPrompt() : null,
                    currentState,
                    formatOptions);
            if (governedFormatAnswer != null
                    && consultIntent != null
                    && "format".equalsIgnoreCase(consultIntent.getCategory())) {
                response.setMessage(governedFormatAnswer);
                warnings.add("table-format-capability-consultative-answer-used");
            }
            return finalizeResponse(
                    attachConsultativeTableActionOptions(
                            response,
                            request,
                            currentState,
                            formatOptions,
                            consultIntent,
                            request != null ? request.getDataProfile() : null),
                    memoryContext);
        }

        AiIntentClassification intent = classifyIntent(
                planningPrompt,
                availableFields,
                inputKeys,
                outputKeys,
                configCategories,
                componentCategories,
                runtimeMetadata,
                fieldTypeHints,
                authoringContract,
                request,
                frontendConfig);

        if (intent == null) {
            return finalizeResponse(error("Falha ao classificar a intenção do usuário."), memoryContext);
        }
        intent = normalizeIntent(
                intent,
                request != null ? request.getContextHints() : null,
                request != null ? request.getUserPrompt() : null,
                columnDescriptors,
                columnResolverKeys,
                availableFields,
                columnOptions,
                configCategories,
                componentCategories,
                isTable,
                warnings);
        adjustPageBuilderCreateIntent(intent, request, context);
        if (isTable) {
            warnings.add("table-computed-text-fast-path-disabled");
        }
        if (selectedFormat == null) {
            selectedFormat = extractSelectedFormatFromLlmIntentOptions(intent, formatOptions);
            if (selectedFormat != null) {
                JsonNode forcedPatch = buildFormatPatchFromSelection(
                        selectedFormat,
                        intent,
                        columnDescriptors,
                        columnResolverKeys);
                if (forcedPatch != null) {
                    warnings.add("Formato selecionado por ação guiada aplicado via intenção LLM.");
                    return finalizeResponse(applySuggestedPatch(
                            forcedPatch,
                            currentState,
                            request.getComponentId(),
                            warnings,
                            configCapabilities,
                            componentCapabilities,
                            componentContext,
                            true), memoryContext);
                }
            }
        } else if (!isBlank(selectedFormat.value)) {
            JsonNode selectedPatch = buildFormatPatchFromSelection(
                    selectedFormat,
                    intent,
                    columnDescriptors,
                    columnResolverKeys);
            if (selectedPatch != null) {
                JsonNode selectedPlan = buildComponentEditPlanFromPatch(
                        request.getComponentId(),
                        selectedPatch,
                        authoringManifest,
                        warnings);
                if (selectedPlan != null && selectedPlan.isObject()) {
                    ObjectNode planResult = objectMapper.createObjectNode();
                    planResult.set("componentEditPlan", selectedPlan);
                    planResult.put(
                            "explanation",
                            buildSelectedFormatReviewMessage(selectedFormat, columnDescriptors));
                    warnings.add("format-option-selected-manifest-backed");
                    return finalizeResponse(
                            componentEditPlanResponse(planResult, request, warnings, authoringManifest),
                            memoryContext);
                }
                warnings.add("Formato selecionado aplicado via contexto.");
                return finalizeResponse(applySuggestedPatch(
                        selectedPatch,
                        currentState,
                        request.getComponentId(),
                        warnings,
                        configCapabilities,
                        componentCapabilities,
                        componentContext,
                        true), memoryContext);
            }
        }
        if (selectedRenderer != null) {
            AiActionPlan selectedRendererPlan = buildSelectedRendererActionPlan(
                    selectedRenderer,
                    intent,
                    currentState,
                    columnDescriptors,
                    columnResolverKeys);
            JsonNode selectedRendererManifestPlan = buildComponentEditPlanFromActionPlan(
                    selectedRendererPlan,
                    authoringManifest);
            if (selectedRendererManifestPlan != null && selectedRendererManifestPlan.isObject()) {
                ObjectNode planResult = objectMapper.createObjectNode();
                planResult.set("componentEditPlan", selectedRendererManifestPlan);
                planResult.put(
                        "explanation",
                        buildActionPlanComponentEditExplanation(
                                selectedRendererPlan,
                                columnDescriptors,
                                "Vou aplicar a apresentação visual escolhida na tabela."));
                warnings.add("renderer-option-selected-manifest-backed");
                return finalizeResponse(
                        componentEditPlanResponse(planResult, request, warnings, authoringManifest),
                        memoryContext);
            }
        }
        if (shouldOfferFormatChoiceFromLlmIntent(isTable, intent, selectedFormat)) {
            ClarificationPayload payload = buildFormatClarificationPayload(
                    intent,
                    formatOptions,
                    request != null ? request.getDataProfile() : null);
            if (payload != null && !payload.options.isEmpty()) {
                warnings.add("format-choice-offered-from-llm-intent-options");
                return finalizeResponse(clarification(
                        buildFormatChoiceMessage(intent, columnDescriptors),
                        payload.options,
                        payload.payloads),
                        memoryContext);
            }
        }
        if (shouldOfferRendererChoiceFromLlmIntent(
                isTable,
                intent,
                request != null ? request.getContextHints() : null)
                || shouldOfferRendererChoiceFromConsultativePrompt(
                isTable,
                intent,
                request != null ? request.getContextHints() : null,
                request != null ? request.getUserPrompt() : null)) {
            List<String> rendererOptions = intent.getOptions();
            if (rendererOptions == null || rendererOptions.isEmpty()) {
                rendererOptions = defaultRendererOptionsForField(intent.getTargetField());
            }
            List<AiOption> payloads = buildRendererOptionPayloads(
                    intent.getTargetField(),
                    rendererOptions);
            if (!payloads.isEmpty()) {
                warnings.add("renderer-choice-offered-from-llm-intent-options");
                return finalizeResponse(clarification(
                        buildRendererChoiceMessage(intent, columnDescriptors),
                        buildAiOptionLabels(payloads),
                        payloads),
                        memoryContext);
            }
        }
        AiActionPlan actionPlan = null;
        List<AiActionItem> expectedActions = List.of();
        boolean createOnlyPlan = false;
        List<String> missingContext = intent.getMissingContext();
        boolean shouldProbeTableActions = shouldProbeTableActionsForMissingContext(
                isTable,
                componentActions,
                missingContext,
                request,
                currentState,
                columnDescriptors);
        if (shouldProbeTableActions) {
            actionPlan = extractTableActionPlan(
                    planningPrompt,
                    columnDescriptors,
                    formatOptions,
                    componentActions,
                    ragHintsBlock,
                    context,
                    request,
                    frontendConfig,
                    resolvedSchema,
                    embeddingConfig,
                    tenantId,
                    environment,
                    authoringManifest);
        }
        if (shouldIgnoreColumnClarification(isTable, columnNames, missingContext)) {
            missingContext = removeMissingContext(missingContext, "column");
            intent.setMissingContext(missingContext == null || missingContext.isEmpty() ? null : missingContext);
            if (intent.getMissingContext() == null) {
                intent.setNeedsClarification(false);
            }
        }
        if (shouldIgnoreMissingColumnForCreate(intent, actionPlan, componentActions)) {
            missingContext = removeMissingContext(intent.getMissingContext(), "column");
            intent.setMissingContext(missingContext == null || missingContext.isEmpty() ? null : missingContext);
            if (intent.getMissingContext() == null) {
                intent.setNeedsClarification(false);
            }
        }
        if (shouldIgnoreCategoryClarification(intent, componentActions)) {
            intent.setNeedsClarification(false);
            intent.setMissingContext(null);
            if (intent.getOptions() != null && !intent.getOptions().isEmpty()) {
                intent.setOptions(null);
            }
            warnings.add("Categoria indefinida ignorada devido a actionCatalog disponível.");
        }
        if (Boolean.TRUE.equals(intent.getNeedsClarification())
                || (missingContext != null && !missingContext.isEmpty())) {
            if (selectedFormat != null
                    && "format".equalsIgnoreCase(intent.getCategory())
                    && !isBlank(selectedFormat.value)) {
                intent.setNeedsClarification(false);
                intent.setMissingContext(null);
                JsonNode forcedPatch = buildFormatPatchFromSelection(
                        selectedFormat,
                        intent,
                        columnDescriptors,
                        columnResolverKeys);
                if (forcedPatch != null) {
                    warnings.add("Formato selecionado aplicado via contexto.");
                    return finalizeResponse(applySuggestedPatch(
                            forcedPatch,
                            currentState,
                            request.getComponentId(),
                            warnings,
                            configCapabilities,
                            componentCapabilities,
                            componentContext,
                            true), memoryContext);
                }
            }
            if (isTable && hasManifestBackedGlobalAction(actionPlan, authoringManifest)) {
                intent.setNeedsClarification(false);
                intent.setMissingContext(null);
                if (intent.getOptions() != null && !intent.getOptions().isEmpty()) {
                    intent.setOptions(null);
                }
                warnings.add("Clarificacao de coluna adiada para action plan global manifest-backed da tabela.");
            } else if (shouldDeferComponentClarificationToActionPlan(
                    intent,
                    request,
                    componentActions,
                    authoringManifest)) {
                intent.setNeedsClarification(false);
                intent.setMissingContext(null);
                if (intent.getOptions() != null && !intent.getOptions().isEmpty()) {
                    intent.setOptions(null);
                }
                warnings.add("Clarificacao de classificacao adiada para action plan manifest-backed.");
            } else if (canBypassClarification(intent, componentActions)) {
                intent.setNeedsClarification(false);
                intent.setMissingContext(null);
                if (intent.getOptions() != null && !intent.getOptions().isEmpty()) {
                    intent.setOptions(null);
                }
                warnings.add("Clarificacao ignorada para toggle simples; aplicando defaults.");
            } else {
                ComputedDefaultResolution computedDefaults = resolveComputedDefaultsForClarification(
                        intent,
                        request,
                        currentState,
                        configCapabilities,
                        componentCapabilities,
                        componentContext);
                if (computedDefaults != null) {
                    warnings.add("Clarificacao ignorada; defaults aplicados para coluna calculada.");
                    return finalizeResponse(applySuggestedPatch(
                            computedDefaults.patch,
                            currentState,
                            request.getComponentId(),
                            warnings,
                            configCapabilities,
                            componentCapabilities,
                            componentContext,
                            true), memoryContext);
                }
                AiOrchestratorResponse badgeResolution = tryResolveBadgeMissingContext(
                        intent,
                        request,
                        currentState,
                        warnings,
                        configCapabilities,
                        componentCapabilities,
                        componentContext);
                if (badgeResolution != null) {
                    return finalizeResponse(badgeResolution, memoryContext);
                }
                AiOrchestratorResponse resourceClarification = resolveResourceClarification(
                        request,
                        intent,
                        embeddingConfig,
                        tenantId,
                        environment);
                if (resourceClarification != null) {
                    return finalizeResponse(resourceClarification, memoryContext);
                }
                missingContext = intent.getMissingContext();
                if (Boolean.TRUE.equals(intent.getNeedsClarification())
                        || (missingContext != null && !missingContext.isEmpty())) {
                    if (isTable && shouldOfferFilterFieldClarification(intent)) {
                        ClarificationPayload filterFieldPayload = buildFilterFieldClarificationPayloadFromPrompt(request);
                        if (filterFieldPayload != null && !filterFieldPayload.options.isEmpty()) {
                            warnings.add("filter-field-catalog-clarification-from-human-prompt");
                            return finalizeResponse(
                                    clarification(
                                            "Encontrei filtros parecidos. Qual deles voce quer usar?",
                                            filterFieldPayload.options,
                                            filterFieldPayload.payloads),
                                    memoryContext);
                        }
                    }
                    if (isTable
                            && "format".equalsIgnoreCase(intent.getCategory())
                            && isSensitiveMaskField(intent.getTargetField())) {
                        ClarificationPayload payload = buildFormatClarificationPayload(
                                intent,
                                formatOptions,
                                request != null ? request.getDataProfile() : null);
                        return finalizeResponse(clarification(
                                buildClarificationMessage(intent, request),
                                payload.options,
                                payload.payloads), memoryContext);
                    }
                    ClarificationPayload columnPayload = buildColumnClarificationPayload(
                            intent,
                            columnDescriptors,
                            columnOptions);
                    if (columnPayload != null && !columnPayload.options.isEmpty()) {
                        return finalizeResponse(
                                clarification(buildClarificationMessage(intent, request),
                                        columnPayload.options,
                                        columnPayload.payloads),
                                memoryContext);
                    }
                    return finalizeResponse(
                            clarification(buildClarificationMessage(intent, request), intent.getOptions()),
                            memoryContext);
                }
            }
        }
        if ("ask_about_config".equalsIgnoreCase(intent.getIntent())) {
            String tableFormatAnswer = answerTableFormatCapabilityQuestion(
                    request != null ? request.getUserPrompt() : null,
                    currentState,
                    formatOptions);
            if (tableFormatAnswer != null) {
                warnings.add("table-format-capability-consultative-answer-used");
                AiOrchestratorResponse response = info(tableFormatAnswer);
                List<AiOption> actionOptions = buildTableDateFormatActionOptions(
                        request != null ? request.getUserPrompt() : null,
                        currentState,
                        formatOptions);
                if (!actionOptions.isEmpty()) {
                    response.setOptionPayloads(actionOptions);
                }
                return finalizeResponse(
                        attachConsultativeTableActionOptions(
                                response,
                                request,
                                currentState,
                                formatOptions,
                                intent,
                                request != null ? request.getDataProfile() : null),
                        memoryContext);
            }
            String answer = answerQuestion(resolvedUserPrompt, currentState, request, frontendConfig, authoringContract);
            AiOrchestratorResponse response = info(answer);
            return finalizeResponse(
                    attachConsultativeTableActionOptions(
                            response,
                            request,
                            currentState,
                            formatOptions,
                            intent,
                            request != null ? request.getDataProfile() : null),
                    memoryContext);
        }

        if (isTable && !componentActions.isEmpty()) {
            if (actionPlan == null) {
                actionPlan = extractTableActionPlan(
                        planningPrompt,
                        columnDescriptors,
                        formatOptions,
                        componentActions,
                        ragHintsBlock,
                        context,
                        request,
                        frontendConfig,
                        resolvedSchema,
                        embeddingConfig,
                        tenantId,
                        environment,
                        authoringManifest);
            }
            actionPlan = completeManifestBackedActionPlanInputs(
                    actionPlan,
                    request,
                    targetCandidates,
                    currentState,
                    authoringManifest,
                    warnings);
            if (isActionPlanEmpty(actionPlan)) {
                warnings.add("table-action-plan-empty-without-local-text-fallback");
            }
            actionPlan = applyActionPlanDefaults(actionPlan, componentActions);
            actionPlan = applySingleActionTargetFallback(
                    actionPlan,
                    intent,
                    columnDescriptors,
                    columnResolverKeys);
            actionPlan = normalizeActionPlanFormatValues(
                    actionPlan,
                    formatOptions,
                    request != null ? request.getUserPrompt() : null,
                    warnings);
            normalizeTableBooleanLabelActionsFromPrompt(
                    request != null ? request.getUserPrompt() : null,
                    actionPlan,
                    currentState);
            actionPlan = pruneTableActionPlanByClassifiedIntent(
                    actionPlan,
                    intent,
                    componentActions,
                    authoringManifest,
                    warnings);
            actionPlan = dedupeIdempotentTableActionsByTarget(actionPlan, warnings);
            String safetyMessage = tableActionPlanSafetyViolationMessage(actionPlan);
            if (safetyMessage != null) {
                warnings.add("table-action-plan-blocked-by-semantic-safety-guardrail");
                return finalizeResponse(clarification(safetyMessage, null), memoryContext);
            }
            Set<String> globalActions = identifyGlobalActions(componentActions);
            expectedActions = normalizePlanActions(
                    actionPlan,
                    columnDescriptors,
                    allowedActionTypes,
                    columnResolverKeys,
                    globalActions);
            if (expectedActions.isEmpty()) {
                warnings.add("table-expected-actions-empty-without-local-text-fallback");
            }
            expectedActions = applyPlanValueFallback(
                    expectedActions,
                    actionPlan,
                    intent,
                    columnDescriptors,
                    allowedActionTypes,
                    columnResolverKeys);
            expectedActions = applySelectedFormatOverride(
                    expectedActions,
                    selectedFormat,
                    intent,
                    columnDescriptors,
                    columnResolverKeys,
                    warnings);
            expectedActions = applyInferredMissingFormatValues(
                    expectedActions,
                    request != null ? request.getUserPrompt() : null,
                    formatOptions,
                    warnings);
            expectedActions = dropEmptyActionsShadowedByClear(expectedActions);

            List<String> ambiguityOptions = collectAmbiguityOptions(actionPlan);
            boolean hasAmbiguity = actionPlan != null
                    && actionPlan.getAmbiguities() != null
                    && !actionPlan.getAmbiguities().isEmpty();
            createOnlyPlan = isCreateOnlyPlan(actionPlan, componentActions);
            JsonNode selectedRecordsRuntimeFilterPatchFromHints = buildSelectedRecordsRuntimeFilterPatchFromContextHints(
                    request,
                    authoringManifest);
            if (selectedRecordsRuntimeFilterPatchFromHints != null && selectedRecordsRuntimeFilterPatchFromHints.isObject()) {
                warnings.add("table-runtime-filter gerado a partir de selecao e filtro escolhido em clarification.");
                return finalizeResponse(
                        tableRuntimeOperationResponse(
                                selectedRecordsRuntimeFilterPatchFromHints,
                                request,
                                warnings,
                                "Vou aplicar o filtro com base nas linhas selecionadas."),
                        memoryContext);
            }
            if (hasAmbiguity
                    && expectedActions.isEmpty()
                    && !createOnlyPlan
                    && !isGlobalTableActionIntent(intent)) {
                List<String> options = !ambiguityOptions.isEmpty()
                        ? ambiguityOptions
                        : columnOptions;
                JsonNode categoricalContinuationPlan = buildCategoricalRendererContinuationPlanFromAmbiguity(
                        actionPlan,
                        options,
                        request,
                        intent != null ? intent.getTargetField() : null,
                        currentState,
                        authoringManifest,
                        warnings);
                if (categoricalContinuationPlan != null && categoricalContinuationPlan.isObject()) {
                    ObjectNode planResult = objectMapper.createObjectNode();
                    planResult.set("componentEditPlan", categoricalContinuationPlan);
                    planResult.put(
                            "explanation",
                            "Vou continuar o ajuste visual no chip selecionado.");
                    return finalizeResponse(
                            componentEditPlanResponse(planResult, request, warnings, authoringManifest),
                            memoryContext);
                }
                List<AiOption> payloads = buildFilterFieldOptionPayloads(
                        options,
                        request != null ? request.getContextHints() : null);
                if (payloads.isEmpty()) {
                    payloads = buildColumnOptionPayloads(options, columnDescriptors);
                }
                List<String> labels = buildAiOptionLabels(payloads);
                return finalizeResponse(clarification(
                        "Preciso da coluna correta para aplicar o ajuste.",
                        labels.isEmpty() ? options : labels,
                        payloads.isEmpty() ? null : payloads), memoryContext);
            }
            List<String> unknownFields = findUnknownActionFields(
                    expectedActions,
                    availableFields,
                    componentActions,
                    authoringManifest);
            if (!unknownFields.isEmpty() && !createOnlyPlan) {
                List<String> suggestions = suggestClosestColumns(unknownFields, columnDescriptors);
                String message = buildUnknownColumnsMessage(unknownFields, suggestions);
                List<String> options = suggestions.isEmpty() ? columnOptions : suggestions;
                List<AiOption> payloads = buildColumnOptionPayloads(options, columnDescriptors);
                List<String> labels = buildAiOptionLabels(payloads);
                return finalizeResponse(clarification(
                        message,
                        labels.isEmpty() ? options : labels,
                        payloads.isEmpty() ? null : payloads), memoryContext);
            }
            EnumValidationResult exportFormatValidation = validateDirectExportFormatPrompt(
                    request != null ? request.getUserPrompt() : null);
            if (exportFormatValidation != null && !exportFormatValidation.valid) {
                return finalizeResponse(invalidEnumValue(exportFormatValidation, warnings), memoryContext);
            }
            AiActionItem missingFormat = findFormatActionMissingValue(expectedActions);
            if (missingFormat != null) {
                String inferredFormat = inferMissingFormatValue(
                        missingFormat,
                        request != null ? request.getUserPrompt() : null,
                        formatOptions);
                if (inferredFormat != null) {
                    expectedActions = replaceMissingFormatValue(expectedActions, missingFormat, inferredFormat);
                    warnings.add("Formato inferido para coluna '" + missingFormat.getField() + "': '" + inferredFormat + "'.");
                    missingFormat = findFormatActionMissingValue(expectedActions);
                }
            }
            if (missingFormat != null) {
                ColumnDescriptor target = findColumnByField(missingFormat.getField(), columnDescriptors);
                String label = target != null
                        ? displayColumnLabel(target, countHeaders(columnDescriptors))
                        : missingFormat.getField();
                List<ContextOption> choices = formatOptions;
                List<AiOption> formatPayloads = null;
                if (isSensitiveMaskField(missingFormat.getField())) {
                    choices = buildMaskOptionsForField(missingFormat.getField());
                    formatPayloads = buildMaskOptionPayloads(missingFormat.getField(), choices);
                }
                List<String> formatChoices = buildOptionLabels(choices);
                if (formatPayloads == null || formatPayloads.isEmpty()) {
                    formatPayloads = buildOptionPayloads(choices);
                }
                String message = formatChoices.isEmpty()
                        ? "Informe o formato desejado para a coluna " + label + "."
                        : "Qual formato deseja aplicar na coluna " + label + "?";
                return finalizeResponse(clarification(
                        message,
                        formatChoices,
                        formatPayloads), memoryContext);
            }
            JsonNode selectedRecordsRuntimeFilterPatchFromIntent = buildSelectedRecordsRuntimeFilterPatchFromIntent(
                    intent,
                    request,
                    authoringManifest);
            if (selectedRecordsRuntimeFilterPatchFromIntent != null
                    && selectedRecordsRuntimeFilterPatchFromIntent.isObject()) {
                selectedRecordsRuntimeFilterPatchFromIntent = appendTableRuntimeExportIfRequested(
                        selectedRecordsRuntimeFilterPatchFromIntent,
                        request,
                        authoringManifest,
                        "filtered");
                warnings.add("table-runtime-filter gerado a partir de selecao e alvo semantico da intencao.");
                return finalizeResponse(
                        tableRuntimeOperationResponse(
                                selectedRecordsRuntimeFilterPatchFromIntent,
                                request,
                                warnings,
                                "Vou aplicar o filtro com base nas linhas selecionadas."),
                        memoryContext);
            }
            JsonNode tableRuntimeExportPatchFromIntent = buildTableRuntimeExportPatchFromIntent(
                    intent,
                    request,
                    authoringManifest);
            if (tableRuntimeExportPatchFromIntent != null
                    && tableRuntimeExportPatchFromIntent.isObject()) {
                warnings.add("table-runtime-export gerado a partir de decisao semantica da intencao.");
                return finalizeResponse(
                        tableRuntimeOperationResponse(
                                tableRuntimeExportPatchFromIntent,
                                request,
                                warnings,
                                "Vou exportar os dados solicitados da tabela."),
                        memoryContext);
            }
            JsonNode tableRuntimeOperationPatch = buildTableRuntimeOperationPatchFromActionPlan(
                    actionPlan,
                    authoringManifest);
            if (tableRuntimeOperationPatch != null && tableRuntimeOperationPatch.isObject()) {
                warnings.add("table-runtime-operation gerada a partir do action plan manifest-backed.");
                return finalizeResponse(
                        tableRuntimeOperationResponse(
                                tableRuntimeOperationPatch,
                                request,
                                warnings,
                                "Vou executar a operacao solicitada na tabela."),
                        memoryContext);
            }
            JsonNode selectedRecordsRuntimeFilterPatch = buildSelectedRecordsRuntimeFilterPatchFromActionPlan(
                    actionPlan,
                    request,
                    authoringManifest);
            if (selectedRecordsRuntimeFilterPatch != null && selectedRecordsRuntimeFilterPatch.isObject()) {
                warnings.add("table-runtime-filter gerado a partir de selecao e alvo semantico do action plan.");
                return finalizeResponse(
                        tableRuntimeOperationResponse(
                                selectedRecordsRuntimeFilterPatch,
                                request,
                                warnings,
                                "Vou aplicar o filtro com base nas linhas selecionadas."),
                        memoryContext);
            }
            JsonNode tableManifestBackedPlan = buildComponentEditPlanFromActionPlan(actionPlan, authoringManifest);
            if (tableManifestBackedPlan != null && tableManifestBackedPlan.isObject()) {
                ObjectNode planResult = objectMapper.createObjectNode();
                planResult.set("componentEditPlan", tableManifestBackedPlan);
                planResult.put(
                        "explanation",
                        buildActionPlanComponentEditExplanation(
                                actionPlan,
                                columnDescriptors,
                                "Plano de edicao da tabela gerado a partir do action plan e validado pelo authoringManifest."));
                warnings.add("componentEditPlan de tabela gerado a partir do action plan manifest-backed.");
                return finalizeResponse(
                        componentEditPlanResponse(planResult, request, warnings, authoringManifest),
                        memoryContext);
            }
        } else if (!componentActions.isEmpty()) {
            actionPlan = extractComponentActionPlan(
                    planningPrompt,
                    componentActions,
                    targetCandidates,
                    ragHintsBlock,
                    context,
                    request,
                    frontendConfig,
                    resolvedSchema,
                    embeddingConfig,
                    tenantId,
                    environment);
            if (isActionPlanEmpty(actionPlan)) {
                AiActionPlan fallbackComponentPlan = deriveFallbackComponentActionPlan(
                        request,
                        componentActions,
                        targetCandidates,
                        authoringManifest);
                if (fallbackComponentPlan != null) {
                    actionPlan = fallbackComponentPlan;
                    warnings.add("componentEditPlan inferido deterministicamente para pedido simples manifest-backed.");
                }
            }
            actionPlan = completeManifestBackedActionPlanInputs(
                    actionPlan,
                    request,
                    targetCandidates,
                    currentState,
                    authoringManifest,
                    warnings);
            actionPlan = applyActionPlanDefaults(actionPlan, componentActions);
            actionPlan = suppressLocalEditorialResourceBindingActions(actionPlan, request, warnings);
            ActionPlanClarification clarification = resolveActionPlanClarification(
                    actionPlan,
                    componentActions,
                    targetOptions,
                    authoringManifest);
            if (clarification != null) {
                return finalizeResponse(clarification(clarification.message, clarification.options), memoryContext);
            }
            createOnlyPlan = isCreateOnlyPlan(actionPlan, componentActions);
            JsonNode manifestBackedPlan = buildComponentEditPlanFromActionPlan(actionPlan, authoringManifest);
            if (manifestBackedPlan != null && manifestBackedPlan.isObject()) {
                ObjectNode planResult = objectMapper.createObjectNode();
                planResult.set("componentEditPlan", manifestBackedPlan);
                planResult.put(
                        "explanation",
                        "Plano de edicao gerado a partir do action plan e validado pelo authoringManifest.");
                warnings.add("componentEditPlan gerado a partir do action plan manifest-backed.");
                return finalizeResponse(
                        componentEditPlanResponse(planResult, request, warnings, authoringManifest),
                        memoryContext);
            }
        }

        String scope = normalizeScope(intent.getScope());
        if ("component".equals(scope) && inputKeys.isEmpty() && outputKeys.isEmpty()) {
            warnings.add("Scope=component mas currentState nao inclui inputs/outputs; usando contexto completo.");
        }
        JsonNode contextConfig = resolveContextForScope(
                scope, request.getComponentId(), currentState, intent);
        List<AiCapability> scopedCapabilities = selectCapabilitiesByScope(
                scope, configCapabilities, componentCapabilities);
        List<AiCapability> filteredCaps = filterCapabilities(
                request.getComponentId(), intent.getCategory(), scope, scopedCapabilities);
        if ((filteredCaps == null || filteredCaps.isEmpty())
                && configCapabilities != null
                && !configCapabilities.isEmpty()) {
            List<AiCapability> fallback = filterCapabilities(
                    request.getComponentId(), intent.getCategory(), "config", configCapabilities);
            if (fallback == null || fallback.isEmpty()) {
                fallback = configCapabilities;
            }
            filteredCaps = fallback;
            warnings.add("Capabilities filtradas vazias; usando fallback de configuracoes.");
            if ("component".equals(scope)) {
                scope = "config";
                intent.setScope(scope);
                contextConfig = resolveContextForScope(
                        "config", request.getComponentId(), currentState, intent);
                warnings.add("Fallback aplicado ao contexto (config) devido a scope=component.");
            }
        }
        if (log.isDebugEnabled()) {
            log.debug(
                    "[AiOrchestratorService] Capabilities selected scope={} category={} count={} samplePaths={}",
                    scope,
                    intent.getCategory(),
                    filteredCaps != null ? filteredCaps.size() : 0,
                    summarizeCapabilityPaths(filteredCaps, 12));
        }
        IntentPlan intentPlan = generateIntentPlan(
                request,
                planningPrompt,
                context,
                filteredCaps,
                currentState,
                componentContext,
                frontendConfig,
                intent != null ? intent.getCategory() : null);
        intentPlan = applyDeterministicIntentChecks(
                intentPlan,
                actionPlan,
                componentActions,
                currentState,
                isTable,
                columnDescriptors,
                columnResolverKeys);
        List<String> planQuestions = intentPlan != null ? intentPlan.getQuestions() : null;
        if (planQuestions != null && !planQuestions.isEmpty()) {
            if (shouldIgnoreIntentPlanQuestions(intent, intentPlan, componentActions)
                    || (isTable && hasResolvedFormatAction(expectedActions))) {
                intentPlan.setQuestions(List.of());
                warnings.add("Perguntas do intent_plan ignoradas para acao ja resolvida; aplicando decisao inferida.");
            } else {
                if (!isTable) {
                    AiOrchestratorResponse deterministicFallback = tryResolveComputedFallback(
                            request,
                            currentState,
                            warnings,
                            configCapabilities,
                            componentCapabilities,
                            componentContext);
                    if (deterministicFallback != null) {
                        return finalizeResponse(deterministicFallback, memoryContext);
                    }
                    deterministicFallback = tryResolveRendererRuleFallback(
                            request,
                            currentState,
                            warnings,
                            configCapabilities,
                            componentCapabilities,
                            componentContext);
                    if (deterministicFallback != null) {
                        return finalizeResponse(deterministicFallback, memoryContext);
                    }
                } else {
                    warnings.add("table-intent-plan-question-local-text-fallback-disabled");
                }
                return finalizeResponse(clarification(buildQuestionsMessage(planQuestions), null), memoryContext);
            }
        }
        String intentPlanJson = formatIntentPlan(intentPlan);
        String capabilityNotes = formatCapabilityNotes(
                "component".equals(scope) || "mixed".equals(scope)
                        ? extractComponentCapabilityNotes(context.getComponentDefinition())
                        : List.of());
        String actionNotes = isTable
                ? formatActionNotes(expectedActions)
                : formatActionPlanNotes(actionPlan);
        String combinedNotes = joinNotes(capabilityNotes, actionNotes);

        Map<String, JsonNode> aiConcepts = extractAiConcepts(context.getComponentDefinition());
        List<String> relatedConceptIds = resolveRelatedConceptIds(componentActions, actionPlan, expectedActions);
        String conceptsBlock = formatConceptsForPrompt(aiConcepts, relatedConceptIds);
        if (log.isDebugEnabled() && relatedConceptIds != null && !relatedConceptIds.isEmpty()) {
            List<String> missingConcepts = resolveMissingConceptIds(aiConcepts, relatedConceptIds);
            log.debug(
                    "[AiOrchestratorService] Concepts resolved count={} chars={} missing={}",
                    relatedConceptIds.size(),
                    conceptsBlock != null ? conceptsBlock.length() : 0,
                    missingConcepts);
        }

        String prompt = buildExecutionPrompt(
                planningPrompt,
                context,
                contextConfig,
                filteredCaps,
                combinedNotes,
                conceptsBlock,
                schemaContext,
                resolvedSchema,
                runtimeMetadata,
                authoringContract,
                ragHintsBlock,
                intentPlanJson,
                null);

        JsonNode result = callAiJson("patch_generation", prompt, null, frontendConfig, request, 1);
        ContextRequest contextRequest = parseContextRequest(result);
        ActionPlanPatchResult actionPlanFallback = null;
        if (contextRequest != null && contextRequest.hasCodes() && createOnlyPlan) {
            actionPlanFallback = renderActionPlanPatch(actionPlan, componentActions);
            if (actionPlanFallback != null
                    && actionPlanFallback.patch != null
                    && actionPlanFallback.missingTokens.isEmpty()) {
                log.info("[AiOrchestratorService] contextRequest ignored; patch derived from action plan");
                ObjectNode fallbackResult = objectMapper.createObjectNode();
                fallbackResult.set("patch", actionPlanFallback.patch);
                result = fallbackResult;
                contextRequest = null;
                warnings.add("ContextRequest ignorado; patch derivado do action plan.");
            }
        }
        if (contextRequest != null && contextRequest.hasCodes()) {
            log.info("[AiOrchestratorService] contextRequest codes={} message={}",
                    contextRequest.codes,
                    contextRequest.message);
            ContextHintsBuildResult resolvedHints = buildContextHintsFromRequest(
                    context,
                    request,
                    resolvedSchema,
                    embeddingConfig,
                    contextRequest.codes,
                    tenantId,
                    environment,
                    warnings);
            if (resolvedHints.hints() != null && !resolvedHints.hints().isNull() && resolvedHints.hints().size() > 0) {
                log.info("[AiOrchestratorService] contextRequest resolved hints keys={}",
                        resolvedHints.hints().isObject()
                                ? resolveContextHintKeys(resolvedHints.hints())
                                : List.of("non-object"));
                JsonNode mergedHints = mergeContextHints(request.getContextHints(), resolvedHints.hints());
                String retryRuntimeMetadata = truncateBlock(
                        "runtime_metadata",
                        safeMetadata(formatRuntimeMetadata(
                                request.getDataProfile(),
                                request.getSchemaFields(),
                                request.getRuntimeState(),
                                mergedHints)),
                        maxRuntimeMetadataChars);
                String retryPrompt = buildExecutionPrompt(
                        planningPrompt,
                        context,
                        contextConfig,
                        filteredCaps,
                        combinedNotes,
                        conceptsBlock,
                        schemaContext,
                        resolvedSchema,
                        retryRuntimeMetadata,
                        authoringContract,
                        ragHintsBlock,
                        intentPlanJson,
                        null);
                JsonNode retryResult = callAiJson("patch_generation", retryPrompt, null, frontendConfig, request, 2);
                ContextRequest retryContextRequest = parseContextRequest(retryResult);
                if (retryContextRequest != null && retryContextRequest.hasCodes()) {
                    log.info("[AiOrchestratorService] contextRequest retry requested codes={} message={}",
                            retryContextRequest.codes,
                            retryContextRequest.message);
                    return finalizeResponse(withWarnings(
                            clarificationWithContextRequest(
                                    retryContextRequest.message,
                                    retryContextRequest.codes),
                            warnings), memoryContext);
                }
                result = retryResult;
            } else {
                log.info("[AiOrchestratorService] contextRequest could not be resolved");
                return finalizeResponse(
                        withWarnings(
                                clarificationWithContextRequest(contextRequest.message, contextRequest.codes),
                                warnings),
                        memoryContext);
            }
        }
        if (result == null || result.get("patch") == null) {
            if (createOnlyPlan) {
                if (actionPlanFallback == null) {
                    actionPlanFallback = renderActionPlanPatch(actionPlan, componentActions);
                }
                if (actionPlanFallback != null
                        && actionPlanFallback.patch != null
                        && actionPlanFallback.missingTokens.isEmpty()) {
                    warnings.add("Patch gerado a partir do action plan (fallback).");
                    ObjectNode fallbackResult = objectMapper.createObjectNode();
                    fallbackResult.set("patch", actionPlanFallback.patch);
                    result = fallbackResult;
                }
            }
        }
        if (result != null && result.get("patch") == null) {
            AiOrchestratorResponse clarification = parseClarificationFromResult(result);
            if (clarification != null) {
                return finalizeResponse(clarification, memoryContext);
            }
        }
        if (result != null && result.has("patch") && result.has("clarification")) {
            warnings.add("clarification ignorado: patch e clarification nao podem coexistir na mesma resposta.");
        }
        if (result != null && result.get("patch") == null && hasComponentEditPlan(result)) {
            return finalizeResponse(
                    componentEditPlanResponse(result, request, warnings, authoringManifest),
                    memoryContext);
        }
        if (result == null || result.get("patch") == null) {
            return finalizeResponse(error("Nenhum patch gerado."), memoryContext);
        }

        JsonNode patchNode = result.get("patch");
        String explanation = textOrNull(result.get("explanation"));

        boolean allowUnknownColumns = createOnlyPlan
                || (request != null && looksLikeCreateColumnPrompt(request.getUserPrompt()));
        SemanticPatchCheck semanticCheck = validateSemanticPatch(
                patchNode, currentState, warnings, allowUnknownColumns);
        if (!semanticCheck.valid) {
            if (semanticCheck.needsClarification) {
                return finalizeResponse(clarification(semanticCheck.message, semanticCheck.options), memoryContext);
            }
            return finalizeResponse(errorWithWarnings(semanticCheck.message, warnings), memoryContext);
        }
        patchNode = semanticCheck.patch;
        if (isTable) {
            warnings.add("table-deterministic-patch-relevance-fallback-disabled");
        }

        if (actionPlan != null
                && actionPlan.getActions() != null
                && !actionPlan.getActions().isEmpty()
                && componentActions != null
                && !componentActions.isEmpty()) {
            AiActionPlan resolvedPlan = isTable
                    ? resolveTableActionPlanTargets(actionPlan, columnDescriptors, columnResolverKeys)
                    : actionPlan;
            ActionPlanCoverage coverage = applyActionPlanCoverage(
                    resolvedPlan,
                    componentActions,
                    patchNode,
                    currentState);
            if (coverage.patch != null && !coverage.missingActions.isEmpty()) {
                patchNode = mergePatchNodes(patchNode, coverage.patch);
                warnings.add("Patch complementado com acoes do plano: "
                        + String.join(", ", coverage.missingActions));
                explanation = appendExplanation(
                        explanation,
                        "Apliquei acoes do plano: " + String.join(", ", coverage.missingActions) + ".");
            }
        }

        JsonNode normalizedPatch = normalizePatch(
                request.getComponentId(), patchNode);
        JsonNode manifestBackedPatchPlan = buildComponentEditPlanFromPatch(
                request.getComponentId(),
                normalizedPatch,
                authoringManifest,
                warnings);
        if (manifestBackedPatchPlan != null && manifestBackedPatchPlan.isObject()) {
            ObjectNode planResult = objectMapper.createObjectNode();
            planResult.set("componentEditPlan", manifestBackedPatchPlan);
            planResult.put(
                    "explanation",
                    "Patch de componente convertido para componentEditPlan validado pelo authoringManifest.");
            warnings.add("componentEditPlan gerado a partir de patch manifest-backed.");
            return finalizeResponse(
                    componentEditPlanResponse(planResult, request, warnings, authoringManifest),
                    memoryContext);
        }
        SanitizeResult sanitizeResult = sanitizePatch(
                normalizedPatch,
                filteredCaps,
                request.getComponentId());
        List<String> sanitizeWarnings = filterInternalWarnings(
                sanitizeResult.warnings,
                patchNode,
                request.getComponentId());
        if (sanitizeWarnings != null && !sanitizeWarnings.isEmpty()) {
            warnings.addAll(sanitizeWarnings);
        }

        if (sanitizeResult.sanitized == null || isEmptyObject(sanitizeResult.sanitized)) {
            return finalizeResponse(errorWithWarnings(
                    "O patch gerado não continha configurações válidas permitidas.",
                    warnings), memoryContext);
        }

        EnumValidationResult enumValidation = validateEnumValues(
                sanitizeResult.sanitized,
                componentContext,
                sanitizeResult.effectiveCapabilities);
        if (!enumValidation.valid) {
            return finalizeResponse(invalidEnumValue(enumValidation, warnings), memoryContext);
        }

        List<AiPatchDiff> initialDiff = buildPatchDiff(currentState, sanitizeResult.sanitized);
        CompletenessResult completeness = evaluateCompleteness(
                intentPlan,
                initialDiff,
                currentState,
                componentContext,
                filteredCaps,
                createOnlyPlan);
        logPatchDiagnostics(
                request,
                "initial",
                patchNode,
                normalizedPatch,
                sanitizeResult.sanitized,
                initialDiff,
                completeness);
        if (completeness != null && !completeness.complete) {
            List<IntentAction> missingActions = completeness.missingActions;
            String completenessHints = buildCompletenessHints(intentPlan, initialDiff, missingActions);
            String retryPrompt = buildExecutionPrompt(
                    planningPrompt,
                    context,
                    contextConfig,
                    filteredCaps,
                    combinedNotes,
                    conceptsBlock,
                    schemaContext,
                    resolvedSchema,
                    runtimeMetadata,
                    authoringContract,
                    ragHintsBlock,
                    intentPlanJson,
                    completenessHints);
            JsonNode retryResult = callAiJson("patch_generation_retry", retryPrompt, null, frontendConfig, request, 2);
            ContextRequest retryContextRequest = parseContextRequest(retryResult);
            if (retryContextRequest != null && retryContextRequest.hasCodes()) {
                return finalizeResponse(clarificationWithContextRequest(
                        retryContextRequest.message,
                        retryContextRequest.codes), memoryContext);
            }
            JsonNode retryPatch = retryResult != null ? retryResult.get("patch") : null;
            if (retryPatch != null && !retryPatch.isNull()) {
                SemanticPatchCheck retryCheck = validateSemanticPatch(
                        retryPatch, currentState, warnings, allowUnknownColumns);
                if (retryCheck.valid && retryCheck.patch != null) {
                    JsonNode normalizedRetry = normalizePatch(request.getComponentId(), retryCheck.patch);
                    SanitizeResult retrySanitized = sanitizePatch(
                            normalizedRetry,
                            filteredCaps,
                            request.getComponentId());
                    List<String> retryWarnings = filterInternalWarnings(
                            retrySanitized.warnings,
                            retryPatch,
                            request.getComponentId());
                    if (retryWarnings != null && !retryWarnings.isEmpty()) {
                        warnings.addAll(retryWarnings);
                    }
                    if (retrySanitized.sanitized != null && !isEmptyObject(retrySanitized.sanitized)) {
                        JsonNode mergedPatch = mergePatchNodes(sanitizeResult.sanitized, retrySanitized.sanitized);
                        List<AiCapability> retryEnumCaps = sanitizeResult.effectiveCapabilities;
                        if (retryEnumCaps == null || retryEnumCaps.isEmpty()) {
                            retryEnumCaps = retrySanitized.effectiveCapabilities;
                        }
                        EnumValidationResult retryEnumValidation = validateEnumValues(
                                mergedPatch,
                                componentContext,
                                retryEnumCaps);
                        if (retryEnumValidation.valid) {
                            List<AiPatchDiff> mergedDiff = buildPatchDiff(currentState, mergedPatch);
                            CompletenessResult retryCompleteness = evaluateCompleteness(
                                    intentPlan,
                                    mergedDiff,
                                    currentState,
                                    componentContext,
                                    filteredCaps,
                                    createOnlyPlan);
                            logPatchDiagnostics(
                                    request,
                                    "retry",
                                    retryPatch,
                                    normalizedRetry,
                                    mergedPatch,
                                    mergedDiff,
                                    retryCompleteness);
                            if (retryCompleteness != null && retryCompleteness.complete) {
                                warnings.add("Patch complementado apos retry de completeness.");
                                return finalizeResponse(AiOrchestratorResponse.builder()
                                        .type("patch")
                                        .patch(mergedPatch)
                                        .diff(mergedDiff)
                                        .explanation(explanation)
                                        .warnings(warnings.isEmpty() ? null : warnings)
                                        .build(), memoryContext);
                            }
                            completeness = retryCompleteness;
                            sanitizeResult = new SanitizeResult(mergedPatch, warnings);
                            initialDiff = mergedDiff;
                        }
                    }
                }
            }
            List<String> questions = completeness != null ? completeness.questions : null;
            if (createOnlyPlan) {
                warnings.add("Completeness ignorada para plano de criacao; patch aplicado com melhor esforco.");
                return finalizeResponse(AiOrchestratorResponse.builder()
                        .type("patch")
                        .patch(sanitizeResult.sanitized)
                        .diff(initialDiff)
                        .explanation(explanation)
                        .warnings(warnings.isEmpty() ? null : warnings)
                        .build(), memoryContext);
            }
            if (questions != null && !questions.isEmpty()) {
                AiOrchestratorResponse deterministicFallback = tryResolveComputedFallback(
                        request,
                        currentState,
                        warnings,
                        configCapabilities,
                        componentCapabilities,
                        componentContext);
                if (deterministicFallback != null) {
                    return finalizeResponse(deterministicFallback, memoryContext);
                }
                deterministicFallback = tryResolveRendererRuleFallback(
                        request,
                        currentState,
                        warnings,
                        configCapabilities,
                        componentCapabilities,
                        componentContext);
                if (deterministicFallback != null) {
                    return finalizeResponse(deterministicFallback, memoryContext);
                }
            }
            if (questions != null && !questions.isEmpty()) {
                return finalizeResponse(clarification(buildQuestionsMessage(questions), null), memoryContext);
            }
            return finalizeResponse(
                    clarification("Preciso de mais detalhes para completar o ajuste.", null),
                    memoryContext);
        }

        return finalizeResponse(AiOrchestratorResponse.builder()
                .type("patch")
                .patch(sanitizeResult.sanitized)
                .diff(initialDiff)
                .explanation(explanation)
                .warnings(warnings.isEmpty() ? null : warnings)
                .build(), memoryContext);
        } catch (AiProviderCallException ex) {
            messageService.expireTurn(memoryContext);
            markObservationFailed(observationId, ex, observationStartedAt);
            AiOrchestratorResponse response = providerCallErrorResponse(ex);
            applyObservationMetadata(response, observationId);
            return finalizeResponse(response, memoryContext);
        } catch (Exception ex) {
            messageService.expireTurn(memoryContext);
            markObservationFailed(observationId, ex, observationStartedAt);
            throw ex;
        } finally {
            turnAuthoringManifest.remove();
            turnDataProfile.remove();
        }
    }

    private AiOrchestratorResponse finalizeResponse(
            AiOrchestratorResponse response,
            AiMemoryContext memoryContext) {
        if (response == null) {
            return null;
        }
        response.setExplanation(polishComponentEditPlanExplanation(response.getExplanation()));
        response.setMessage(polishComponentEditPlanExplanation(response.getMessage()));
        messageService.storeAssistantResponse(memoryContext, response);
        boolean summaryUpdated = messageService.summarizeIfNeeded(memoryContext);
        messageService.applyMemoryMetadata(response, memoryContext, summaryUpdated);
        UUID observationId = resolveObservationId(response.getObservationId(), memoryContext);
        applyObservationMetadata(response, observationId);
        linkObservation(observationId, memoryContext);
        markObservationCompleted(observationId, response, 0L);
        return response;
    }

    private UUID captureObservation(
            AiOrchestratorRequest request,
            String tenantId,
            String userId,
            String environment,
            String resolvedUserPrompt) {
        if (assistantObservationService == null) {
            return null;
        }
        String surface = request != null && Boolean.TRUE.equals(request.getStreamTransport())
                ? AiAssistantObservationService.SURFACE_PATCH_STREAM
                : AiAssistantObservationService.SURFACE_SYNC_PATCH;
        return assistantObservationService.capture(
                request,
                tenantId,
                userId,
                environment,
                surface,
                resolvedUserPrompt);
    }

    private void applyObservationMetadata(AiOrchestratorResponse response, UUID observationId) {
        if (response != null && observationId != null) {
            response.setObservationId(observationId);
        }
    }

    private UUID resolveObservationId(UUID observationId, AiMemoryContext memoryContext) {
        if (observationId != null || assistantObservationService == null || memoryContext == null) {
            return observationId;
        }
        return assistantObservationService.findObservationId(
                        memoryContext.getThreadId(),
                        memoryContext.getTurnId(),
                        null)
                .orElse(null);
    }

    private void linkObservation(UUID observationId, AiMemoryContext memoryContext) {
        if (assistantObservationService != null && observationId != null && memoryContext != null) {
            assistantObservationService.link(observationId, memoryContext.getThreadId(), memoryContext.getTurnId(), null);
        }
    }

    private void markObservationAdmission(UUID observationId, String outcome, String code, String message) {
        if (assistantObservationService != null && observationId != null) {
            assistantObservationService.markAdmission(observationId, outcome, code, message);
        }
    }

    private void markObservationCompleted(UUID observationId, AiOrchestratorResponse response, long startedAtNanos) {
        if (assistantObservationService != null && observationId != null) {
            long latencyMs = startedAtNanos > 0 ? elapsedMs(startedAtNanos) : 0L;
            assistantObservationService.markCompleted(observationId, response, latencyMs);
        }
    }

    private void markObservationFailed(UUID observationId, Throwable error, long startedAtNanos) {
        if (assistantObservationService != null && observationId != null) {
            long latencyMs = startedAtNanos > 0 ? elapsedMs(startedAtNanos) : 0L;
            assistantObservationService.markFailed(observationId, error, latencyMs);
        }
    }

    private String resolveAdmissionOutcome(AiOrchestratorResponse response) {
        String code = response != null ? response.getCode() : null;
        if (AiAssistantAdmissionService.CODE_POLICY_REJECTED.equals(code)) {
            return "policy_rejected";
        }
        if (AiAssistantAdmissionService.CODE_OUT_OF_SCOPE.equals(code)) {
            return "out_of_scope";
        }
        return "blocked";
    }

    private String resolveUserPrompt(AiOrchestratorRequest request) {
        if (request == null) {
            return null;
        }
        if (request.getUserPrompt() != null && !request.getUserPrompt().isBlank()) {
            return request.getUserPrompt().trim();
        }
        if (request.getMessages() != null && !request.getMessages().isEmpty()) {
            for (int i = request.getMessages().size() - 1; i >= 0; i--) {
                AiChatMessage msg = request.getMessages().get(i);
                if (msg == null) {
                    continue;
                }
                String role = msg.getRole() != null ? msg.getRole().toLowerCase(Locale.ROOT) : "user";
                if (!"user".equals(role)) {
                    continue;
                }
                if (msg.getContent() != null && !msg.getContent().isBlank()) {
                    return msg.getContent().trim();
                }
            }
        }
        return request.getUserPrompt();
    }

    private String buildPromptWithMemory(String userPrompt, AiMemoryContext memoryContext) {
        if (memoryContext == null) {
            return userPrompt;
        }
        StringBuilder sb = new StringBuilder();
        boolean hasUserInWindow = false;
        if (memoryContext.getSummary() != null && !memoryContext.getSummary().isBlank()) {
            sb.append("SUMMARY:\n")
                    .append(memoryContext.getSummary().trim())
                    .append("\n\n");
        }
        if (memoryContext.getWindowMessages() != null && !memoryContext.getWindowMessages().isEmpty()) {
            sb.append("CHAT_WINDOW:\n");
            for (var msg : memoryContext.getWindowMessages()) {
                if (msg == null || msg.getContent() == null || msg.getContent().isBlank()) {
                    continue;
                }
                String role = msg.getRole() != null ? msg.getRole() : "user";
                if ("user".equalsIgnoreCase(role) && userPrompt != null
                        && userPrompt.trim().equals(msg.getContent().trim())) {
                    hasUserInWindow = true;
                }
                sb.append(role).append(": ").append(msg.getContent().trim()).append("\n");
            }
            sb.append("\n");
        }
        if (!hasUserInWindow && userPrompt != null && !userPrompt.isBlank()) {
            sb.append("USER:\n").append(userPrompt.trim());
        }
        String prompt = sb.toString().trim();
        return prompt.isEmpty() ? userPrompt : prompt;
    }

    private boolean shouldOfferFilterFieldClarification(AiIntentClassification intent) {
        return "filtering".equals(normalizeIntentCategory(intent != null ? intent.getCategory() : null));
    }

    private String resolveCurrentTurnPlanningPrompt(String resolvedUserPrompt) {
        return resolveCurrentTurnPlanningPrompt(resolvedUserPrompt, null);
    }

    private String resolveCurrentTurnPlanningPrompt(String resolvedUserPrompt, AiMemoryContext memoryContext) {
        String current = resolvedUserPrompt != null ? resolvedUserPrompt.trim() : "";
        if (memoryContext == null
                || memoryContext.getWindowMessages() == null
                || memoryContext.getWindowMessages().isEmpty()) {
            return current;
        }
        StringBuilder context = new StringBuilder();
        int appended = 0;
        for (AiChatMessage msg : memoryContext.getWindowMessages()) {
            if (msg == null || msg.getContent() == null || msg.getContent().isBlank()) {
                continue;
            }
            if (!"user".equalsIgnoreCase(msg.getRole())) {
                continue;
            }
            String content = msg.getContent().trim();
            if (!current.isBlank() && current.equals(content)) {
                continue;
            }
            context.append("previous-user: ").append(content).append("\n");
            appended++;
        }
        if (appended == 0) {
            return current;
        }
        StringBuilder prompt = new StringBuilder();
        prompt.append("CURRENT_USER_REQUEST:\n")
                .append(current)
                .append("\n\n")
                .append("CONVERSATION_CONTEXT_FOR_REFERENCE_ONLY:\n")
                .append("Use o pedido atual como unica instrucao nova. Os pedidos anteriores abaixo servem somente para resolver continuacao, pronomes, alvo visual, campo/coluna omitidos e intencao de refinamento. Nao inclua acoes antigas no plano, nao reexecute operacoes ja aplicadas e nao copie configuracoes anteriores, salvo se o pedido atual pedir explicitamente manter, incluir, remover ou modificar algo delas. Quando o pedido atual for um refinamento curto, mantenha apenas o alvo semantico do turno anterior, a menos que o usuario indique explicitamente outro alvo.\n");
        prompt.append(context.toString().trim());
        return prompt.toString().trim();
    }

    private void logPatchDiagnostics(
            AiOrchestratorRequest request,
            String stage,
            JsonNode rawPatch,
            JsonNode normalizedPatch,
            JsonNode sanitizedPatch,
            List<AiPatchDiff> diff,
            CompletenessResult completeness) {
        ObjectNode payload = objectMapper.createObjectNode();
        payload.put("stage", stage);
        if (rawPatch != null) {
            payload.set("patchRaw", rawPatch);
        } else {
            payload.putNull("patchRaw");
        }
        if (normalizedPatch != null) {
            payload.set("patchNormalized", normalizedPatch);
        } else {
            payload.putNull("patchNormalized");
        }
        if (sanitizedPatch != null) {
            payload.set("patchSanitized", sanitizedPatch);
        } else {
            payload.putNull("patchSanitized");
        }
        if (diff != null) {
            payload.set("diff", objectMapper.valueToTree(diff));
        } else {
            payload.putNull("diff");
        }
        if (completeness != null) {
            ObjectNode completenessNode = payload.putObject("completeness");
            completenessNode.put("complete", completeness.complete);
            completenessNode.set("missingActions", objectMapper.valueToTree(completeness.missingActions));
            completenessNode.set("questions", objectMapper.valueToTree(completeness.questions));
        } else {
            payload.putNull("completeness");
        }
        interactionLogger.logDiagnostic(request, "patch_diagnostics", payload);
    }

    private AiIntentClassification classifyIntent(
            String userPrompt,
            List<String> columns,
            List<String> inputs,
            List<String> outputs,
            List<String> configCategories,
            List<String> componentCategories,
            String runtimeMetadata,
            String fieldTypeHints,
            JsonNode authoringContract,
            AiOrchestratorRequest request,
            AiCallConfig callConfig) {
        String prompt = AiPromptTemplates.buildPrompt(
                AiPromptTemplates.PROMPT_INTENT_CLASSIFIER,
                Map.of(
                        "USER_INPUT", safe(userPrompt),
                        "COLUMNS_LIST", objectMapper.valueToTree(columns).toString(),
                        "INPUTS_LIST", objectMapper.valueToTree(inputs).toString(),
                        "OUTPUTS_LIST", objectMapper.valueToTree(outputs).toString(),
                        "RUNTIME_METADATA", truncateBlock(
                                "intent_runtime_metadata",
                                safeMetadata(runtimeMetadata),
                                maxIntentRuntimeMetadataChars),
                        "FIELD_TYPES", truncateBlock(
                                "intent_field_types",
                                safeMetadata(fieldTypeHints),
                                maxIntentFieldTypesChars),
                        "AUTHORING_CONTRACT", truncateBlock(
                                "intent_authoring_contract",
                                formatAuthoringContract(authoringContract),
                                maxIntentAuthoringContractChars),
                        "CONFIG_CATEGORIES", objectMapper.valueToTree(configCategories).toString(),
                        "COMPONENT_CATEGORIES", objectMapper.valueToTree(componentCategories).toString()));
        AiJsonSchema schema = buildIntentSchema();
        JsonNode json = callAiJson("intent_classification", prompt, schema, callConfig, request, 1);
        if (json != null) {
            log.info("[AiOrchestratorService] Intent raw json (nodeType={}): {}", json.getNodeType(), json);
        }
        if (json == null) return null;
        return objectMapper.convertValue(json, AiIntentClassification.class);
    }

    private AiIntentClassification classifyConsultIntentSafely(
            String userPrompt,
            List<String> columns,
            List<String> inputs,
            List<String> outputs,
            List<String> configCategories,
            List<String> componentCategories,
            String runtimeMetadata,
            String fieldTypeHints,
            JsonNode authoringContract,
            AiOrchestratorRequest request,
            AiCallConfig callConfig,
            List<String> warnings) {
        try {
            return classifyIntent(
                    userPrompt,
                    columns,
                    inputs,
                    outputs,
                    configCategories,
                    componentCategories,
                    runtimeMetadata,
                    fieldTypeHints,
                    authoringContract,
                    request,
                    callConfig);
        } catch (AiProviderCallException ex) {
            if (warnings != null) {
                warnings.add("consultative-intent-classification-degraded: " + ex.getKind());
            }
            log.warn(
                    "[AiOrchestratorService] Consultative intent classification degraded. provider={} kind={} message={}",
                    ex.getProvider(),
                    ex.getKind(),
                    ex.getMessage());
            return null;
        }
    }

    private String selectAuthoringResponseMode(
            String userPrompt,
            JsonNode authoringContract,
            AiOrchestratorRequest request,
            AiCallConfig callConfig) {
        if (!hasAuthoringResponseModes(authoringContract)) {
            return null;
        }
        String explicitMode = normalizeAuthoringResponseModeKind(firstNonBlank(
                textOrNull(pathOrMissing(authoringContract, "/activeResponseMode/kind")),
                textOrNull(pathOrMissing(authoringContract, "/selectedResponseMode/kind")),
                textOrNull(pathOrMissing(authoringContract, "/responseMode/kind")),
                textOrNull(pathOrMissing(authoringContract, "/activeResponseMode")),
                textOrNull(pathOrMissing(authoringContract, "/selectedResponseMode")),
                textOrNull(pathOrMissing(authoringContract, "/responseMode"))));
        if (explicitMode != null) {
            return explicitMode;
        }
        String prompt = AiPromptTemplates.buildPrompt(
                AiPromptTemplates.PROMPT_AUTHORING_RESPONSE_MODE_CLASSIFIER,
                Map.of(
                        "USER_INPUT", safe(userPrompt),
                        "AUTHORING_CONTRACT", truncateBlock(
                                "response_mode_authoring_contract",
                                formatAuthoringResponseModeContract(authoringContract),
                                maxResponseModeAuthoringContractChars),
                        "RUNTIME_METADATA", truncateBlock(
                                "response_mode_runtime_metadata",
                                safeMetadata(formatRuntimeMetadata(
                                        request != null ? request.getDataProfile() : null,
                                        request != null ? request.getSchemaFields() : null,
                                        request != null ? request.getRuntimeState() : null,
                                        request != null ? request.getContextHints() : null)),
                                maxIntentRuntimeMetadataChars)));
        JsonNode json = callAiJson(
                "authoring_response_mode_classification",
                prompt,
                buildAuthoringResponseModeSchema(authoringContract),
                callConfig,
                request,
                1);
        String selected = normalizeAuthoringResponseModeKind(textOrNull(json != null ? json.get("kind") : null));
        return hasResponseModeKind(authoringContract, selected) ? selected : null;
    }

    private AiJsonSchema buildAuthoringResponseModeSchema(JsonNode authoringContract) {
        ObjectNode schema = objectMapper.createObjectNode();
        schema.put("type", "object");
        schema.put("additionalProperties", false);
        ObjectNode properties = schema.putObject("properties");
        ObjectNode kind = properties.putObject("kind");
        kind.put("type", "string");
        ArrayNode enumValues = kind.putArray("enum");
        for (String mode : authoringResponseModeKinds(authoringContract)) {
            enumValues.add(mode);
        }
        properties.putObject("preferredResponse").put("type", "string");
        properties.putObject("reason").put("type", "string");
        schema.putArray("required").add("kind").add("preferredResponse").add("reason");
        return AiJsonSchema.of(schema.toString(), null);
    }

    private boolean shouldResolveSelectedRecordFilterCandidateDecision(String selectedResponseMode) {
        return selectedResponseMode == null || "runtime".equals(selectedResponseMode);
    }

    private boolean hasAuthoringResponseModes(JsonNode authoringContract) {
        return authoringResponseModeKinds(authoringContract).size() > 1;
    }

    private boolean hasResponseModeKind(JsonNode authoringContract, String kind) {
        return kind != null && authoringResponseModeKinds(authoringContract).contains(kind);
    }

    private List<String> authoringResponseModeKinds(JsonNode authoringContract) {
        JsonNode modes = authoringContract != null ? authoringContract.get("responseModes") : null;
        if (modes == null || !modes.isArray()) {
            return List.of();
        }
        List<String> kinds = new ArrayList<>();
        for (JsonNode mode : modes) {
            String kind = normalizeAuthoringResponseModeKind(textOrNull(mode != null ? mode.get("kind") : null));
            if (kind != null && !kinds.contains(kind)) {
                kinds.add(kind);
            }
        }
        return kinds;
    }

    private String normalizeAuthoringResponseModeKind(String kind) {
        if (kind == null || kind.isBlank()) {
            return null;
        }
        return kind.trim().toLowerCase(Locale.ROOT);
    }

    private AiJsonSchema buildIntentSchema() {
        ObjectNode schema = objectMapper.createObjectNode();
        schema.put("type", "object");
        schema.put("additionalProperties", false);

        ObjectNode properties = schema.putObject("properties");

        ObjectNode intent = properties.putObject("intent");
        intent.put("type", "string");
        intent.putArray("enum")
                .add("add_column_computed")
                .add("add_column")
                .add("create_flow") // Adicionado intent create_flow
                .add("update_column")
                .add("remove_column")
                .add("toggle_feature")
                .add("global_style")
                .add("ask_about_config")
                .add("unknown");

        ObjectNode newField = properties.putObject("newField");
        newField.put("type", "string");
        newField.put("nullable", true);

        ObjectNode baseFields = properties.putObject("baseFields");
        baseFields.put("type", "array");
        baseFields.putObject("items").put("type", "string");

        ObjectNode computedFormat = properties.putObject("computedFormat");
        computedFormat.put("type", "string");
        computedFormat.put("nullable", true);
        computedFormat.putArray("enum")
                .add("years")
                .add("years_months")
                .add("months_total")
                .add("decimal_years")
                .add("custom_expression");

        ObjectNode expression = properties.putObject("expression");
        expression.put("type", "string");
        expression.put("nullable", true);

        ObjectNode targetField = properties.putObject("targetField");
        targetField.put("type", "string");
        targetField.put("nullable", true);

        properties.putObject("category").put("type", "string");

        ObjectNode scope = properties.putObject("scope");
        scope.put("type", "string");
        scope.putArray("enum").add("config").add("component").add("mixed");

        properties.putObject("needsClarification").put("type", "boolean");

        ObjectNode missingContext = properties.putObject("missingContext");
        missingContext.put("type", "array");
        missingContext.putObject("items").put("type", "string");

        ObjectNode options = properties.putObject("options");
        options.put("type", "array");
        options.putObject("items").put("type", "string");

        schema.putArray("required")
                .add("intent")
                .add("targetField")
                .add("newField")
                .add("baseFields")
                .add("computedFormat")
                .add("expression")
                .add("category")
                .add("scope")
                .add("needsClarification")
                .add("missingContext")
                .add("options");
        return AiJsonSchema.of(schema.toString(), AiIntentClassification.class);
    }

    private AiJsonSchema buildIntentPlanSchema() {
        ObjectNode schema = objectMapper.createObjectNode();
        schema.put("type", "object");
        schema.put("additionalProperties", false);
        ArrayNode required = schema.putArray("required");

        ObjectNode properties = schema.putObject("properties");
        properties.putObject("intent").put("type", "string");
        required.add("intent");

        ObjectNode actions = properties.putObject("actions");
        actions.put("type", "array");
        required.add("actions");
        ObjectNode actionItem = actions.putObject("items");
        actionItem.put("type", "object");
        actionItem.put("additionalProperties", false);
        ObjectNode actionProps = actionItem.putObject("properties");
        ArrayNode actionRequired = actionItem.putArray("required");
        actionProps.putObject("id").put("type", "string");
        actionRequired.add("id");
        ObjectNode checks = actionProps.putObject("checks");
        checks.put("type", "array");
        actionRequired.add("checks");
        ObjectNode checkItem = checks.putObject("items");
        checkItem.put("type", "object");
        checkItem.put("additionalProperties", false);
        ObjectNode checkProps = checkItem.putObject("properties");
        ArrayNode checkRequired = checkItem.putArray("required");
        checkProps.putObject("type").put("type", "string");
        checkRequired.add("type");
        checkProps.putObject("path").put("type", "string");
        checkRequired.add("path");
        ObjectNode value = checkProps.putObject("value");
        checkRequired.add("value");
        ArrayNode valueAnyOf = value.putArray("anyOf");
        valueAnyOf.addObject().put("type", "string");
        valueAnyOf.addObject().put("type", "number");
        valueAnyOf.addObject().put("type", "boolean");
        ObjectNode arrayType = valueAnyOf.addObject();
        arrayType.put("type", "array");
        ArrayNode arrayItemsAnyOf = arrayType.putObject("items").putArray("anyOf");
        arrayItemsAnyOf.addObject().put("type", "string");
        arrayItemsAnyOf.addObject().put("type", "number");
        arrayItemsAnyOf.addObject().put("type", "boolean");
        arrayItemsAnyOf.addObject().put("type", "null");
        valueAnyOf.addObject().put("type", "null");

        ObjectNode questions = properties.putObject("questions");
        questions.put("type", "array");
        questions.putObject("items").put("type", "string");
        required.add("questions");

        return AiJsonSchema.of(schema.toString(), IntentPlan.class);
    }

    private AiActionPlan extractTableActionPlan(
            String userPrompt,
            List<ColumnDescriptor> columns,
            List<ContextOption> formatOptions,
            List<ComponentAction> actionCatalog,
            String ragHints,
            AiContextDTO context,
            AiOrchestratorRequest request,
            AiCallConfig callConfig,
            JsonNode resolvedSchema,
            EmbeddingService.EmbeddingCallConfig embeddingConfig,
            String tenantId,
            String environment,
            JsonNode authoringManifest) {
        ArrayNode columnsNode = objectMapper.createArrayNode();
        if (columns != null) {
            for (ColumnDescriptor col : columns) {
                if (col == null || col.field == null || col.field.isBlank()) continue;
                ObjectNode node = objectMapper.createObjectNode();
                node.put("field", col.field);
                if (col.header != null && !col.header.isBlank()) {
                    node.put("header", col.header);
                }
                columnsNode.add(node);
            }
        }
        ArrayNode actionsNode = buildTableOperationCatalogNode(authoringManifest, actionCatalog);
        String formatChoices = objectMapper.valueToTree(buildOptionLabels(formatOptions)).toString();
        String actionRuntimeMetadata = truncateBlock(
                "table_action_plan_runtime_metadata",
                safeMetadata(formatRuntimeMetadata(
                        request != null ? request.getDataProfile() : null,
                        request != null ? request.getSchemaFields() : null,
                        request != null ? request.getRuntimeState() : null,
                        request != null ? request.getContextHints() : null)),
                maxRuntimeMetadataChars);
        String prompt = AiPromptTemplates.buildPrompt(
                AiPromptTemplates.PROMPT_TABLE_ACTION_PLAN,
                Map.of(
                        "USER_INPUT", safe(userPrompt),
                        "COLUMNS_LIST", columnsNode.toString(),
                        "ACTION_CATALOG", actionsNode.toString(),
                        "RAG_HINTS", safe(ragHints),
                        "FORMAT_OPTIONS", formatChoices,
                        "CONTEXT_HINTS", actionRuntimeMetadata));
        AiJsonSchema planSchema = buildTableActionPlanSchema(actionCatalog, authoringManifest);
        JsonNode json = generateActionPlanJson("table_action_plan", prompt, planSchema, request, callConfig);
        ContextRequest contextRequest = parseContextRequest(json);
        if (contextRequest != null && contextRequest.hasCodes()) {
            ContextHintsBuildResult resolvedHints = buildContextHintsFromRequest(
                    context,
                    request,
                    resolvedSchema,
                    embeddingConfig,
                    contextRequest.codes,
                    tenantId,
                    environment,
                    null);
            JsonNode merged = mergeContextHints(
                    request != null ? request.getContextHints() : null,
                    resolvedHints.hints());
            String retryRuntimeMetadata = truncateBlock(
                    "table_action_plan_runtime_metadata",
                    safeMetadata(formatRuntimeMetadata(
                            request != null ? request.getDataProfile() : null,
                            request != null ? request.getSchemaFields() : null,
                            request != null ? request.getRuntimeState() : null,
                            merged)),
                    maxRuntimeMetadataChars);
            String retryPrompt = AiPromptTemplates.buildPrompt(
                    AiPromptTemplates.PROMPT_TABLE_ACTION_PLAN,
                    Map.of(
                            "USER_INPUT", safe(userPrompt),
                            "COLUMNS_LIST", columnsNode.toString(),
                            "ACTION_CATALOG", actionsNode.toString(),
                            "RAG_HINTS", safe(ragHints),
                            "FORMAT_OPTIONS", formatChoices,
                            "CONTEXT_HINTS", retryRuntimeMetadata));
            json = generateActionPlanJson("table_action_plan", retryPrompt, planSchema, request, callConfig);
        }
        if (json == null) {
            return null;
        }
        if (parseContextRequest(json) != null) {
            return null;
        }
        AiActionPlan plan = objectMapper.convertValue(json, AiActionPlan.class);
        normalizeTableBooleanLabelActionsFromPrompt(userPrompt, plan, null);
        return plan;
    }

    private void normalizeTableBooleanLabelActionsFromPrompt(String userPrompt, AiActionPlan plan, JsonNode currentState) {
        if (plan == null || plan.getActions() == null || plan.getActions().isEmpty()) {
            return;
        }
        String normalizedPrompt = normalizeText(userPrompt);
        String[] labels = inferBooleanStateRendererLabels(userPrompt, normalizeText(userPrompt));
        String explicitTrueLabel = inferBooleanStateRendererTrueLabel(userPrompt, normalizedPrompt);
        String explicitFalseLabel = inferBooleanStateRendererFalseLabel(userPrompt, normalizedPrompt);
        if ((labels == null || isBlank(labels[0])) && !isBlank(explicitTrueLabel)) {
            labels = new String[] { explicitTrueLabel, labels != null && labels.length > 1 ? labels[1] : null };
        }
        if ((labels == null || labels.length < 2 || isBlank(labels[1])) && !isBlank(explicitFalseLabel)) {
            labels = new String[] {
                    labels != null && labels.length > 0 ? labels[0] : null,
                    explicitFalseLabel
            };
        }
        String rendererTarget = findBooleanRendererActionTarget(plan);
        if (!isBlank(rendererTarget)
                && (looksLikeBooleanStateRendererPrompt(normalizedPrompt)
                || looksLikeBooleanStateRendererRefinementPrompt(normalizedPrompt, currentState, rendererTarget)
                || looksLikeBooleanStateRendererRefinementFromPlan(normalizedPrompt, plan))) {
            AiActionPlan rendererPlan = buildBooleanStateRendererActionPlan(
                    userPrompt,
                    new ColumnDescriptor(rendererTarget, rendererTarget),
                    currentState);
            if (rendererPlan != null && rendererPlan.getActions() != null && !rendererPlan.getActions().isEmpty()) {
                plan.setActions(rendererPlan.getActions());
                plan.setAmbiguities(List.of());
                return;
            }
        }
        normalizeBooleanRendererLabelsFromCurrentState(plan, currentState, normalizedPrompt);
        if (labels == null || isBlank(labels[0]) || isBlank(labels[1])) {
            normalizePartialBooleanRendererLabels(labels, plan);
            return;
        }
        for (AiActionPlan.Action action : plan.getActions()) {
            if (action == null || isBlank(action.getType())) {
                continue;
            }
            JsonNode params = action.getParams();
            if (params == null || params.isNull() || !params.isObject()) {
                continue;
            }
            ObjectNode objectParams = (ObjectNode) params;
            if ("column.valueMapping.set".equals(action.getType())) {
                ObjectNode valueMapping = objectParams.with("valueMapping");
                valueMapping.put("true", labels[0]);
                valueMapping.put("false", labels[1]);
            } else if ("column.conditionalRenderer.add".equals(action.getType())) {
                JsonNode expected = objectParams.path("condition").path("==").path(1);
                ObjectNode visual = firstRendererVisualNode(objectParams.path("renderer"));
                if (visual != null) {
                    if (expected.isBoolean()) {
                        visual.put("text", expected.asBoolean() ? labels[0] : labels[1]);
                    } else if ("true".equalsIgnoreCase(expected.asText())) {
                        visual.put("text", labels[0]);
                    } else if ("false".equalsIgnoreCase(expected.asText())) {
                        visual.put("text", labels[1]);
                    }
                }
            }
        }
    }

    private boolean looksLikeBooleanStateRendererRefinementFromPlan(String normalizedPrompt, AiActionPlan plan) {
        if (!looksLikeVisualRendererRefinementPrompt(normalizedPrompt)
                || plan == null
                || plan.getActions() == null
                || plan.getActions().isEmpty()) {
            return false;
        }
        boolean hasPositiveBranch = false;
        boolean hasNegativeBranch = false;
        for (AiActionPlan.Action action : plan.getActions()) {
            if (action == null || !"column.conditionalRenderer.add".equals(action.getType())) {
                continue;
            }
            JsonNode params = action.getParams();
            if (params == null || !params.isObject()) {
                continue;
            }
            JsonNode expected = params.path("condition").path("==").path(1);
            if (expected.isBoolean()) {
                hasPositiveBranch = hasPositiveBranch || expected.asBoolean();
                hasNegativeBranch = hasNegativeBranch || !expected.asBoolean();
            } else if ("true".equalsIgnoreCase(expected.asText())) {
                hasPositiveBranch = true;
            } else if ("false".equalsIgnoreCase(expected.asText())) {
                hasNegativeBranch = true;
            }
            if (hasPositiveBranch && hasNegativeBranch) {
                return true;
            }
        }
        return false;
    }

    private boolean looksLikeBooleanStateRendererRefinementPrompt(
            String normalizedPrompt,
            JsonNode currentState,
            String field) {
        if (normalizedPrompt == null || normalizedPrompt.isBlank() || currentState == null || isBlank(field)) {
            return false;
        }
        if (!looksLikeVisualRendererRefinementPrompt(normalizedPrompt)) {
            return false;
        }
        JsonNode columnState = findColumnState(currentState, field);
        if (columnState == null || columnState.isMissingNode() || columnState.isNull()) {
            return false;
        }
        JsonNode valueMapping = columnState.path("valueMapping");
        if (valueMapping.has("true") || valueMapping.has("false")) {
            return true;
        }
        return !isBlank(findBooleanConditionalRendererLabel(columnState, true))
                || !isBlank(findBooleanConditionalRendererLabel(columnState, false));
    }

    private boolean looksLikeVisualRendererRefinementPrompt(String normalizedPrompt) {
        if (normalizedPrompt == null || normalizedPrompt.isBlank()) {
            return false;
        }
        return normalizedPrompt.contains("verde")
                || normalizedPrompt.contains("cinza")
                || normalizedPrompt.contains("vermelh")
                || normalizedPrompt.contains("laranja")
                || normalizedPrompt.contains("suave")
                || normalizedPrompt.contains("discreto")
                || normalizedPrompt.contains("cor ")
                || normalizedPrompt.contains("cores")
                || normalizedPrompt.contains("icone")
                || normalizedPrompt.contains("ícone")
                || normalizedPrompt.contains("tooltip");
    }

    private void normalizeBooleanRendererLabelsFromCurrentState(
            AiActionPlan plan,
            JsonNode currentState,
            String normalizedPrompt) {
        if (plan == null || plan.getActions() == null || currentState == null) {
            return;
        }
        String normalized = normalizedPrompt != null ? normalizedPrompt : "";
        if (normalized.contains("curto") || normalized.contains("s/n") || normalized.contains("sn")) {
            return;
        }
        for (AiActionPlan.Action action : plan.getActions()) {
            if (action == null || !"column.conditionalRenderer.add".equals(action.getType())) {
                continue;
            }
            String field = trimToNull(action.getTarget());
            if (field == null || action.getParams() == null || !action.getParams().isObject()) {
                continue;
            }
            ObjectNode params = (ObjectNode) action.getParams();
            JsonNode expected = params.path("condition").path("==").path(1);
            Boolean expectedBoolean = null;
            if (expected.isBoolean()) {
                expectedBoolean = expected.asBoolean();
            } else if ("true".equalsIgnoreCase(expected.asText()) || "false".equalsIgnoreCase(expected.asText())) {
                expectedBoolean = Boolean.parseBoolean(expected.asText());
            }
            if (expectedBoolean == null) {
                continue;
            }
            JsonNode columnState = findColumnState(currentState, field);
            String existingLabel = findBooleanConditionalRendererLabel(columnState, expectedBoolean);
            if (isBlank(existingLabel)) {
                continue;
            }
            ObjectNode visual = firstRendererVisualNode(params.path("renderer"));
            if (visual != null) {
                visual.put("text", existingLabel);
            }
        }
    }

    private void normalizePartialBooleanRendererLabels(String[] labels, AiActionPlan plan) {
        if (labels == null || plan == null || plan.getActions() == null) {
            return;
        }
        String trueLabel = labels.length > 0 ? trimToNull(labels[0]) : null;
        String falseLabel = labels.length > 1 ? trimToNull(labels[1]) : null;
        if (trueLabel == null && falseLabel == null) {
            return;
        }
        for (AiActionPlan.Action action : plan.getActions()) {
            if (action == null || isBlank(action.getType())) {
                continue;
            }
            JsonNode params = action.getParams();
            if (params == null || params.isNull() || !params.isObject()) {
                continue;
            }
            ObjectNode objectParams = (ObjectNode) params;
            if ("column.valueMapping.set".equals(action.getType())) {
                ObjectNode valueMapping = objectParams.with("valueMapping");
                if (trueLabel != null) {
                    valueMapping.put("true", trueLabel);
                }
                if (falseLabel != null) {
                    valueMapping.put("false", falseLabel);
                }
            } else if ("column.conditionalRenderer.add".equals(action.getType())) {
                JsonNode expected = objectParams.path("condition").path("==").path(1);
                ObjectNode visual = firstRendererVisualNode(objectParams.path("renderer"));
                if (visual == null) {
                    continue;
                }
                if (expected.isBoolean()) {
                    String label = expected.asBoolean() ? trueLabel : falseLabel;
                    if (label != null) {
                        visual.put("text", label);
                    }
                } else if ("true".equalsIgnoreCase(expected.asText()) && trueLabel != null) {
                    visual.put("text", trueLabel);
                } else if ("false".equalsIgnoreCase(expected.asText()) && falseLabel != null) {
                    visual.put("text", falseLabel);
                }
            }
        }
    }

    private String findBooleanRendererActionTarget(AiActionPlan plan) {
        if (plan == null || plan.getActions() == null) {
            return null;
        }
        for (AiActionPlan.Action action : plan.getActions()) {
            if (action == null || isBlank(action.getTarget())) {
                continue;
            }
            String type = action.getType();
            if ("column.renderer.set".equals(type)
                    || "column.conditionalRenderer.add".equals(type)
                    || "column.valueMapping.set".equals(type)) {
                return action.getTarget();
            }
        }
        return null;
    }

    private ObjectNode firstRendererVisualNode(JsonNode renderer) {
        if (renderer == null || renderer.isNull() || !renderer.isObject()) {
            return null;
        }
        String type = textOrNull(renderer.get("type"));
        JsonNode typed = !isBlank(type) ? renderer.get(type) : null;
        if (typed != null && typed.isObject()) {
            return (ObjectNode) typed;
        }
        JsonNode badge = renderer.get("badge");
        if (badge != null && badge.isObject()) {
            return (ObjectNode) badge;
        }
        JsonNode chip = renderer.get("chip");
        if (chip != null && chip.isObject()) {
            return (ObjectNode) chip;
        }
        return null;
    }

    private AiActionPlan extractComponentActionPlan(
            String userPrompt,
            List<ComponentAction> actionCatalog,
            ArrayNode targetCandidates,
            String ragHints,
            AiContextDTO context,
            AiOrchestratorRequest request,
            AiCallConfig callConfig,
            JsonNode resolvedSchema,
            EmbeddingService.EmbeddingCallConfig embeddingConfig,
            String tenantId,
            String environment) {
        ArrayNode actionsNode = buildActionCatalogNode(actionCatalog);
        String candidates = targetCandidates != null ? targetCandidates.toString() : "[]";
        String prompt = AiPromptTemplates.buildPrompt(
                AiPromptTemplates.PROMPT_COMPONENT_ACTION_PLAN,
                Map.of(
                        "USER_INPUT", safe(userPrompt),
                        "ACTION_CATALOG", actionsNode.toString(),
                        "TARGET_CANDIDATES", candidates,
                        "RAG_HINTS", safe(ragHints),
                        "CONTEXT_HINTS", formatContextHints(request != null ? request.getContextHints() : null)));
        AiJsonSchema planSchema = buildComponentActionPlanSchema(actionCatalog);
        JsonNode json = generateActionPlanJson("component_action_plan", prompt, planSchema, request, callConfig);
        ContextRequest contextRequest = parseContextRequest(json);
        if (contextRequest != null && contextRequest.hasCodes()) {
            ContextHintsBuildResult resolvedHints = buildContextHintsFromRequest(
                    context,
                    request,
                    resolvedSchema,
                    embeddingConfig,
                    contextRequest.codes,
                    tenantId,
                    environment,
                    null);
            JsonNode merged = mergeContextHints(
                    request != null ? request.getContextHints() : null,
                    resolvedHints.hints());
            String retryPrompt = AiPromptTemplates.buildPrompt(
                    AiPromptTemplates.PROMPT_COMPONENT_ACTION_PLAN,
                    Map.of(
                            "USER_INPUT", safe(userPrompt),
                            "ACTION_CATALOG", actionsNode.toString(),
                            "TARGET_CANDIDATES", candidates,
                            "RAG_HINTS", safe(ragHints),
                            "CONTEXT_HINTS", formatContextHints(merged)));
            json = generateActionPlanJson("component_action_plan", retryPrompt, planSchema, request, callConfig);
        }
        if (json == null) {
            return null;
        }
        if (parseContextRequest(json) != null) {
            return null;
        }
        return objectMapper.convertValue(json, AiActionPlan.class);
    }

    private JsonNode generateActionPlanJson(
            String callType,
            String prompt,
            AiJsonSchema schema,
            AiOrchestratorRequest request,
            AiCallConfig callConfig) {
        AiCallConfig baseConfig = buildActionPlanConfig(callConfig);
        JsonNode json = callAiJson(callType, prompt, schema, baseConfig, request, 1);
        if (json != null) {
            return json;
        }
        AiCallConfig retryConfig = buildActionPlanRetryConfig(baseConfig);
        if (retryConfig == null) {
            return null;
        }
        log.info("[AiOrchestratorService] Action plan parse failed; retrying with temperature {}.",
                retryConfig.getTemperature());
        return callAiJson(callType, prompt, schema, retryConfig, request, 2);
    }

    private JsonNode callAiJson(
            String callType,
            String prompt,
            AiJsonSchema schema,
            AiCallConfig config,
            AiOrchestratorRequest request,
            Integer attempt) {
        long start = System.nanoTime();
        try {
            JsonNode json = aiProvider.generateJson(prompt, schema, config);
            interactionLogger.logLlmInteraction(
                    request,
                    callType,
                    resolveProviderName(config),
                    attempt,
                    prompt,
                    json,
                    null,
                    elapsedMs(start),
                    null);
            recordObservationLlmCall(request, callType, prompt, config, elapsedMs(start), null);
            return json;
        } catch (Exception ex) {
            interactionLogger.logLlmInteraction(
                    request,
                    callType,
                    resolveProviderName(config),
                    attempt,
                    prompt,
                    null,
                    null,
                    elapsedMs(start),
                    ex);
            recordObservationLlmCall(request, callType, prompt, config, elapsedMs(start), ex);
            throw ex;
        }
    }

    private String callAiText(
            String callType,
            String prompt,
            AiCallConfig config,
            AiOrchestratorRequest request,
            Integer attempt) {
        long start = System.nanoTime();
        try {
            String text = resolveTextGeneration(callType, prompt, config, request);
            interactionLogger.logLlmInteraction(
                    request,
                    callType,
                    resolveProviderName(config),
                    attempt,
                    prompt,
                    null,
                    text,
                    elapsedMs(start),
                    null);
            recordObservationLlmCall(request, callType, prompt, config, elapsedMs(start), null);
            return text;
        } catch (Exception ex) {
            interactionLogger.logLlmInteraction(
                    request,
                    callType,
                    resolveProviderName(config),
                    attempt,
                    prompt,
                    null,
                    null,
                    elapsedMs(start),
                    ex);
            recordObservationLlmCall(request, callType, prompt, config, elapsedMs(start), ex);
            throw ex;
        }
    }

    private void recordObservationLlmCall(
            AiOrchestratorRequest request,
            String callType,
            String prompt,
            AiCallConfig config,
            long durationMs,
            Throwable error) {
        if (assistantObservationService != null && request != null && request.getObservationId() != null) {
            assistantObservationService.recordLlmCall(
                    request.getObservationId(),
                    resolveProviderName(config),
                    resolveEffectiveModel(config),
                    callType,
                    prompt != null ? prompt.length() : null,
                    durationMs,
                    error);
        }
    }

    private String resolveEffectiveModel(AiCallConfig config) {
        String configured = config != null ? trimToNull(config.getModel()) : null;
        if (configured != null) {
            return configured;
        }
        String provider = resolveProviderName(config);
        if ("openai".equalsIgnoreCase(provider)) {
            return trimToNull(defaultOpenAiChatModel);
        }
        return null;
    }

    private String resolveTextGeneration(
            String callType,
            String prompt,
            AiCallConfig config,
            AiOrchestratorRequest request) {
        boolean streamTransport = request != null && Boolean.TRUE.equals(request.getStreamTransport());
        if (!providerTextStreamEnabled || !streamTransport || !aiProvider.supportsTextStreaming(config)) {
            return aiProvider.generateText(prompt, config);
        }

        Supplier<Boolean> cancellationRequested = AiStreamExecutionContextHolder.cancellationRequested();
        try {
            log.debug("[AiOrchestratorService] Using provider text stream (callType={}, provider={}).",
                    callType, resolveProviderName(config));
            return aiProvider.generateTextStream(prompt, config, null, cancellationRequested);
        } catch (Exception ex) {
            if (ex instanceof CancellationException) {
                throw ex;
            }
            String fallbackReasonKind = resolveSyncFallbackReasonKind(ex);
            if (fallbackReasonKind != null) {
                incrementStreamFallbackMetric(config, fallbackReasonKind);
                log.warn("[AiOrchestratorService] Provider stream failed; falling back to sync text generation. provider={} callType={} reason_kind={} reason={}",
                        resolveProviderName(config),
                        callType,
                        fallbackReasonKind,
                        safeErrorMessage(ex));
                return aiProvider.generateText(prompt, config);
            }
            throw ex;
        }
    }

    private String resolveSyncFallbackReasonKind(Exception streamError) {
        if (!providerTextStreamFallbackSyncOnError || streamError == null) {
            return null;
        }
        Throwable rootCause = streamError;
        while (rootCause.getCause() != null && rootCause.getCause() != rootCause) {
            rootCause = rootCause.getCause();
        }
        if (rootCause instanceof CancellationException) {
            return null;
        }
        if (rootCause instanceof AiProviderStreamException streamException) {
            return switch (streamException.getKind()) {
                case TRANSPORT -> "transport";
                case TIMEOUT -> "timeout";
                case RATE_LIMIT -> "rate_limit";
                case QUOTA_EXHAUSTED -> "quota_exhausted";
                case CAPACITY -> "capacity";
                default -> null;
            };
        }
        if (rootCause instanceof IOException
                || rootCause instanceof java.net.ConnectException
                || rootCause instanceof java.net.SocketException
                || rootCause instanceof java.net.UnknownHostException
                || rootCause instanceof java.net.http.HttpTimeoutException) {
            return "transport";
        }
        String message = safeErrorMessage(rootCause).toLowerCase(Locale.ROOT);
        if (message.contains("http 429")) {
            return "rate_limit";
        }
        if (message.contains("http 503")
                || message.contains("capacity")
                || message.contains("temporarily unavailable")) {
            return "capacity";
        }
        if (message.contains("timeout") || message.contains("timed out")) {
            return "timeout";
        }
        if (message.contains("connection reset")
                || message.contains("connection refused")
                || message.contains("broken pipe")
                || message.contains("premature close")) {
            return "transport";
        }
        return null;
    }

    private void incrementStreamFallbackMetric(AiCallConfig config, String reasonKind) {
        String provider = normalizeMetricTag(resolveProviderName(config), METRIC_TAG_UNKNOWN);
        String normalizedReason = normalizeMetricTag(reasonKind, "unknown");
        Metrics.counter(
                        METRIC_STREAM_FALLBACK_TOTAL,
                        METRIC_TAG_PROVIDER,
                        provider,
                        METRIC_TAG_REASON_KIND,
                        normalizedReason)
                .increment();
    }

    private String safeErrorMessage(Throwable error) {
        if (error == null) {
            return "unknown";
        }
        String message = error.getMessage();
        if (message == null || message.isBlank()) {
            return error.getClass().getSimpleName();
        }
        return message;
    }

    private String resolveProviderName(AiCallConfig config) {
        String provider = config != null ? trimToNull(config.getProvider()) : null;
        if (provider != null) {
            return provider.toLowerCase(Locale.ROOT);
        }
        return aiProvider.getProviderName();
    }

    String resolveStreamMetricsProvider(String tenantId, String userId, String environment) {
        AiCallConfig frontendConfig = resolveFrontendCallConfig(tenantId, userId, environment);
        return normalizeMetricTag(resolveProviderName(frontendConfig), METRIC_TAG_UNKNOWN);
    }

    private long elapsedMs(long startNanos) {
        return (System.nanoTime() - startNanos) / 1_000_000L;
    }

    private String normalizeMetricTag(String value, String fallback) {
        String normalized = trimToNull(value);
        if (normalized == null) {
            return fallback;
        }
        StringBuilder out = new StringBuilder(normalized.length());
        for (int idx = 0; idx < normalized.length(); idx++) {
            char ch = Character.toLowerCase(normalized.charAt(idx));
            if ((ch >= 'a' && ch <= 'z')
                    || (ch >= '0' && ch <= '9')
                    || ch == '_'
                    || ch == '-'
                    || ch == '.') {
                out.append(ch);
            } else {
                out.append('_');
            }
        }
        String sanitized = out.toString();
        return sanitized.isBlank() ? fallback : sanitized;
    }

    private AiCallConfig buildActionPlanConfig(AiCallConfig baseConfig) {
        AiCallConfig.AiCallConfigBuilder builder = baseConfig != null
                ? baseConfig.toBuilder()
                : AiCallConfig.builder();
        boolean hasConfig = baseConfig != null;
        String provider = trimToNull(actionPlanProvider);
        if (provider != null) {
            builder.provider(provider);
            hasConfig = true;
        }
        String model = trimToNull(actionPlanModel);
        if (model != null) {
            builder.model(model);
            hasConfig = true;
        }
        if (actionPlanTemperature != null) {
            builder.temperature(actionPlanTemperature);
            hasConfig = true;
        }
        if (actionPlanMaxTokens != null && actionPlanMaxTokens > 0) {
            builder.maxTokens(actionPlanMaxTokens);
            hasConfig = true;
        }
        return hasConfig ? builder.build() : null;
    }

    private AiCallConfig buildActionPlanRetryConfig(AiCallConfig baseConfig) {
        double retryTemp = actionPlanRetryTemperature;
        if (retryTemp < 0) {
            retryTemp = 0;
        }
        Double baseTemp = baseConfig != null ? baseConfig.getTemperature() : null;
        double effectiveTemp = baseTemp != null ? Math.min(baseTemp, retryTemp) : retryTemp;
        AiCallConfig.AiCallConfigBuilder builder = baseConfig != null
                ? baseConfig.toBuilder()
                : AiCallConfig.builder();
        builder.temperature(effectiveTemp);
        return builder.build();
    }

    private AiCallConfig resolveFrontendCallConfig(String tenantId, String userId, String environment) {
        String resolvedTenant = trimToNull(tenantId);
        String resolvedEnv = trimToNull(environment);
        AiCallConfig config = null;
        if (resolvedTenant != null && userConfigService != null) {
            for (String componentId : buildGlobalConfigIds(resolvedTenant)) {
                Optional<UserConfigService.ResolvedConfig> resolved =
                        userConfigService.getResolved(
                                resolvedTenant,
                                userId,
                                GLOBAL_CONFIG_COMPONENT_TYPE,
                                componentId,
                                resolvedEnv);
                if (resolved.isEmpty()) {
                    continue;
                }
                JsonNode payload = parsePayload(resolved.get().config().getPayload());
                config = parseAiCallConfig(payload);
                if (config != null) {
                    break;
                }
            }
        }
        if (resolvedTenant == null) {
            return config;
        }
        if (config == null) {
            return AiCallConfig.builder()
                    .tenantId(resolvedTenant)
                    .environment(resolvedEnv)
                    .build();
        }
        return config.toBuilder()
                .tenantId(resolvedTenant)
                .environment(resolvedEnv)
                .build();
    }

    private AiCallConfig withRagRelease(AiCallConfig config, String releaseId) {
        String resolvedReleaseId = trimToNull(releaseId);
        if (resolvedReleaseId == null) {
            return config;
        }
        if (config == null) {
            return AiCallConfig.builder()
                    .ragReleaseId(resolvedReleaseId)
                    .build();
        }
        return config.toBuilder()
                .ragReleaseId(resolvedReleaseId)
                .build();
    }

    private EmbeddingService.EmbeddingCallConfig resolveEmbeddingCallConfig(
            String tenantId,
            String userId,
            String environment) {
        String resolvedTenant = trimToNull(tenantId);
        if (resolvedTenant == null || userConfigService == null) {
            return null;
        }
        String resolvedEnv = trimToNull(environment);
        for (String componentId : buildGlobalConfigIds(resolvedTenant)) {
            Optional<UserConfigService.ResolvedConfig> resolved =
                    userConfigService.getResolved(
                            resolvedTenant,
                            userId,
                            GLOBAL_CONFIG_COMPONENT_TYPE,
                            componentId,
                            resolvedEnv);
            if (resolved.isEmpty()) {
                continue;
            }
            JsonNode payload = parsePayload(resolved.get().config().getPayload());
            EmbeddingService.EmbeddingCallConfig config = parseEmbeddingCallConfig(payload);
            if (config != null) {
                return config;
            }
        }
        return null;
    }

    private List<String> buildGlobalConfigIds(String tenantId) {
        List<String> ids = new ArrayList<>();
        if (tenantId != null && !tenantId.isBlank()) {
            ids.add(GLOBAL_CONFIG_KEY + ":" + tenantId.trim());
        }
        ids.add(GLOBAL_CONFIG_KEY);
        return ids;
    }

    private JsonNode parsePayload(String raw) {
        if (raw == null || raw.isBlank()) {
            return objectMapper.createObjectNode();
        }
        try {
            return objectMapper.readTree(raw);
        } catch (Exception e) {
            return objectMapper.createObjectNode();
        }
    }

    private AiCallConfig parseAiCallConfig(JsonNode payload) {
        if (payload == null || payload.isNull()) {
            return null;
        }
        JsonNode aiNode = payload.get("ai");
        if (aiNode == null || !aiNode.isObject()) {
            return null;
        }
        AiCallConfig.AiCallConfigBuilder builder = AiCallConfig.builder();
        boolean hasValue = false;

        String provider = trimToNull(textOrNull(aiNode.get("provider")));
        if (provider != null) {
            builder.provider(provider);
            hasValue = true;
        }
        String model = trimToNull(textOrNull(aiNode.get("model")));
        if (model != null) {
            builder.model(model);
            hasValue = true;
        }
        Double temperature = parseDouble(aiNode.get("temperature"));
        if (temperature != null) {
            builder.temperature(temperature);
            hasValue = true;
        }
        Integer maxTokens = parseInteger(aiNode.get("maxTokens"));
        if (maxTokens != null && maxTokens > 0) {
            builder.maxTokens(maxTokens);
            hasValue = true;
        }
        String apiKey = trimToNull(textOrNull(aiNode.get("apiKey")));
        if (apiKey == null) {
            String encrypted = trimToNull(textOrNull(aiNode.get("apiKeyEncrypted")));
            String decrypted = apiKeyCryptoService.decrypt(encrypted);
            apiKey = trimToNull(decrypted);
        }
        if (apiKey != null) {
            builder.apiKey(apiKey);
            hasValue = true;
        }
        String ragReleaseId = trimToNull(textOrNull(aiNode.get("ragReleaseId")));
        if (ragReleaseId == null) {
            ragReleaseId = trimToNull(textOrNull(aiNode.get("releaseId")));
        }
        if (ragReleaseId != null) {
            builder.ragReleaseId(ragReleaseId);
            hasValue = true;
        }

        return hasValue ? builder.build() : null;
    }

    private EmbeddingService.EmbeddingCallConfig parseEmbeddingCallConfig(JsonNode payload) {
        if (payload == null || payload.isNull()) {
            return null;
        }
        JsonNode aiNode = payload.get("ai");
        if (aiNode == null || !aiNode.isObject()) {
            return null;
        }
        JsonNode embeddingNode = aiNode.get("embedding");
        boolean useSameAsLlm = embeddingNode != null
                && embeddingNode.has("useSameAsLlm")
                && embeddingNode.get("useSameAsLlm").asBoolean(false);

        String provider = embeddingNode != null ? trimToNull(textOrNull(embeddingNode.get("provider"))) : null;
        String apiKey = embeddingNode != null ? resolveApiKeyFromNode(embeddingNode) : null;
        String model = embeddingNode != null ? trimToNull(textOrNull(embeddingNode.get("model"))) : null;
        Integer dimensions = embeddingNode != null ? parseInteger(embeddingNode.get("dimensions")) : null;

        if (useSameAsLlm) {
            if (provider == null) {
                provider = trimToNull(textOrNull(aiNode.get("provider")));
            }
            if (apiKey == null) {
                apiKey = resolveApiKeyFromNode(aiNode);
            }
        }

        if (provider == null && apiKey == null && model == null && dimensions == null) {
            return null;
        }
        return new EmbeddingService.EmbeddingCallConfig(provider, apiKey, model, dimensions);
    }

    private String resolveApiKeyFromNode(JsonNode node) {
        if (node == null || node.isNull()) {
            return null;
        }
        String apiKey = trimToNull(textOrNull(node.get("apiKey")));
        if (apiKey != null) {
            return apiKey;
        }
        String encrypted = trimToNull(textOrNull(node.get("apiKeyEncrypted")));
        if (encrypted == null) {
            return null;
        }
        String decrypted = apiKeyCryptoService.decrypt(encrypted);
        return trimToNull(decrypted);
    }

    private Double parseDouble(JsonNode node) {
        if (node == null || node.isNull()) {
            return null;
        }
        if (node.isNumber()) {
            return node.asDouble();
        }
        if (node.isTextual()) {
            try {
                return Double.parseDouble(node.asText());
            } catch (NumberFormatException ignore) {
                return null;
            }
        }
        return null;
    }

    private Integer parseInteger(JsonNode node) {
        if (node == null || node.isNull()) {
            return null;
        }
        if (node.isInt() || node.isLong() || node.canConvertToInt()) {
            return node.asInt();
        }
        if (node.isTextual()) {
            try {
                return Integer.parseInt(node.asText());
            } catch (NumberFormatException ignore) {
                return null;
            }
        }
        return null;
    }

    private String trimToNull(String value) {
        if (value == null) {
            return null;
        }
        String trimmed = value.trim();
        return trimmed.isEmpty() ? null : trimmed;
    }

    private AiJsonSchema buildTableActionPlanSchema(List<ComponentAction> actionCatalog, JsonNode authoringManifest) {
        ObjectNode schema = objectMapper.createObjectNode();
        schema.put("type", "object");
        schema.put("additionalProperties", false);
        ArrayNode required = schema.putArray("required");

        ObjectNode properties = schema.putObject("properties");

        ObjectNode actions = properties.putObject("actions");
        actions.put("type", "array");
        required.add("actions");
        ObjectNode actionItem = actions.putObject("items");
        actionItem.put("type", "object");
        actionItem.put("additionalProperties", false);
        ObjectNode actionProps = actionItem.putObject("properties");
        ArrayNode actionRequired = actionItem.putArray("required");

        ObjectNode type = actionProps.putObject("type");
        type.put("type", "string");
        type.putArray("enum").addAll(buildTableOperationEnum(authoringManifest, actionCatalog));
        actionRequired.add("type");

        ObjectNode target = actionProps.putObject("target");
        target.put("type", "string");
        actionRequired.add("target");

        ObjectNode value = actionProps.putObject("value");
        value.put("type", "string");
        value.put("nullable", true);
        actionRequired.add("value");

        ObjectNode params = actionProps.putObject("params");
        params.put("type", "object");
        params.put("nullable", true);
        params.put("additionalProperties", true);
        actionRequired.add("params");

        ObjectNode ambiguities = properties.putObject("ambiguities");
        ambiguities.put("type", "array");
        required.add("ambiguities");
        ObjectNode ambiguityItem = ambiguities.putObject("items");
        ambiguityItem.put("type", "object");
        ambiguityItem.put("additionalProperties", false);
        ObjectNode ambiguityProps = ambiguityItem.putObject("properties");
        ArrayNode ambiguityRequired = ambiguityItem.putArray("required");

        ambiguityProps.putObject("alias").put("type", "string");
        ambiguityRequired.add("alias");
        ObjectNode candidates = ambiguityProps.putObject("candidates");
        candidates.put("type", "array");
        candidates.putObject("items").put("type", "string");
        ambiguityRequired.add("candidates");
        ambiguityProps.putObject("reason").put("type", "string");
        ambiguityRequired.add("reason");

        ObjectNode contextRequest = properties.putObject("contextRequest");
        contextRequest.put("type", "array");
        contextRequest.putObject("items").put("type", "integer");
        required.add("contextRequest");
        properties.putObject("message").put("type", "string");
        required.add("message");

        return AiJsonSchema.ofSchema(schema.toString());
    }

    private AiJsonSchema buildComponentActionPlanSchema(List<ComponentAction> actionCatalog) {
        ObjectNode schema = objectMapper.createObjectNode();
        schema.put("type", "object");
        schema.put("additionalProperties", false);
        ArrayNode required = schema.putArray("required");

        ObjectNode properties = schema.putObject("properties");

        ObjectNode actions = properties.putObject("actions");
        actions.put("type", "array");
        required.add("actions");
        ObjectNode actionItem = actions.putObject("items");
        actionItem.put("type", "object");
        actionItem.put("additionalProperties", false);
        ObjectNode actionProps = actionItem.putObject("properties");
        ArrayNode actionRequired = actionItem.putArray("required");

        ObjectNode type = actionProps.putObject("type");
        type.put("type", "string");
        type.putArray("enum").addAll(buildActionEnumFromCatalog(actionCatalog));
        actionRequired.add("type");

        ObjectNode target = actionProps.putObject("target");
        target.put("type", "string");
        actionRequired.add("target");

        ObjectNode value = actionProps.putObject("value");
        value.put("type", "string");
        value.put("nullable", true);
        actionRequired.add("value");

        ObjectNode params = actionProps.putObject("params");
        params.put("type", "string");
        params.put("nullable", true);
        actionRequired.add("params");

        ObjectNode ambiguities = properties.putObject("ambiguities");
        ambiguities.put("type", "array");
        required.add("ambiguities");
        ObjectNode ambiguityItem = ambiguities.putObject("items");
        ambiguityItem.put("type", "object");
        ambiguityItem.put("additionalProperties", false);
        ObjectNode ambiguityProps = ambiguityItem.putObject("properties");
        ArrayNode ambiguityRequired = ambiguityItem.putArray("required");

        ambiguityProps.putObject("alias").put("type", "string");
        ambiguityRequired.add("alias");
        ObjectNode candidates = ambiguityProps.putObject("candidates");
        candidates.put("type", "array");
        candidates.putObject("items").put("type", "string");
        ambiguityRequired.add("candidates");
        ambiguityProps.putObject("reason").put("type", "string");
        ambiguityRequired.add("reason");

        ObjectNode contextRequest = properties.putObject("contextRequest");
        contextRequest.put("type", "array");
        contextRequest.putObject("items").put("type", "integer");
        required.add("contextRequest");
        properties.putObject("message").put("type", "string");
        required.add("message");

        return AiJsonSchema.ofSchema(schema.toString());
    }

    private void appendActionParamsSchema(ObjectNode actionProps, Set<String> paramKeys) {
        if (paramKeys == null || paramKeys.isEmpty()) {
            return;
        }
        ObjectNode params = actionProps.putObject("params");
        params.put("type", "object");
        params.put("nullable", true);
        params.put("additionalProperties", false);
        ObjectNode properties = params.putObject("properties");
        for (String key : paramKeys) {
            if (key == null || key.isBlank()) continue;
            ObjectNode prop = properties.putObject(key);
            ArrayNode anyOf = prop.putArray("anyOf");
            anyOf.addObject().put("type", "string");
            anyOf.addObject().put("type", "number");
            anyOf.addObject().put("type", "boolean");
            ObjectNode obj = anyOf.addObject();
            obj.put("type", "object");
            obj.put("additionalProperties", true);
            ObjectNode arr = anyOf.addObject();
            arr.put("type", "array");
            arr.putObject("items");
            anyOf.addObject().put("type", "null");
        }
    }

    private Set<String> extractParamKeysFromCatalog(List<ComponentAction> actionCatalog) {
        java.util.LinkedHashSet<String> keys = new java.util.LinkedHashSet<>();
        if (actionCatalog == null || actionCatalog.isEmpty()) {
            return keys;
        }
        for (ComponentAction action : actionCatalog) {
            if (action == null || action.patchTemplate == null || action.patchTemplate.isNull()) {
                continue;
            }
            collectParamKeys(action.patchTemplate, keys);
        }
        return keys;
    }

    private void collectParamKeys(JsonNode node, Set<String> keys) {
        if (node == null || node.isNull()) {
            return;
        }
        if (node.isTextual()) {
            String text = node.asText();
            if (text == null || text.isBlank()) {
                return;
            }
            java.util.regex.Pattern pattern = java.util.regex.Pattern.compile("\\{\\{\\s*params\\.([^}\\s]+)\\s*}}");
            java.util.regex.Matcher matcher = pattern.matcher(text);
            while (matcher.find()) {
                String raw = matcher.group(1);
                if (raw == null || raw.isBlank()) continue;
                String key = raw.split("\\.")[0];
                if (!key.isBlank()) {
                    keys.add(key);
                }
            }
            return;
        }
        if (node.isArray()) {
            for (JsonNode item : node) {
                collectParamKeys(item, keys);
            }
            return;
        }
        if (node.isObject()) {
            node.fields().forEachRemaining(entry -> collectParamKeys(entry.getValue(), keys));
        }
    }


    private ArrayNode buildActionEnumFromCatalog(List<ComponentAction> actionCatalog) {
        ArrayNode enumNode = objectMapper.createArrayNode();
        if (actionCatalog == null) {
            return enumNode;
        }
        for (ComponentAction action : actionCatalog) {
            if (action == null || action.id == null || action.id.isBlank()) {
                continue;
            }
            enumNode.add(action.id.trim());
        }
        return enumNode;
    }

    private ArrayNode buildTableOperationEnum(JsonNode authoringManifest, List<ComponentAction> actionCatalog) {
        ArrayNode manifestOperationIds = buildManifestOperationEnum(authoringManifest);
        if (!manifestOperationIds.isEmpty()) {
            return manifestOperationIds;
        }
        return buildActionEnumFromCatalog(actionCatalog);
    }

    private ArrayNode buildManifestOperationEnum(JsonNode authoringManifest) {
        ArrayNode enumNode = objectMapper.createArrayNode();
        JsonNode operations = authoringManifest != null && authoringManifest.isObject()
                ? authoringManifest.get("operations")
                : null;
        if (operations == null || !operations.isArray()) {
            return enumNode;
        }
        Set<String> seen = new LinkedHashSet<>();
        for (JsonNode operation : operations) {
            String operationId = textOrNull(operation != null ? operation.get("operationId") : null);
            if (operationId != null && !operationId.isBlank() && seen.add(operationId)) {
                enumNode.add(operationId);
            }
        }
        return enumNode;
    }

    private ArrayNode buildTableOperationCatalogNode(JsonNode authoringManifest, List<ComponentAction> actionCatalog) {
        ArrayNode manifestOperations = buildManifestOperationCatalogNode(authoringManifest);
        if (!manifestOperations.isEmpty()) {
            return manifestOperations;
        }
        return buildActionCatalogNode(actionCatalog);
    }

    private ArrayNode buildManifestOperationCatalogNode(JsonNode authoringManifest) {
        ArrayNode out = objectMapper.createArrayNode();
        JsonNode operations = authoringManifest != null && authoringManifest.isObject()
                ? authoringManifest.get("operations")
                : null;
        if (operations == null || !operations.isArray()) {
            return out;
        }
        for (JsonNode operation : operations) {
            String operationId = textOrNull(operation != null ? operation.get("operationId") : null);
            if (operationId == null || operationId.isBlank()) {
                continue;
            }
            ObjectNode node = objectMapper.createObjectNode();
            node.put("id", operationId);
            node.put("operationId", operationId);
            putIfText(node, "title", operation.get("title"));
            putIfText(node, "scope", operation.get("scope"));
            putIfText(node, "targetKind", firstPresent(operation.get("targetKind"), operation.at("/target/kind")));
            JsonNode target = operation.get("target");
            if (target != null && target.isObject()) {
                ObjectNode targetNode = node.putObject("target");
                putIfText(targetNode, "kind", target.get("kind"));
                putIfText(targetNode, "resolver", target.get("resolver"));
                targetNode.put("required", target.path("required").asBoolean(false));
            }
            JsonNode inputSchema = operation.get("inputSchema");
            if (inputSchema != null && inputSchema.isObject()) {
                node.set("inputSchema", inputSchema);
            }
            JsonNode affectedPaths = operation.get("affectedPaths");
            if (affectedPaths != null && affectedPaths.isArray()) {
                node.set("affectedPaths", affectedPaths);
            }
            JsonNode validators = operation.get("validators");
            if (validators != null && validators.isArray()) {
                node.set("validators", validators);
            }
            ArrayNode examples = buildManifestOperationExampleCatalogNode(authoringManifest, operationId);
            if (!examples.isEmpty()) {
                node.set("examples", examples);
            }
            out.add(node);
        }
        return out;
    }

    private ArrayNode buildManifestOperationExampleCatalogNode(JsonNode authoringManifest, String operationId) {
        ArrayNode out = objectMapper.createArrayNode();
        if (operationId == null || operationId.isBlank()) {
            return out;
        }
        JsonNode examples = authoringManifest != null && authoringManifest.isObject()
                ? authoringManifest.get("examples")
                : null;
        if (examples == null || !examples.isArray()) {
            return out;
        }
        for (JsonNode example : examples) {
            String exampleOperationId = textOrNull(example != null ? example.get("operationId") : null);
            if (!operationId.equals(exampleOperationId)) {
                continue;
            }
            ObjectNode node = objectMapper.createObjectNode();
            putIfText(node, "id", example.get("id"));
            putIfText(node, "request", example.get("request"));
            putIfText(node, "target", example.get("target"));
            JsonNode params = example.get("params");
            if (params != null && params.isObject()) {
                node.set("params", params);
            }
            if (example.has("isPositive")) {
                node.put("isPositive", example.path("isPositive").asBoolean(true));
            }
            out.add(node);
        }
        return out;
    }

    private void putIfText(ObjectNode node, String fieldName, JsonNode value) {
        String text = textOrNull(value);
        if (node != null && fieldName != null && text != null && !text.isBlank()) {
            node.put(fieldName, text);
        }
    }

    private ArrayNode buildActionCatalogNode(List<ComponentAction> actionCatalog) {
        ArrayNode out = objectMapper.createArrayNode();
        if (actionCatalog == null) {
            return out;
        }
        for (ComponentAction action : actionCatalog) {
            if (action == null || action.id == null || action.id.isBlank()) {
                continue;
            }
            ObjectNode node = objectMapper.createObjectNode();
            node.put("id", action.id);
            if (action.intentExamples != null && !action.intentExamples.isEmpty()) {
                ArrayNode examplesNode = node.putArray("intentExamples");
                for (String example : action.intentExamples) {
                    if (example != null && !example.isBlank()) {
                        examplesNode.add(example);
                    }
                }
            }
            if (action.patchTemplate != null && !action.patchTemplate.isNull()) {
                node.set("patchTemplate", action.patchTemplate);
            }
            out.add(node);
        }
        return out;
    }

    private ArrayNode buildTargetCandidates(JsonNode componentContext, JsonNode currentState) {
        ArrayNode out = objectMapper.createArrayNode();
        if (componentContext == null || currentState == null) {
            return out;
        }
        JsonNode resolvers = componentContext.get("fieldResolvers");
        if (resolvers == null || !resolvers.isObject()) {
            return out;
        }
        resolvers.fields().forEachRemaining(entry -> {
            String path = entry.getKey();
            if (path == null || path.isBlank()) {
                return;
            }
            List<String> keys = parseResolverKeys(entry.getValue(), false);
            ArrayNode items = collectResolverItems(currentState, path, keys);
            if (items.size() == 0) {
                return;
            }
            ObjectNode node = objectMapper.createObjectNode();
            node.put("path", path);
            node.set("items", items);
            out.add(node);
        });
        return out;
    }

    private List<String> buildTargetOptions(ArrayNode targetCandidates) {
        if (targetCandidates == null || !targetCandidates.isArray()) {
            return List.of();
        }
        java.util.LinkedHashSet<String> out = new java.util.LinkedHashSet<>();
        for (JsonNode candidateNode : targetCandidates) {
            if (candidateNode == null || !candidateNode.isObject()) continue;
            JsonNode itemsNode = candidateNode.get("items");
            if (itemsNode == null || !itemsNode.isArray()) continue;
            for (JsonNode item : itemsNode) {
                String label = extractCandidateLabel(item);
                if (label != null && !label.isBlank()) {
                    out.add(label);
                }
            }
        }
        return new ArrayList<>(out);
    }

    private String extractCandidateLabel(JsonNode item) {
        if (item == null || item.isNull()) {
            return null;
        }
        if (item.isTextual() || item.isNumber()) {
            return item.asText();
        }
        if (!item.isObject()) {
            return null;
        }
        String[] preferred = new String[] { "field", "id", "name", "label", "value", "key" };
        for (String key : preferred) {
            JsonNode value = item.get(key);
            if (value != null && !value.isNull() && !value.asText().isBlank()) {
                return value.asText();
            }
        }
        var fields = item.fields();
        while (fields.hasNext()) {
            var entry = fields.next();
            JsonNode value = entry.getValue();
            if (value != null && value.isValueNode() && !value.asText().isBlank()) {
                return value.asText();
            }
        }
        return null;
    }

    private ArrayNode collectResolverItems(JsonNode currentState, String path, List<String> keys) {
        ArrayNode out = objectMapper.createArrayNode();
        if (currentState == null || path == null || path.isBlank()) {
            return out;
        }
        String arrayPath = resolverArrayPath(path);
        List<JsonNode> nodes = collectNodesByPath(currentState, arrayPath);
        if (nodes.isEmpty()) {
            return out;
        }
        int limit = MAX_TARGET_CANDIDATES_PER_PATH;
        for (JsonNode node : nodes) {
            if (out.size() >= limit) {
                break;
            }
            if (node == null || node.isNull()) {
                continue;
            }
            if (node.isObject()) {
                ObjectNode item = objectMapper.createObjectNode();
                if (keys == null || keys.isEmpty()) {
                    node.fields().forEachRemaining(entry -> {
                        JsonNode value = entry.getValue();
                        if (value != null && value.isValueNode()) {
                            item.set(entry.getKey(), value);
                        }
                    });
                } else {
                    for (String key : keys) {
                        if (key == null || key.isBlank()) continue;
                        JsonNode value = node.get(key);
                        if (value != null && value.isValueNode()) {
                            item.set(key, value);
                        }
                    }
                }
                if (item.size() > 0) {
                    out.add(item);
                }
            } else if (node.isValueNode()) {
                out.add(node);
            }
        }
        return out;
    }

    private String resolverArrayPath(String path) {
        int idx = path.lastIndexOf("[]");
        if (idx < 0) {
            return path;
        }
        return path.substring(0, idx + 2);
    }

    private List<JsonNode> collectNodesByPath(JsonNode root, String path) {
        if (root == null || path == null || path.isBlank()) {
            return List.of();
        }
        List<PathToken> tokens = parsePathTokens(path);
        if (tokens.isEmpty()) {
            return List.of();
        }
        List<JsonNode> nodes = new ArrayList<>();
        nodes.add(root);
        for (PathToken token : tokens) {
            List<JsonNode> next = new ArrayList<>();
            for (JsonNode node : nodes) {
                if (node == null || node.isNull()) {
                    continue;
                }
                JsonNode child = node.get(token.name);
                if (child == null || child.isNull()) {
                    continue;
                }
                if (token.isArray) {
                    if (child.isArray()) {
                        for (JsonNode item : child) {
                            if (item != null && !item.isNull()) {
                                next.add(item);
                            }
                        }
                    }
                } else {
                    next.add(child);
                }
            }
            nodes = next;
            if (nodes.isEmpty()) {
                break;
            }
        }
        return nodes;
    }

    private List<PathToken> parsePathTokens(String path) {
        if (path == null || path.isBlank()) {
            return List.of();
        }
        String normalized = path.trim();
        String[] parts = normalized.split("\\.");
        List<PathToken> tokens = new ArrayList<>();
        for (String part : parts) {
            if (part == null || part.isBlank()) {
                continue;
            }
            boolean isArray = part.endsWith("[]");
            String name = isArray ? part.substring(0, part.length() - 2) : part;
            if (name.isBlank()) {
                continue;
            }
            tokens.add(new PathToken(name, isArray));
        }
        return tokens;
    }

    private List<AiActionItem> normalizePlanActions(
            AiActionPlan actionPlan,
            List<ColumnDescriptor> columns,
            Set<String> allowedActionTypes,
            List<String> columnResolverKeys,
            Set<String> globalActionTypes) {
        if (actionPlan == null || actionPlan.getActions() == null || actionPlan.getActions().isEmpty()) {
            return List.of();
        }
        Set<String> allowed = allowedActionTypes == null ? Set.of() : allowedActionTypes;
        if (allowed.isEmpty()) {
            return List.of();
        }
        List<AiActionItem> out = new ArrayList<>();
        for (AiActionPlan.Action action : actionPlan.getActions()) {
            if (action == null) continue;
            String type = action.getType() != null ? action.getType().trim().toUpperCase() : null;
            String target = action.getTarget() != null ? action.getTarget().trim() : null;
            String value = textOrNull(action.getValue());

            boolean isGlobal = type != null && globalActionTypes != null
                    && globalActionTypes.contains(normalizeActionKey(type));

            if (type == null || type.isBlank()) {
                continue;
            }
            if ((target == null || target.isBlank()) && !isGlobal) {
                continue;
            }
            if (!allowed.contains(type)) {
                continue;
            }
            String resolvedField = null;
            if (isGlobal) {
                target = null;
            } else if (target != null && !target.isBlank()) {
                resolvedField = resolveActionField(target, columns, columnResolverKeys);
            }
            out.add(AiActionItem.builder()
                    .type(type)
                    .field(resolvedField != null ? resolvedField : target)
                    .value(value)
                    .build());
        }
        return out;
    }

    private AiActionPlan pruneTableActionPlanByClassifiedIntent(
            AiActionPlan actionPlan,
            AiIntentClassification intent,
            List<ComponentAction> actionCatalog,
            JsonNode authoringManifest,
            List<String> warnings) {
        if (actionPlan == null
                || actionPlan.getActions() == null
                || actionPlan.getActions().isEmpty()
                || intent == null) {
            return actionPlan;
        }
        String category = normalizeIntentCategory(intent.getCategory());
        if (category == null) {
            return actionPlan;
        }
        List<AiActionPlan.Action> retained = new ArrayList<>();
        for (AiActionPlan.Action action : actionPlan.getActions()) {
            if (action == null || isBlank(action.getType())) {
                continue;
            }
            if (isTableActionCompatibleWithIntentCategory(
                    action,
                    category,
                    actionCatalog,
                    authoringManifest)) {
                retained.add(action);
            }
        }
        if (retained.size() == actionPlan.getActions().size()) {
            return actionPlan;
        }
        if (retained.isEmpty()) {
            if (warnings != null) {
                warnings.add("table-action-plan-intent-pruning-kept-empty:" + category);
            }
            return actionPlan;
        }
        actionPlan.setActions(retained);
        if (warnings != null) {
            warnings.add("table-action-plan-pruned-by-llm-intent:" + category);
        }
        return actionPlan;
    }

    private String normalizeIntentCategory(String category) {
        if (category == null || category.isBlank()) {
            return null;
        }
        String normalized = category.trim().toLowerCase(Locale.ROOT);
        return switch (normalized) {
            case "actions", "toolbar", "export" -> "global-actions";
            case "format", "renderer", "conditional", "columns", "sorting", "filtering", "mapping" -> normalized;
            case "selection", "pagination", "appearance", "behavior", "messages", "localization",
                    "performance", "interaction", "data", "accessibility", "meta" -> "global-config";
            default -> normalized;
        };
    }

    private boolean isTableActionCompatibleWithIntentCategory(
            AiActionPlan.Action action,
            String category,
            List<ComponentAction> actionCatalog,
            JsonNode authoringManifest) {
        String actionType = action != null ? action.getType() : null;
        if (isBlank(actionType) || isBlank(category)) {
            return false;
        }
        JsonNode manifestOperation = findManifestOperation(authoringManifest, actionType);
        String operationId = normalizeActionKey(actionType);
        String targetKind = normalizeActionKey(textOrNull(
                firstPresent(
                        manifestOperation != null ? manifestOperation.get("targetKind") : null,
                        manifestOperation != null ? manifestOperation.at("/target/kind") : null)));
        List<String> affectedPaths = readStringArray(
                manifestOperation != null ? manifestOperation.get("affectedPaths") : null);
        ComponentAction catalogAction = findComponentAction(actionCatalog, actionType);
        String scope = catalogAction != null ? normalizeActionKey(catalogAction.scope) : null;
        boolean globalScope = "global".equals(scope)
                || "global".equals(normalizeActionKey(textOrNull(
                        manifestOperation != null ? manifestOperation.get("scope") : null)));

        return switch (category) {
            case "global-actions" -> globalScope
                    && (operationId.startsWith("toolbar")
                    || operationId.startsWith("export")
                    || operationId.startsWith("actions")
                    || "toolbar".equals(targetKind)
                    || "export".equals(targetKind)
                    || targetKind.contains("action")
                    || anyPathStartsWith(affectedPaths, List.of("toolbar", "export", "actions")));
            case "global-config" -> globalScope;
            case "format" -> operationId.startsWith("column.format")
                    || operationId.contains(".format")
                    || anyPathStartsWith(affectedPaths, List.of("columns[].format", "columns[].type", "columns[].computed"));
            case "renderer" -> operationId.contains("renderer")
                    || anyPathStartsWith(affectedPaths, List.of("columns[].renderer", "columns[].conditionalRenderers"));
            case "conditional" -> operationId.contains("conditional")
                    || anyPathStartsWith(affectedPaths, List.of("columns[].conditional", "rowConditional"));
            case "sorting" -> operationId.contains("sort")
                    || anyPathStartsWith(affectedPaths, List.of("behavior.sorting", "columns[].sortable"));
            case "filtering" -> operationId.contains("filter")
                    || anyPathStartsWith(affectedPaths, List.of("behavior.filtering", "columns[].filterable"));
            case "mapping" -> operationId.contains("mapping")
                    || anyPathStartsWith(affectedPaths, List.of("columns[].valueMapping"));
            case "columns" -> !globalScope || anyPathStartsWith(affectedPaths, List.of("columns"));
            default -> true;
        };
    }

    private ComponentAction findComponentAction(List<ComponentAction> actionCatalog, String actionType) {
        if (actionCatalog == null || actionCatalog.isEmpty() || isBlank(actionType)) {
            return null;
        }
        String normalized = normalizeActionKey(actionType);
        for (ComponentAction action : actionCatalog) {
            if (action == null || isBlank(action.id)) {
                continue;
            }
            if (normalized.equals(normalizeActionKey(action.id))) {
                return action;
            }
        }
        return null;
    }

    private boolean anyPathStartsWith(List<String> paths, List<String> prefixes) {
        if (paths == null || paths.isEmpty() || prefixes == null || prefixes.isEmpty()) {
            return false;
        }
        for (String path : paths) {
            if (path == null || path.isBlank()) {
                continue;
            }
            for (String prefix : prefixes) {
                if (prefix != null && !prefix.isBlank() && path.startsWith(prefix)) {
                    return true;
                }
            }
        }
        return false;
    }

    private AiActionPlan dedupeIdempotentTableActionsByTarget(
            AiActionPlan actionPlan,
            List<String> warnings) {
        if (actionPlan == null || actionPlan.getActions() == null || actionPlan.getActions().size() < 2) {
            return actionPlan;
        }
        Map<String, AiActionPlan.Action> retained = new LinkedHashMap<>();
        List<AiActionPlan.Action> ordered = new ArrayList<>();
        boolean changed = false;
        for (AiActionPlan.Action action : actionPlan.getActions()) {
            if (action == null || !isIdempotentTableAction(action.getType())) {
                ordered.add(action);
                continue;
            }
            String key = normalizeActionKey(action.getType()) + ":" + safe(action.getTarget());
            AiActionPlan.Action previous = retained.put(key, action);
            if (previous == null) {
                ordered.add(action);
                continue;
            }
            int index = ordered.indexOf(previous);
            if (index >= 0) {
                ordered.set(index, action);
            } else {
                ordered.add(action);
            }
            changed = true;
        }
        if (changed) {
            actionPlan.setActions(ordered);
            if (warnings != null) {
                warnings.add("table-action-plan-idempotent-actions-deduped");
            }
        }
        return actionPlan;
    }

    private String tableActionPlanSafetyViolationMessage(AiActionPlan actionPlan) {
        if (actionPlan == null || actionPlan.getActions() == null || actionPlan.getActions().isEmpty()) {
            return null;
        }
        for (AiActionPlan.Action action : actionPlan.getActions()) {
            if (isAccessibilityRegressionAction(action)) {
                return "Não posso aplicar uma alteração que reduza proteções de acessibilidade da tabela. "
                        + "Posso ajudar a ativar alto contraste, reduzir movimento ou ajustar animações preservando a política de acessibilidade.";
            }
        }
        return null;
    }

    private boolean isAccessibilityRegressionAction(AiActionPlan.Action action) {
        if (action == null || !"accessibility.configure".equals(normalizeActionKey(action.getType()))) {
            return false;
        }
        JsonNode input = action.getParams();
        if (input == null || input.isNull() || input.isMissingNode()) {
            input = action.getValue();
        }
        if (input == null || input.isNull() || input.isMissingNode()) {
            return true;
        }
        if (!input.isObject() || input.isEmpty()) {
            return true;
        }
        boolean enablesKnownProtection = booleanFieldIsTrue(input, "enabled")
                || booleanFieldIsTrue(input, "highContrast")
                || booleanFieldIsTrue(input, "reduceMotion")
                || booleanPointerIsTrue(input, "/keyboard/shortcuts")
                || textPointerIsPresent(input, "/announcements/liveRegion");
        if (!enablesKnownProtection) {
            return true;
        }
        return booleanFieldIsFalse(input, "enabled")
                || booleanFieldIsFalse(input, "highContrast")
                || booleanFieldIsFalse(input, "reduceMotion")
                || booleanPointerIsFalse(input, "/keyboard/shortcuts");
    }

    private boolean booleanFieldIsTrue(JsonNode node, String field) {
        return node != null && node.has(field) && node.get(field).isBoolean() && node.get(field).asBoolean();
    }

    private boolean booleanFieldIsFalse(JsonNode node, String field) {
        return node != null && node.has(field) && node.get(field).isBoolean() && !node.get(field).asBoolean();
    }

    private boolean booleanPointerIsTrue(JsonNode node, String pointer) {
        JsonNode value = node != null ? node.at(pointer) : null;
        return value != null && value.isBoolean() && value.asBoolean();
    }

    private boolean booleanPointerIsFalse(JsonNode node, String pointer) {
        JsonNode value = node != null ? node.at(pointer) : null;
        return value != null && value.isBoolean() && !value.asBoolean();
    }

    private boolean textPointerIsPresent(JsonNode node, String pointer) {
        JsonNode value = node != null ? node.at(pointer) : null;
        return value != null && value.isTextual() && !value.asText().isBlank();
    }

    private boolean isIdempotentTableAction(String actionType) {
        if (isBlank(actionType)) {
            return false;
        }
        String normalized = normalizeActionKey(actionType);
        return normalized.endsWith(".set")
                || normalized.endsWith(".configure")
                || "column.visibility.toggle".equals(normalized)
                || "column.width.set".equals(normalized)
                || "column.align.set".equals(normalized);
    }

    private boolean isGlobalTableActionIntent(AiIntentClassification intent) {
        return "global-actions".equals(normalizeIntentCategory(intent != null ? intent.getCategory() : null));
    }

    private List<String> collectAmbiguityOptions(AiActionPlan actionPlan) {
        if (actionPlan == null || actionPlan.getAmbiguities() == null
                || actionPlan.getAmbiguities().isEmpty()) {
            return List.of();
        }
        java.util.LinkedHashSet<String> options = new java.util.LinkedHashSet<>();
        for (AiActionPlan.Ambiguity ambiguity : actionPlan.getAmbiguities()) {
            if (ambiguity == null) continue;
            List<String> candidates = ambiguity.getCandidates();
            if (candidates != null && !candidates.isEmpty()) {
                for (String candidate : candidates) {
                    if (candidate != null && !candidate.isBlank()) {
                        options.add(candidate);
                    }
                }
            } else if (ambiguity.getAlias() != null && !ambiguity.getAlias().isBlank()) {
                options.add(ambiguity.getAlias());
            }
        }
        return new ArrayList<>(options);
    }

    private boolean isActionPlanEmpty(AiActionPlan actionPlan) {
        return actionPlan == null
                || actionPlan.getActions() == null
                || actionPlan.getActions().isEmpty();
    }

    private boolean shouldProbeTableActionsForMissingContext(
            boolean isTable,
            List<ComponentAction> componentActions,
            List<String> missingContext,
            AiOrchestratorRequest request,
            JsonNode currentState,
            List<ColumnDescriptor> columns) {
        if (!isTable || componentActions == null || componentActions.isEmpty()) {
            return false;
        }
        boolean missingColumn = missingContext != null
                && missingContext.stream()
                .map(this::normalizeMissingKey)
                .anyMatch(key -> key.contains("column"));
        if (missingColumn) {
            return true;
        }
        String prompt = request != null ? request.getUserPrompt() : null;
        String normalizedPrompt = normalizeText(prompt);
        if (!looksLikeContextualTableContinuation(normalizedPrompt)) {
            return false;
        }
        return resolveContinuationColumn(request, currentState, columns) != null;
    }

    private boolean hasManifestBackedGlobalAction(AiActionPlan actionPlan, JsonNode authoringManifest) {
        if (actionPlan == null
                || actionPlan.getActions() == null
                || actionPlan.getActions().isEmpty()
                || authoringManifest == null
                || !authoringManifest.isObject()) {
            return false;
        }
        Map<String, JsonNode> operationsById = indexManifestOperations(authoringManifest, new ArrayList<>());
        for (AiActionPlan.Action action : actionPlan.getActions()) {
            if (action == null || isBlank(action.getType())) {
                continue;
            }
            JsonNode operation = operationsById.get(action.getType());
            if (operation == null) {
                operation = operationsById.get(normalizeActionKey(action.getType()));
            }
            if (operation == null || operation.isMissingNode()) {
                continue;
            }
            if ("global".equalsIgnoreCase(textOrNull(operation.get("scope")))) {
                return true;
            }
            JsonNode required = operation.at("/target/required");
            if (required != null && required.isBoolean() && !required.asBoolean()) {
                return true;
            }
        }
        return false;
    }

    private AiActionPlan deriveFallbackTableManifestActionPlan(
            AiOrchestratorRequest request,
            AiIntentClassification intent,
            JsonNode currentState,
            List<ColumnDescriptor> columns,
            List<ComponentAction> actionCatalog,
            JsonNode authoringManifest) {
        if (request == null
                || isBlank(request.getUserPrompt())
                || columns == null
                || columns.isEmpty()
                || authoringManifest == null
                || !authoringManifest.isObject()) {
            return null;
        }
        String prompt = request.getUserPrompt();
        String normalizedPrompt = normalizeText(prompt);
        ColumnDescriptor explicitTargetColumn = resolvePromptColumn(prompt, intent, columns);
        ColumnDescriptor targetColumn = explicitTargetColumn;
        if (targetColumn == null && looksLikeContextualTableContinuation(normalizedPrompt)) {
            targetColumn = resolveContinuationColumn(request, currentState, columns);
        }

        if (targetColumn != null
                && isTableManifestOperationAvailable(actionCatalog, authoringManifest, "column.valueMapping.set")
                && looksLikeBooleanValueMappingPrompt(normalizedPrompt)) {
            AiActionPlan mappingPlan = buildBooleanValueMappingActionPlan(normalizedPrompt, targetColumn);
            if (mappingPlan != null) {
                return mappingPlan;
            }
        }

        ColumnDescriptor booleanStateTargetColumn = null;
        if (isTableManifestOperationAvailable(actionCatalog, authoringManifest, "column.conditionalRenderer.add")
                && looksLikeBooleanStateRendererPrompt(normalizedPrompt)) {
            booleanStateTargetColumn = resolveBooleanStateRendererTargetColumn(
                    explicitTargetColumn,
                    targetColumn,
                    request,
                    currentState,
                    columns);
            ColumnDescriptor rendererTargetColumn = booleanStateTargetColumn;
            AiActionPlan rendererPlan = buildBooleanStateRendererActionPlan(normalizedPrompt, rendererTargetColumn, currentState);
            if (rendererPlan != null) {
                return rendererPlan;
            }
        }

        if (isTableManifestOperationAvailable(actionCatalog, authoringManifest, "column.computed.add")) {
            AiActionPlan computedPlan = buildComputedColumnActionPlan(prompt, normalizedPrompt, columns, request, currentState);
            if (computedPlan != null) {
                return computedPlan;
            }
        }

        if (targetColumn != null
                && isTableManifestOperationAvailable(actionCatalog, authoringManifest, "column.format.set")
                && looksLikeTableFormatCommand(prompt.toLowerCase(Locale.ROOT))
                && !looksLikeRichColumnRendererPrompt(normalizedPrompt)) {
            AiActionPlan formatPlan = buildColumnFormatActionPlan(prompt, normalizedPrompt, targetColumn);
            if (formatPlan != null) {
                return formatPlan;
            }
        }

        if (isTableManifestOperationAvailable(actionCatalog, authoringManifest, "column.renderer.set")
                && looksLikeAvatarRendererRepairPrompt(normalizedPrompt)) {
            ColumnDescriptor avatarColumn = resolveAvatarRendererTargetColumn(targetColumn, currentState, columns);
            AiActionPlan rendererPlan = buildAvatarRendererRepairActionPlan(avatarColumn);
            if (rendererPlan != null) {
                return rendererPlan;
            }
        }

        if (isTableManifestOperationAvailable(actionCatalog, authoringManifest, "column.renderer.set")
                && looksLikeComposeRendererRefinementPrompt(normalizedPrompt)
                && !looksLikeConditionalChipTablePrompt(normalizedPrompt)
                && booleanStateTargetColumn == null) {
            ColumnDescriptor rendererColumn = resolveAvatarRendererTargetColumn(targetColumn, currentState, columns);
            AiActionPlan rendererPlan = buildComposeRendererRefinementActionPlan(
                    normalizedPrompt,
                    request,
                    rendererColumn,
                    currentState);
            if (rendererPlan != null) {
                return rendererPlan;
            }
        }

        if (targetColumn != null
                && isTableManifestOperationAvailable(actionCatalog, authoringManifest, "column.renderer.set")
                && looksLikeRichColumnRendererPrompt(normalizedPrompt)
                && !looksLikeConditionalChipTablePrompt(normalizedPrompt)) {
            ColumnDescriptor rendererTargetColumn = targetColumn;
            if (explicitTargetColumn == null && looksLikeContextualTableContinuation(normalizedPrompt)) {
                ColumnDescriptor conversationColumn = resolveContinuationColumnFromConversation(request, columns);
                if (conversationColumn != null) {
                    rendererTargetColumn = conversationColumn;
                }
            }
            AiActionPlan rendererPlan = buildRichColumnRendererActionPlan(
                    normalizedPrompt,
                    rendererTargetColumn,
                    currentState);
            if (rendererPlan != null) {
                return rendererPlan;
            }
        }

        if (targetColumn != null
                && isTableManifestOperationAvailable(actionCatalog, authoringManifest, "column.conditionalStyle.add")
                && looksLikeConditionalVisualTablePrompt(normalizedPrompt)) {
            ColumnDescriptor styleTargetColumn = targetColumn;
            boolean idLikeContextualFalsePositive = explicitTargetColumn != null
                    && isIdLikeField(explicitTargetColumn.field)
                    && looksLikeContextualTableContinuation(normalizedPrompt)
                    && !promptExplicitlyMentionsIdColumn(normalizedPrompt);
            if ((explicitTargetColumn == null || idLikeContextualFalsePositive)
                    && looksLikeContextualTableContinuation(normalizedPrompt)) {
                ColumnDescriptor conversationColumn = resolveConditionalStyleColumnFromConversation(request, columns);
                if (conversationColumn != null) {
                    styleTargetColumn = conversationColumn;
                } else {
                    ColumnDescriptor stateColumn = resolveConditionalStyleColumnFromCurrentState(currentState, columns);
                    if (stateColumn != null) {
                        styleTargetColumn = stateColumn;
                    }
                }
            }
            AiActionPlan stylePlan = null;
            if ((explicitTargetColumn == null || idLikeContextualFalsePositive)
                    && looksLikeContextualTableContinuation(normalizedPrompt)) {
                stylePlan = buildConditionalStyleActionPlanFromConversation(
                        prompt,
                        normalizedPrompt,
                        styleTargetColumn,
                        request,
                        currentState);
            }
            if (stylePlan == null) {
                stylePlan = buildConditionalStyleActionPlan(prompt, normalizedPrompt, styleTargetColumn, currentState);
            }
            if (stylePlan == null) {
                stylePlan = buildConditionalStyleActionPlanFromConversation(
                        prompt,
                        normalizedPrompt,
                        styleTargetColumn,
                        request,
                        currentState);
            }
            if (stylePlan != null) {
                return stylePlan;
            }
        }

        if (targetColumn != null
                && isTableManifestOperationAvailable(actionCatalog, authoringManifest, "column.conditionalRenderer.add")
                && looksLikeConditionalChipTablePrompt(normalizedPrompt)) {
            AiActionPlan chipPlan = buildConditionalChipActionPlan(prompt, normalizedPrompt, targetColumn, currentState);
            if (chipPlan == null) {
                chipPlan = buildConditionalChipActionPlanFromConversation(
                        prompt,
                        normalizedPrompt,
                        targetColumn,
                        request,
                        currentState);
            }
            if (chipPlan != null) {
                return chipPlan;
            }
        }

        if (isTableManifestOperationAvailable(actionCatalog, authoringManifest, "row.conditionalRenderer.add")
                && looksLikeRowAnimationTablePrompt(normalizedPrompt)) {
            ColumnDescriptor animationTargetColumn = targetColumn;
            boolean idLikeContextualFalsePositive = explicitTargetColumn != null
                    && isIdLikeField(explicitTargetColumn.field)
                    && looksLikeContextualTableContinuation(normalizedPrompt)
                    && !promptExplicitlyMentionsIdColumn(normalizedPrompt);
            if (looksLikeContextualTableContinuation(normalizedPrompt)
                    && !hasExplicitThresholdOrSemanticFieldReference(normalizedPrompt)) {
                animationTargetColumn = null;
            }
            if ((animationTargetColumn == null || idLikeContextualFalsePositive)
                    && looksLikeContextualTableContinuation(normalizedPrompt)) {
                ColumnDescriptor rowContextColumn = resolveRowAnimationColumnFromCurrentState(currentState, columns);
                if (rowContextColumn != null) {
                    animationTargetColumn = rowContextColumn;
                } else {
                    ColumnDescriptor conversationColumn = resolveRowAnimationColumnFromConversation(request, columns);
                    if (conversationColumn != null) {
                        animationTargetColumn = conversationColumn;
                    } else if (idLikeContextualFalsePositive) {
                        animationTargetColumn = null;
                    }
                }
            }
            AiActionPlan animationPlan = buildRowAnimationActionPlan(prompt, normalizedPrompt, animationTargetColumn, currentState, columns);
            if (animationPlan == null) {
                animationPlan = buildRowAnimationActionPlanFromConversation(
                        prompt,
                        normalizedPrompt,
                        animationTargetColumn,
                        request,
                        currentState);
            }
            if (animationPlan != null) {
                return animationPlan;
            }
        }

        return null;
    }

    private AiActionPlan buildColumnFormatActionPlan(
            String prompt,
            String normalizedPrompt,
            ColumnDescriptor targetColumn) {
        if (isBlank(prompt) || targetColumn == null || isBlank(targetColumn.field)) {
            return null;
        }
        List<ContextOption> formatOptions = defaultTableFormatOptionsForPrompt(normalizedPrompt, targetColumn.field);
        String format = inferFormatFromPrompt(prompt, formatOptions);
        if (isBlank(format)) {
            format = inferFormatFromPromptForColumn(normalizedPrompt, targetColumn, formatOptions);
        }
        if (isBlank(format)) {
            return null;
        }
        ObjectNode input = objectMapper.createObjectNode();
        input.put("format", format);
        return AiActionPlan.builder()
                .actions(List.of(AiActionPlan.Action.builder()
                        .type("column.format.set")
                        .target(targetColumn.field)
                        .params(input)
                        .build()))
                .ambiguities(List.of())
                .build();
    }

    private JsonNode buildFormatPatchFromActionPlan(AiActionPlan actionPlan) {
        if (actionPlan == null || actionPlan.getActions() == null || actionPlan.getActions().isEmpty()) {
            return null;
        }
        ObjectNode patch = objectMapper.createObjectNode();
        ArrayNode columns = patch.putArray("columns");
        for (AiActionPlan.Action action : actionPlan.getActions()) {
            if (action == null || !"column.format.set".equalsIgnoreCase(action.getType())) {
                continue;
            }
            String field = trimToNull(action.getTarget());
            String format = textOrNull(action.getParams() != null ? action.getParams().get("format") : null);
            if (field == null || isBlank(format)) {
                continue;
            }
            ObjectNode column = columns.addObject();
            column.put("field", field);
            column.put("format", format);
        }
        return columns.isEmpty() ? null : patch;
    }

    private List<ContextOption> defaultTableFormatOptionsForPrompt(String normalizedPrompt, String targetField) {
        List<ContextOption> options = new ArrayList<>();
        if (isSensitiveMaskField(targetField) || containsSensitiveFieldToken(normalizedPrompt)) {
            options.addAll(buildMaskOptionsForField(targetField));
        }
        options.add(new ContextOption("dd/MM/yyyy", "Date dd/MM/yyyy", "13/06/2022"));
        options.add(new ContextOption("fullDate", "Date full", "segunda-feira, 13 de junho de 2022"));
        options.add(new ContextOption("MMM/yyyy", "Month/Year", "jun./2022"));
        options.add(new ContextOption("BRL|symbol|2", "Currency BRL symbol", "R$ 1.234,56"));
        options.add(new ContextOption("1.0-0", "Number integer", "1234"));
        options.add(new ContextOption("1.2-2", "Number decimal", "1.234,56"));
        options.add(new ContextOption("1.0-2|x100", "Percent", "12,34%"));
        options.add(new ContextOption("active-inactive", "Ativo/Inativo", "Ativo / Inativo"));
        options.add(new ContextOption("yes-no", "Sim/Não", "Sim / Não"));
        options.add(new ContextOption("custom|Sim|Nao", "Sim/Não personalizado", "Sim / Não"));
        options.add(new ContextOption("true-false", "Verdadeiro/Falso", "true / false"));
        return options;
    }

    private boolean isTableManifestOperationAvailable(
            List<ComponentAction> actionCatalog,
            JsonNode authoringManifest,
            String operationId) {
        return findManifestOperation(authoringManifest, operationId) != null;
    }

    private ColumnDescriptor resolvePromptColumn(
            String prompt,
            AiIntentClassification intent,
            List<ColumnDescriptor> columns) {
        if (columns == null || columns.isEmpty()) {
            return null;
        }
        String targetField = intent != null ? intent.getTargetField() : null;
        String resolved = resolveActionField(targetField, columns, List.of("field", "header"));
        if (resolved != null) {
            return findColumnByField(resolved, columns);
        }
        if (prompt == null || prompt.isBlank()) {
            return null;
        }
        String promptLower = prompt.toLowerCase(Locale.ROOT);
        String normalizedPrompt = normalizeText(prompt);
        for (ColumnDescriptor column : columns) {
            if (column == null || column.field == null || column.field.isBlank()) {
                continue;
            }
            if (clauseMentionsColumn(promptLower, column, List.of("field", "header"))) {
                return column;
            }
            String normalizedField = normalizeText(column.field);
            String normalizedHeader = normalizeText(column.header);
            if (!normalizedField.isBlank()
                    && normalizedColumnTokenMatches(normalizedPrompt, normalizedField)) {
                return column;
            }
            if (!normalizedHeader.isBlank() && normalizedPrompt.contains(normalizedHeader)) {
                return column;
            }
        }
        return null;
    }

    private boolean normalizedColumnTokenMatches(String normalizedPrompt, String normalizedField) {
        if (isBlank(normalizedPrompt) || isBlank(normalizedField)) {
            return false;
        }
        if (normalizedField.length() <= 2 || "id".equals(normalizedField)) {
            return containsWord(normalizedPrompt, normalizedField);
        }
        return normalizedPrompt.contains(normalizedField);
    }

    private boolean looksLikeContextualTableContinuation(String normalizedPrompt) {
        if (normalizedPrompt == null || normalizedPrompt.isBlank()) {
            return false;
        }
        return normalizedPrompt.contains("agora")
                || normalizedPrompt.contains("tambem")
                || normalizedPrompt.contains("também")
                || normalizedPrompt.contains("os menores")
                || normalizedPrompt.contains("os maiores")
                || normalizedPrompt.contains("menor")
                || normalizedPrompt.contains("maior")
                || normalizedPrompt.contains("abaixo")
                || normalizedPrompt.contains("acima")
                || normalizedPrompt.contains("restante")
                || normalizedPrompt.contains("demais")
                || normalizedPrompt.contains("troque")
                || normalizedPrompt.contains("mude")
                || normalizedPrompt.contains("altere")
                || normalizedPrompt.contains("repita")
                || normalizedPrompt.contains("repetir")
                || normalizedPrompt.contains("vez")
                || normalizedPrompt.contains("volte");
    }

    private ColumnDescriptor resolveContinuationColumnFromCurrentState(
            JsonNode currentState,
            List<ColumnDescriptor> columns) {
        if (currentState == null || columns == null || columns.isEmpty()) {
            return null;
        }
        String field = findLastColumnFieldWithConditionalAuthoring(currentState);
        if (isBlank(field)) {
            field = findLastColumnFieldWithFormatAuthoring(currentState);
        }
        if (isBlank(field)) {
            field = findLastColumnFieldWithValueMappingAuthoring(currentState);
        }
        if (isBlank(field)) {
            field = findLastColumnFieldWithRendererAuthoring(currentState);
        }
        if (isBlank(field)) {
            field = findLastColumnFieldWithComputedAuthoring(currentState);
        }
        if (isBlank(field)) {
            return null;
        }
        return findColumnByField(field, columns);
    }

    private ColumnDescriptor resolveContinuationColumn(
            AiOrchestratorRequest request,
            JsonNode currentState,
            List<ColumnDescriptor> columns) {
        ColumnDescriptor fromState = resolveContinuationColumnFromCurrentState(currentState, columns);
        if (fromState != null) {
            return fromState;
        }
        return resolveContinuationColumnFromConversation(request, columns);
    }

    private ColumnDescriptor resolveVisualPropertyContinuationColumn(
            AiOrchestratorRequest request,
            JsonNode currentState,
            List<ColumnDescriptor> columns) {
        ColumnDescriptor fromConversation = resolveContinuationColumnFromConversation(request, columns);
        if (fromConversation != null) {
            return fromConversation;
        }
        String field = findLastColumnFieldWithVisualPropertyAuthoring(currentState);
        if (!isBlank(field)) {
            ColumnDescriptor column = findColumnByField(field, columns);
            if (column != null) {
                return column;
            }
        }
        return resolveContinuationColumnFromCurrentState(currentState, columns);
    }

    private ColumnDescriptor resolveContinuationColumnFromConversation(
            AiOrchestratorRequest request,
            List<ColumnDescriptor> columns) {
        if (request == null || request.getMessages() == null || request.getMessages().isEmpty()
                || columns == null || columns.isEmpty()) {
            return null;
        }
        for (int i = request.getMessages().size() - 1; i >= 0; i--) {
            AiChatMessage message = request.getMessages().get(i);
            String role = message != null ? trimToNull(message.getRole()) : null;
            if (role != null && !"user".equalsIgnoreCase(role)) {
                continue;
            }
            String content = message != null ? message.getContent() : null;
            if (isBlank(content)) {
                continue;
            }
            if (looksLikeAssistantTechnicalPayload(content)) {
                continue;
            }
            ColumnDescriptor explicit = resolvePromptColumn(content, null, columns);
            if (explicit != null) {
                return explicit;
            }
            String normalized = normalizeText(content);
            if ((normalized.contains("salario") || normalized.contains("remuneracao"))
                    && resolveActionField("salario", columns, List.of("field", "header")) != null) {
                return findColumnByField(resolveActionField("salario", columns, List.of("field", "header")), columns);
            }
            if ((normalized.contains("admiss") || normalized.contains("data"))
                    && resolveActionField("dataAdmissao", columns, List.of("field", "header")) != null) {
                return findColumnByField(resolveActionField("dataAdmissao", columns, List.of("field", "header")), columns);
            }
            if (looksLikeAvatarRendererRepairPrompt(normalized) || looksLikeComposeRendererRefinementPrompt(normalized)) {
                ColumnDescriptor avatarColumn = resolveAvatarRendererColumnFromCurrentState(null, columns);
                if (avatarColumn != null) {
                    return avatarColumn;
                }
            }
        }
        return null;
    }

    private ColumnDescriptor resolveConditionalStyleColumnFromConversation(
            AiOrchestratorRequest request,
            List<ColumnDescriptor> columns) {
        if (request == null || request.getMessages() == null || request.getMessages().isEmpty()
                || columns == null || columns.isEmpty()) {
            return null;
        }
        for (int i = request.getMessages().size() - 1; i >= 0; i--) {
            AiChatMessage message = request.getMessages().get(i);
            String role = message != null ? trimToNull(message.getRole()) : null;
            if (role != null && !"user".equalsIgnoreCase(role)) {
                continue;
            }
            String content = message != null ? message.getContent() : null;
            if (isBlank(content) || looksLikeAssistantTechnicalPayload(content)) {
                continue;
            }
            String normalized = normalizeText(content);
            boolean conditionalVisualSignal = looksLikeConditionalVisualTablePrompt(normalized)
                    || looksLikeConditionalChipTablePrompt(normalized)
                    || looksLikeRowAnimationTablePrompt(normalized);
            if (!conditionalVisualSignal) {
                continue;
            }
            ColumnDescriptor explicit = resolvePromptColumn(content, null, columns);
            if (explicit != null && !isIdLikeField(explicit.field)) {
                return explicit;
            }
            if ((normalized.contains("salario") || normalized.contains("remuneracao"))
                    && resolveActionField("salario", columns, List.of("field", "header")) != null) {
                return findColumnByField(resolveActionField("salario", columns, List.of("field", "header")), columns);
            }
        }
        return null;
    }

    private ColumnDescriptor resolveConditionalStyleColumnFromCurrentState(
            JsonNode currentState,
            List<ColumnDescriptor> columns) {
        if (currentState == null || columns == null || columns.isEmpty()) {
            return null;
        }
        JsonNode columnsNode = currentState.get("columns");
        if (columnsNode == null || !columnsNode.isArray()) {
            return null;
        }
        String lastField = null;
        String computedField = findLastColumnFieldWithComputedAuthoring(currentState);
        for (JsonNode column : columnsNode) {
            if (column == null || !column.isObject()) {
                continue;
            }
            String field = textOrNull(column.get("field"));
            if (isBlank(field) || isIdLikeField(field)) {
                continue;
            }
            if (hasNonEmptyArray(column.get("conditionalStyles"))) {
                lastField = field;
            }
        }
        if (isBlank(lastField) && !isBlank(computedField)) {
            lastField = computedField;
        }
        return findColumnByField(lastField, columns);
    }

    private ColumnDescriptor resolveRowAnimationColumnFromCurrentState(
            JsonNode currentState,
            List<ColumnDescriptor> columns) {
        String field = findLastRowConditionalRendererField(currentState);
        if (isBlank(field) || isIdLikeField(field)) {
            field = findLastColumnFieldWithConditionalAuthoring(currentState);
        }
        if (isBlank(field) || isIdLikeField(field)) {
            field = findLastColumnFieldWithComputedAuthoring(currentState);
        }
        if (isBlank(field) || isIdLikeField(field)) {
            return null;
        }
        return findColumnByField(field, columns);
    }

    private ColumnDescriptor resolveRowAnimationColumnFromConversation(
            AiOrchestratorRequest request,
            List<ColumnDescriptor> columns) {
        if (request == null || request.getMessages() == null || request.getMessages().isEmpty()
                || columns == null || columns.isEmpty()) {
            return null;
        }
        for (int i = request.getMessages().size() - 1; i >= 0; i--) {
            AiChatMessage message = request.getMessages().get(i);
            String role = message != null ? trimToNull(message.getRole()) : null;
            if (role != null && !"user".equalsIgnoreCase(role)) {
                continue;
            }
            String content = message != null ? message.getContent() : null;
            if (isBlank(content) || looksLikeAssistantTechnicalPayload(content)) {
                continue;
            }
            String normalized = normalizeText(content);
            if (!looksLikeRowAnimationTablePrompt(normalized)
                    && inferThresholdCondition(content, normalized) == null) {
                continue;
            }
            ColumnDescriptor explicit = resolvePromptColumn(content, null, columns);
            if (explicit != null && !isIdLikeField(explicit.field)) {
                return explicit;
            }
            if ((normalized.contains("salario") || normalized.contains("remuneracao"))
                    && resolveActionField("salario", columns, List.of("field", "header")) != null) {
                return findColumnByField(resolveActionField("salario", columns, List.of("field", "header")), columns);
            }
        }
        return null;
    }

    private boolean promptExplicitlyMentionsIdColumn(String normalizedPrompt) {
        if (normalizedPrompt == null || normalizedPrompt.isBlank()) {
            return false;
        }
        return java.util.regex.Pattern.compile("(^|\\s)(id|identificador)(\\s|$)")
                .matcher(normalizedPrompt)
                .find();
    }

    private boolean looksLikeAssistantTechnicalPayload(String content) {
        if (isBlank(content)) {
            return false;
        }
        String normalized = content.toLowerCase(Locale.ROOT);
        return normalized.contains("\"operationid\"")
                || normalized.contains("\"componenteditplan\"")
                || normalized.contains("\"contractversion\"")
                || normalized.contains("\"schemahash\"")
                || normalized.contains("\"warnings\"")
                || normalized.contains("\"optionpayloads\"")
                || normalized.contains("operationid:")
                || normalized.contains("componenteditplan:");
    }

    private String findLastColumnFieldWithConditionalAuthoring(JsonNode currentState) {
        JsonNode columnsNode = currentState != null ? currentState.get("columns") : null;
        if (columnsNode == null || !columnsNode.isArray()) {
            return null;
        }
        String lastField = null;
        for (JsonNode column : columnsNode) {
            if (column == null || !column.isObject()) {
                continue;
            }
            String field = textOrNull(column.get("field"));
            if (isBlank(field)) {
                continue;
            }
            if (hasNonEmptyArray(column.get("conditionalStyles"))
                    || hasNonEmptyArray(column.get("conditionalRenderers"))) {
                lastField = field;
            }
        }
        return lastField;
    }

    private String findLastColumnFieldWithVisualPropertyAuthoring(JsonNode currentState) {
        JsonNode columnsNode = currentState != null ? currentState.get("columns") : null;
        if (columnsNode == null || !columnsNode.isArray()) {
            return null;
        }
        String lastField = null;
        for (JsonNode column : columnsNode) {
            if (column == null || !column.isObject()) {
                continue;
            }
            String field = textOrNull(column.get("field"));
            if (isBlank(field)) {
                continue;
            }
            if (column.has("align")
                    || column.has("width")
                    || column.has("sortable")
                    || column.has("visible")
                    || column.has("filterable")
                    || column.has("sticky")) {
                lastField = field;
            }
        }
        return lastField;
    }

    private String findLastColumnFieldWithFormatAuthoring(JsonNode currentState) {
        JsonNode columnsNode = currentState != null ? currentState.get("columns") : null;
        if (columnsNode == null || !columnsNode.isArray()) {
            return null;
        }
        String lastField = null;
        for (JsonNode column : columnsNode) {
            if (column == null || !column.isObject()) {
                continue;
            }
            String field = textOrNull(column.get("field"));
            if (isBlank(field)) {
                continue;
            }
            if (!isBlank(textOrNull(column.get("format")))) {
                lastField = field;
            }
        }
        return lastField;
    }

    private String findLastColumnFieldWithValueMappingAuthoring(JsonNode currentState) {
        JsonNode columnsNode = currentState != null ? currentState.get("columns") : null;
        if (columnsNode == null || !columnsNode.isArray()) {
            return null;
        }
        String lastField = null;
        for (JsonNode column : columnsNode) {
            if (column == null || !column.isObject()) {
                continue;
            }
            String field = textOrNull(column.get("field"));
            JsonNode valueMapping = column.get("valueMapping");
            if (!isBlank(field) && valueMapping != null && valueMapping.isObject() && !valueMapping.isEmpty()) {
                lastField = field;
            }
        }
        return lastField;
    }

    private String findLastColumnFieldWithRendererAuthoring(JsonNode currentState) {
        JsonNode columnsNode = currentState != null ? currentState.get("columns") : null;
        if (columnsNode == null || !columnsNode.isArray()) {
            return null;
        }
        String lastField = null;
        for (JsonNode column : columnsNode) {
            if (column == null || !column.isObject()) {
                continue;
            }
            String field = textOrNull(column.get("field"));
            JsonNode renderer = column.get("renderer");
            if (!isBlank(field) && renderer != null && renderer.isObject()) {
                lastField = field;
            }
        }
        return lastField;
    }

    private String findLastColumnFieldWithComputedAuthoring(JsonNode currentState) {
        JsonNode columnsNode = currentState != null ? currentState.get("columns") : null;
        if (columnsNode == null || !columnsNode.isArray()) {
            return null;
        }
        String lastField = null;
        for (JsonNode column : columnsNode) {
            if (column == null || !column.isObject()) {
                continue;
            }
            String field = textOrNull(column.get("field"));
            JsonNode computed = column.get("computed");
            if (!isBlank(field) && computed != null && computed.isObject() && !computed.isEmpty()) {
                lastField = field;
            }
        }
        return lastField;
    }

    private String findLastRowConditionalRendererField(JsonNode currentState) {
        JsonNode context = findRowConditionalRendererContext(currentState);
        return fieldFromJsonLogicCondition(context != null ? context.get("condition") : null);
    }

    private JsonNode findRowConditionalRendererContext(JsonNode currentState) {
        JsonNode renderers = currentState != null ? currentState.get("rowConditionalRenderers") : null;
        if (renderers == null || !renderers.isArray() || renderers.isEmpty()) {
            return null;
        }
        return renderers.get(renderers.size() - 1);
    }

    private JsonNode findRowAnimationForCondition(JsonNode currentState, ThresholdCondition threshold) {
        if (threshold == null) {
            return null;
        }
        JsonNode renderers = currentState != null ? currentState.get("rowConditionalRenderers") : null;
        if (renderers == null || !renderers.isArray()) {
            return null;
        }
        for (int i = renderers.size() - 1; i >= 0; i--) {
            JsonNode renderer = renderers.get(i);
            ThresholdCondition candidate = thresholdConditionFromJsonLogic(renderer != null ? renderer.get("condition") : null);
            if (candidate == null) {
                continue;
            }
            if (Objects.equals(candidate.operator, threshold.operator)
                    && Objects.equals(candidate.value, threshold.value)) {
                JsonNode animation = renderer.get("animation");
                return animation != null && animation.isObject() ? animation : null;
            }
        }
        return null;
    }

    private String fieldFromJsonLogicCondition(JsonNode condition) {
        if (condition == null || !condition.isObject()) {
            return null;
        }
        for (String operator : List.of(">", ">=", "<", "<=")) {
            JsonNode args = condition.get(operator);
            if (args == null || !args.isArray() || args.isEmpty()) {
                continue;
            }
            String field = textOrNull(args.get(0) != null ? args.get(0).get("var") : null);
            if (!isBlank(field)) {
                return field;
            }
        }
        return null;
    }

    private boolean hasNonEmptyArray(JsonNode node) {
        return node != null && node.isArray() && !node.isEmpty();
    }

