    private List<AiOption> buildTableDateFormatActionOptions(
            String userPrompt,
            JsonNode currentState,
            List<ContextOption> formatOptions) {
        if (isBlank(userPrompt)) {
            return List.of();
        }
        String normalizedPrompt = normalizeText(userPrompt);
        if (containsSensitiveFieldToken(userPrompt)) {
            ColumnDescriptor targetColumn = findPromptedFormatColumn(currentState, normalizedPrompt);
            String targetField = targetColumn != null ? targetColumn.field : promptedSensitiveFieldFallback(normalizedPrompt);
            String targetLabel = targetColumn != null && !isBlank(targetColumn.header)
                    ? targetColumn.header
                    : targetField;
            return buildMaskOptionPayloads(targetField, targetLabel, buildMaskOptionsForField(targetField));
        }
        if (!canMaterializeTableFormatActions(userPrompt, currentState)) {
            return List.of();
        }
        String targetLabel = findPromptedDateActionTargetLabel(currentState, normalizedPrompt);
        if (isBlank(targetLabel)) {
            targetLabel = "data";
        }
        List<String> targetFields = findPromptedDateActionTargetFields(currentState, normalizedPrompt);
        List<AiOption> options = new ArrayList<>();
        addDateFormatActionOption(
                options,
                formatOptions,
                targetLabel,
                targetFields,
                "dd/MM/yyyy",
                "Usar dd/MM/yyyy",
                "Formato brasileiro compacto para operação diária.",
                "format_list_numbered");
        addDateFormatActionOption(
                options,
                formatOptions,
                targetLabel,
                targetFields,
                "fullDate",
                "Usar data por extenso",
                "Inclui dia da semana e melhora a leitura em telas menos densas.",
                "event_note");
        addDateFormatActionOption(
                options,
                formatOptions,
                targetLabel,
                targetFields,
                "MMM/yyyy",
                "Usar mês/ano",
                "Bom para visão de competência, agrupamento mensal ou análise temporal.",
                "calendar_month");
        return options;
    }

    private ColumnDescriptor findPromptedFormatColumn(JsonNode currentState, String normalizedPrompt) {
        JsonNode columns = currentState != null ? currentState.get("columns") : null;
        if (columns == null || !columns.isArray()) {
            return null;
        }
        for (JsonNode column : columns) {
            if (column == null || !column.isObject()) continue;
            String field = textOrNull(column.get("field"));
            String header = textOrNull(column.get("header"));
            if (isBlank(field) && isBlank(header)) continue;
            String normalizedField = normalizeText(field);
            String normalizedHeader = normalizeText(header);
            if ((!isBlank(normalizedField) && normalizedPrompt.contains(normalizedField))
                    || (!isBlank(normalizedHeader) && normalizedPrompt.contains(normalizedHeader))) {
                return new ColumnDescriptor(field, header);
            }
        }
        return null;
    }

    private String promptedSensitiveFieldFallback(String normalizedPrompt) {
        if (normalizedPrompt != null) {
            if (normalizedPrompt.contains("cnpj")) return "cnpj";
            if (normalizedPrompt.contains("cep")) return "cep";
            if (normalizedPrompt.contains("telefone") || normalizedPrompt.contains("phone") || normalizedPrompt.contains("celular")) {
                return "telefone";
            }
        }
        return "cpf";
    }

    private void addDateFormatActionOption(
            List<AiOption> options,
            List<ContextOption> formatOptions,
            String targetLabel,
            List<String> targetFields,
            String format,
            String label,
            String description,
            String icon) {
        if (!supportsDateFormatOption(formatOptions, format)) {
            return;
        }
        ObjectNode hints = objectMapper.createObjectNode();
        hints.put("targetField", targetLabel);
        ArrayNode targetFieldsNode = hints.putArray("targetFields");
        for (String field : targetFields != null ? targetFields : List.<String>of()) {
            if (!isBlank(field)) {
                targetFieldsNode.add(field);
            }
        }
        ObjectNode selected = hints.putObject("optionSelected");
        if (targetFields != null && targetFields.size() == 1 && !isBlank(targetFields.get(0))) {
            selected.put("targetField", targetFields.get(0));
        } else if (!isBlank(targetLabel)) {
            selected.put("targetField", targetLabel);
        }
        ArrayNode selectedFields = selected.putArray("targetFields");
        for (String field : targetFields != null ? targetFields : List.<String>of()) {
            if (!isBlank(field)) {
                selectedFields.add(field);
            }
        }
        ObjectNode selection = selected.putObject("selection");
        selection.put("value", format);
        selection.put("mode", "format");
        hints.put("format", format);
        ObjectNode presentation = hints.putObject("presentation");
        presentation.put("kind", "guided-option");
        presentation.put("description", description);
        presentation.put("ctaLabel", "Aplicar formato");
        presentation.put("icon", icon);
        presentation.put("tone", "primary");
        ArrayNode items = presentation.putArray("items");
        ObjectNode bestFor = items.addObject();
        bestFor.put("key", "bestFor");
        bestFor.put("label", "Indicado para");
        bestFor.put("value", description);
        ObjectNode next = items.addObject();
        next.put("key", "nextStep");
        next.put("label", "Próximo passo");
        next.put("value", "Clique para aplicar na coluna " + targetLabel + ".");
        options.add(AiOption.builder()
                .value("formate " + dateFormatActionTargetPrompt(targetLabel, targetFields) + " como " + humanDateFormatPrompt(format))
                .label(label)
                .example(format)
                .contextHints(hints)
                .build());
    }

    private String dateFormatActionTargetPrompt(String targetLabel, List<String> targetFields) {
        List<String> fields = targetFields == null
                ? List.of()
                : targetFields.stream().filter(field -> !isBlank(field)).distinct().toList();
        if (!fields.isEmpty()) {
            if (fields.size() == 1) {
                return "a coluna " + fields.get(0);
            }
            return "as colunas " + joinHumanLabels(fields);
        }
        if (isBlank(targetLabel)) {
            return "a coluna de data";
        }
        String normalized = normalizeText(targetLabel);
        if (targetLabel.contains(" e ") || targetLabel.contains(",") || normalized.contains(" e ") || normalized.contains(",")) {
            return "as colunas " + targetLabel;
        }
        return "a coluna " + targetLabel;
    }

    private boolean supportsDateFormatOption(List<ContextOption> formatOptions, String format) {
        if (isBlank(format)) {
            return false;
        }
        if (formatOptions == null || formatOptions.isEmpty()) {
            return Set.of("dd/MM/yyyy", "fullDate", "MMM/yyyy").contains(format);
        }
        return findOptionByValue(formatOptions, format) != null;
    }

    private String findPromptedDateActionTargetLabel(JsonNode currentState, String normalizedPrompt) {
        List<String> labels = collectDateColumnPlainLabels(currentState);
        if (labels.isEmpty()) {
            return findPromptedDateColumnPlainLabel(currentState, normalizedPrompt);
        }
        String explicit = findPromptedDateColumnPlainLabel(currentState, normalizedPrompt);
        if (!isBlank(explicit) && labels.contains(explicit) && !asksForMultipleDateColumns(normalizedPrompt)) {
            return explicit;
        }
        if (labels.size() > 1 && asksForMultipleDateColumns(normalizedPrompt)) {
            return joinHumanLabels(labels);
        }
        return !isBlank(explicit) ? explicit : labels.get(0);
    }

    private List<String> findPromptedDateActionTargetFields(JsonNode currentState, String normalizedPrompt) {
        List<ColumnDescriptor> dateColumns = collectDateColumnDescriptors(currentState);
        if (dateColumns.isEmpty()) {
            return List.of();
        }
        if (dateColumns.size() > 1 && asksForMultipleDateColumns(normalizedPrompt)) {
            return dateColumns.stream()
                    .map(column -> column.field)
                    .filter(field -> !isBlank(field))
                    .distinct()
                    .collect(Collectors.toList());
        }
        for (ColumnDescriptor column : dateColumns) {
            if (matchesPromptedDateColumn(normalizedPrompt, column.field, column.header)) {
                return !isBlank(column.field) ? List.of(column.field) : List.of();
            }
        }
        String firstField = dateColumns.get(0).field;
        return !isBlank(firstField) ? List.of(firstField) : List.of();
    }

    private List<ColumnDescriptor> collectDateColumnDescriptors(JsonNode currentState) {
        JsonNode columns = currentState != null ? currentState.get("columns") : null;
        if (columns == null || !columns.isArray()) {
            return List.of();
        }
        List<ColumnDescriptor> descriptors = new ArrayList<>();
        for (JsonNode column : columns) {
            if (column == null || !column.isObject()) continue;
            String type = textOrNull(column.get("type"));
            String field = textOrNull(column.get("field"));
            String header = textOrNull(column.get("header"));
            boolean isDate = "date".equalsIgnoreCase(type)
                    || normalizeText(field).contains("data")
                    || normalizeText(header).contains("data");
            if (isDate && (!isBlank(field) || !isBlank(header))) {
                descriptors.add(new ColumnDescriptor(field, header));
            }
        }
        return descriptors;
    }

    private List<String> collectDateColumnPlainLabels(JsonNode currentState) {
        JsonNode columns = currentState != null ? currentState.get("columns") : null;
        if (columns == null || !columns.isArray()) {
            return List.of();
        }
        List<String> labels = new ArrayList<>();
        for (JsonNode column : columns) {
            if (column == null || !column.isObject()) continue;
            String type = textOrNull(column.get("type"));
            String field = textOrNull(column.get("field"));
            String header = textOrNull(column.get("header"));
            boolean isDate = "date".equalsIgnoreCase(type)
                    || normalizeText(field).contains("data")
                    || normalizeText(header).contains("data");
            if (!isDate) continue;
            String label = !isBlank(header) ? header : field;
            if (!isBlank(label) && !labels.contains(label)) {
                labels.add(label);
            }
        }
        return labels;
    }

    private boolean asksForMultipleDateColumns(String normalizedPrompt) {
        if (isBlank(normalizedPrompt)) {
            return false;
        }
        return normalizedPrompt.contains("datas")
                || normalizedPrompt.contains("colunas de data")
                || normalizedPrompt.contains("campos de data");
    }

    private String joinHumanLabels(List<String> labels) {
        List<String> clean = labels == null
                ? List.of()
                : labels.stream().filter(label -> !isBlank(label)).distinct().toList();
        if (clean.isEmpty()) {
            return "";
        }
        if (clean.size() == 1) {
            return clean.get(0);
        }
        return String.join(", ", clean.subList(0, clean.size() - 1))
                + " e "
                + clean.get(clean.size() - 1);
    }

    private String humanDateFormatPrompt(String format) {
        return switch (format) {
            case "fullDate" -> "data por extenso";
            case "MMM/yyyy" -> "mes e ano";
            case "dd/MM/yyyy" -> "dd/MM/yyyy";
            default -> format;
        };
    }

    private String findPromptedDateColumnPlainLabel(JsonNode currentState, String normalizedPrompt) {
        JsonNode columns = currentState != null ? currentState.get("columns") : null;
        if (columns == null || !columns.isArray()) {
            return null;
        }
        String firstDateLabel = null;
        for (JsonNode column : columns) {
            if (column == null || !column.isObject()) continue;
            String type = textOrNull(column.get("type"));
            String field = textOrNull(column.get("field"));
            String header = textOrNull(column.get("header"));
            boolean isDate = "date".equalsIgnoreCase(type)
                    || normalizeText(field).contains("data")
                    || normalizeText(header).contains("data");
            if (!isDate) continue;
            String label = !isBlank(header) ? header : field;
            if (firstDateLabel == null && !isBlank(label)) {
                firstDateLabel = label;
            }
            if (matchesPromptedDateColumn(normalizedPrompt, field, header)) {
                return label;
            }
        }
        return firstDateLabel;
    }

    private boolean matchesPromptedDateColumn(String normalizedPrompt, String field, String header) {
        String normalizedField = normalizeText(field);
        String normalizedHeader = normalizeText(header);
        if (!normalizedField.isBlank() && normalizedPrompt.contains(normalizedField)) {
            return true;
        }
        if (!normalizedHeader.isBlank() && normalizedPrompt.contains(normalizedHeader)) {
            return true;
        }
        return normalizedPrompt.contains("admissao")
                && (normalizedField.contains("admissao")
                || normalizedHeader.contains("admissao")
                || normalizedHeader.contains("admisso"));
    }

    private String buildExecutionPrompt(
            String userPrompt,
            AiContextDTO context,
            JsonNode contextConfig,
            List<AiCapability> capabilities,
            String capabilityNotes,
            String relevantConcepts,
            AiSchemaContext schemaContext,
            JsonNode schema,
            String runtimeMetadata,
            JsonNode authoringContract,
            String ragHints,
            String intentPlan,
            String completenessHints) {
        String contextDesc = buildContextDescription(context, schemaContext);
        String caps = truncateBlock("capabilities",
                formatCapabilities(capabilities),
                maxCapabilitiesChars);
        String notes = truncateBlock("capability_notes",
                capabilityNotes != null ? capabilityNotes : "",
                maxCapabilityNotesChars);
        String concepts = truncateBlock("relevant_concepts",
                relevantConcepts != null ? relevantConcepts : "",
                maxConceptsChars);
        String behavior = truncateBlock("component_behavior",
                buildComponentBehaviorBlock(context != null ? context.getComponentDefinition() : null),
                maxCapabilityNotesChars);
        String configJson = truncateBlock("target_config",
                contextConfig != null ? contextConfig.toPrettyString() : "{}",
                maxConfigChars);
        String schemaJson = truncateBlock("schema_json",
                schema != null ? schema.toPrettyString() : "N/A",
                maxSchemaChars);
        String metadataJson = safeMetadata(runtimeMetadata);
        String authoringContractBlock = truncateBlock(
                "authoring_contract",
                formatAuthoringContract(authoringContract),
                maxCapabilityNotesChars);
        String ragBlock = truncateBlock("rag_hints",
                safeMetadata(ragHints),
                maxRagHintsChars);
        boolean hasTargetConfig = contextConfig != null
                && !contextConfig.isNull()
                && !contextConfig.isMissingNode()
                && !(contextConfig.isObject() && contextConfig.size() == 0);
        String templateConfig = truncateBlock("template_config",
                !hasTargetConfig && context.getTemplate() != null && context.getTemplate().getConfigJson() != null
                ? context.getTemplate().getConfigJson().toPrettyString()
                : "N/A",
                maxTemplateConfigChars);
        String templateMeta = truncateBlock("template_meta",
                !hasTargetConfig && context.getTemplate() != null && context.getTemplate().getTemplateMeta() != null
                ? context.getTemplate().getTemplateMeta().toPrettyString()
                : "N/A",
                maxTemplateMetaChars);
        boolean isTable = "praxis-table".equals(context.getComponentId());
        String contractFormatting = isTable ? AiPromptTemplates.CONTRACT_FORMATTING : "";
        String contractRenderers = isTable ? AiPromptTemplates.CONTRACT_RENDERER_PAYLOADS : "";
        String intentPlanBlock = truncateBlock(
                "intent_plan",
                intentPlan != null ? intentPlan : "N/A",
                maxCapabilityNotesChars);
        String completenessBlock = truncateBlock(
                "completeness_hints",
                completenessHints != null ? completenessHints : "N/A",
                maxCapabilityNotesChars);

        return AiPromptTemplates.buildPrompt(
                AiPromptTemplates.PROMPT_EXECUTION_ENRICHED,
                Map.ofEntries(
                        Map.entry("USER_INPUT", safe(userPrompt)),
                        Map.entry("CONTEXT_DESCRIPTION", contextDesc),
                        Map.entry("CAPABILITIES_RESTRICTION", caps),
                        Map.entry("CAPABILITY_NOTES", notes),
                        Map.entry("RELEVANT_CONCEPTS", concepts),
                        Map.entry("COMPONENT_BEHAVIOR", behavior),
                        Map.entry("TARGET_CONFIG", configJson),
                        Map.entry("TEMPLATE_CONFIG", templateConfig),
                        Map.entry("TEMPLATE_META", templateMeta),
                        Map.entry("RAG_HINTS", ragBlock),
                        Map.entry("SCHEMA_JSON", schemaJson),
                        Map.entry("RUNTIME_METADATA", metadataJson),
                        Map.entry("AUTHORING_CONTRACT", authoringContractBlock),
                        Map.entry("INTENT_PLAN", intentPlanBlock),
                        Map.entry("COMPLETENESS_HINTS", completenessBlock),
                        Map.entry("CONTRACT_DSL", AiPromptTemplates.CONTRACT_DSL),
                        Map.entry("CONTRACT_ICONS", AiPromptTemplates.CONTRACT_ICONS),
                        Map.entry("CONTRACT_SAFETY", AiPromptTemplates.CONTRACT_SAFETY),
                        Map.entry("CONTRACT_API_LISTING", AiPromptTemplates.CONTRACT_API_LISTING),
                        Map.entry("CONTRACT_FORMATTING", contractFormatting),
                        Map.entry("CONTRACT_RENDERER_PAYLOADS", contractRenderers),
                        Map.entry("CONTRACT_VISUAL_DESIGN", AiPromptTemplates.CONTRACT_VISUAL_DESIGN)));
    }

    private String buildComponentBehaviorBlock(JsonNode componentDefinition) {
        if (componentDefinition == null || componentDefinition.isNull()) {
            return "N/A";
        }
        JsonNode contextPack = extractComponentContextPack(componentDefinition);
        if (contextPack == null || !contextPack.isObject()) {
            return "N/A";
        }
        JsonNode hints = contextPack.get("hints");
        if (hints == null || !hints.isArray() || hints.isEmpty()) {
            return "N/A";
        }
        StringBuilder out = new StringBuilder("### COMPONENT BEHAVIOR (from component hints):\n");
        for (JsonNode hint : hints) {
            if (hint == null || hint.isNull()) continue;
            String text = textOrNull(hint);
            if (text == null || text.isBlank()) continue;
            out.append("- ").append(text.trim()).append("\n");
        }
        String block = out.toString().trim();
        return block.isEmpty() ? "N/A" : block;
    }

    private IntentPlan generateIntentPlan(
            AiOrchestratorRequest request,
            String userPrompt,
            AiContextDTO context,
            List<AiCapability> capabilities,
            JsonNode currentState,
            JsonNode componentContext,
            AiCallConfig callConfig,
            String category) {
        JsonNode definition = context != null ? context.getComponentDefinition() : null;
        String runtimeMetadata = truncateBlock(
                "intent_plan_runtime_metadata",
                safeMetadata(formatRuntimeMetadata(
                        request != null ? request.getDataProfile() : null,
                        request != null ? request.getSchemaFields() : null,
                        request != null ? request.getRuntimeState() : null,
                        request != null ? request.getContextHints() : null)),
                maxRuntimeMetadataChars);
        String prompt = buildIntentPlanPrompt(
                context != null ? context.getComponentId() : null,
                request != null ? request.getComponentType() : null,
                userPrompt,
                capabilities,
                currentState,
                componentContext,
                definition,
                category,
                runtimeMetadata);
        AiJsonSchema schema = buildIntentPlanSchema();
        JsonNode json = generateIntentPlanJson(prompt, schema, request, callConfig);
        if (json == null) {
            return null;
        }
        return objectMapper.convertValue(json, IntentPlan.class);
    }

    private JsonNode generateIntentPlanJson(
            String prompt,
            AiJsonSchema schema,
            AiOrchestratorRequest request,
            AiCallConfig callConfig) {
        AiCallConfig baseConfig = buildActionPlanConfig(callConfig);
        JsonNode json = callAiJson("intent_plan", prompt, schema, baseConfig != null ? baseConfig : callConfig, request, 1);
        if (json != null) {
            return json;
        }
        AiCallConfig retryConfig = buildActionPlanRetryConfig(baseConfig);
        if (retryConfig == null) {
            return null;
        }
        return callAiJson("intent_plan", prompt, schema, retryConfig, request, 2);
    }

    private String buildIntentPlanPrompt(
            String componentId,
            String componentType,
            String userPrompt,
            List<AiCapability> capabilities,
            JsonNode currentState,
            JsonNode componentContext,
            JsonNode componentDefinition,
            String category,
            String runtimeMetadata) {
        String categoryOverride = category;
        if ("praxis-dynamic-page".equals(componentId) && "page".equalsIgnoreCase(category)) {
            categoryOverride = null;
        }
        List<AiCapability> reducedCaps = reduceCapabilitiesForIntentPlan(capabilities, categoryOverride);
        String caps = truncateBlock(
                "capabilities",
                formatCapabilities(reducedCaps),
                maxCapabilitiesChars);
        String stateSummary = truncateBlock(
                "current_state_summary",
                buildCurrentStateSummary(currentState),
                maxRuntimeMetadataChars);
        
        String concepts = buildConceptsBlock(componentDefinition);
        String options = buildOptionsByPathSummary(componentContext, categoryOverride);
        
        String optionsSummary = truncateBlock(
                "options_by_path_and_concepts",
                options + concepts,
                maxCapabilityNotesChars);
        return AiPromptTemplates.buildPrompt(
                AiPromptTemplates.PROMPT_INTENT_PLAN,
                Map.of(
                        "COMPONENT_TYPE", safe(componentType),
                        "USER_INPUT", safe(userPrompt),
                        "CAPABILITIES_RESTRICTION", caps,
                        "CURRENT_STATE_SUMMARY", stateSummary,
                        "RUNTIME_METADATA", runtimeMetadata != null ? runtimeMetadata : "N/A",
                        "OPTIONS_BY_PATH", optionsSummary));
    }

    private String buildCurrentStateSummary(JsonNode currentState) {
        ObjectNode summary = objectMapper.createObjectNode();
        ArrayNode keys = buildCurrentStateKeys(currentState);
        if (keys != null && keys.size() > 0) {
            summary.set("keys", keys);
        }
        List<String> columns = extractColumnNames(currentState);
        if (!columns.isEmpty()) {
            summary.set("columns", objectMapper.valueToTree(columns));
        }
        List<String> inputs = extractObjectKeys(currentState, "inputs");
        if (!inputs.isEmpty()) {
            summary.set("inputs", objectMapper.valueToTree(inputs));
        }
        List<String> outputs = extractObjectKeys(currentState, "outputs");
        if (!outputs.isEmpty()) {
            summary.set("outputs", objectMapper.valueToTree(outputs));
        }
        return summary.size() > 0 ? summary.toPrettyString() : "{}";
    }

    private String buildConceptsBlock(JsonNode componentDefinition) {
        if (componentDefinition == null) return "";
        JsonNode conceptsNode = componentDefinition.get("aiConcepts");
        if (conceptsNode == null || conceptsNode.isEmpty()) return "";

        StringBuilder sb = new StringBuilder("\n### REGRAS E CONCEITOS IMPORTANTES (Leia com atenção):\n");
        conceptsNode.fields().forEachRemaining(entry -> {
            JsonNode concept = entry.getValue();
            sb.append("- ").append(textOrNull(concept.get("title"))).append(" (").append(entry.getKey()).append(")\n");
            sb.append("  Desc: ").append(textOrNull(concept.get("description"))).append("\n");
            
            JsonNode rules = concept.get("rules");
            if (rules != null && rules.isArray()) {
                rules.forEach(r -> sb.append("  * RULE: ").append(r.asText()).append("\n"));
            }
            
            JsonNode syntax = concept.get("syntax");
            if (syntax != null && !syntax.isNull()) {
                sb.append("  * SYNTAX: ").append(syntax.asText()).append("\n");
            }

            JsonNode anti = concept.get("antiPatterns");
            if (anti != null && anti.isArray()) {
                anti.forEach(a -> sb.append("  * AVOID (Anti-Pattern): ").append(a.asText()).append("\n"));
            }
            sb.append("\n");
        });
        return sb.toString();
    }

    private String buildOptionsByPathSummary(JsonNode componentContext, String category) {
        if (componentContext == null || !componentContext.isObject()) {
            return "N/A";
        }
        JsonNode optionsByPath = componentContext.get("optionsByPath");
        if (optionsByPath == null || !optionsByPath.isObject()) {
            return "N/A";
        }
        ArrayNode keys = objectMapper.createArrayNode();
        List<String> prefixes = resolveIntentPlanPrefixes(category);
        optionsByPath.fieldNames().forEachRemaining(key -> {
            if (prefixes.isEmpty() || matchesPrefix(key, prefixes)) {
                keys.add(key);
            }
        });
        return keys.size() > 0 ? keys.toPrettyString() : "N/A";
    }

    private List<AiCapability> reduceCapabilitiesForIntentPlan(
            List<AiCapability> capabilities,
            String category) {
        if (capabilities == null || capabilities.isEmpty()) {
            return List.of();
        }
        List<String> prefixes = resolveIntentPlanPrefixes(category);
        List<AiCapability> filtered = new ArrayList<>();
        if (prefixes.isEmpty()) {
            filtered.addAll(capabilities);
        } else {
            for (AiCapability cap : capabilities) {
                if (cap == null || cap.getPath() == null) continue;
                if (matchesPrefix(cap.getPath(), prefixes)) {
                    filtered.add(cap);
                }
            }
        }
        int limit = 40;
        if (filtered.size() > limit) {
            return new ArrayList<>(filtered.subList(0, limit));
        }
        return filtered;
    }

    private List<String> resolveIntentPlanPrefixes(String category) {
        if (category == null || category.isBlank()) {
            return List.of();
        }
        String normalized = category.trim().toLowerCase(Locale.ROOT);
        List<String> prefixes = new ArrayList<>();
        prefixes.add("columns[].field");
        prefixes.add("columns[].header");
        switch (normalized) {
            case "renderer" -> {
                prefixes.add("columns[].renderer");
                prefixes.add("columns[].conditionalRenderers[].renderer");
            }
            case "conditional" -> {
                prefixes.add("columns[].conditionalRenderers");
                prefixes.add("columns[].conditionalStyles");
                prefixes.add("rowConditionalStyles");
            }
            case "format" -> {
                prefixes.add("columns[].format");
                prefixes.add("columns[].type");
                prefixes.add("columns[].computed.format");
                prefixes.add("columns[].computed.outputType");
            }
            case "columns" -> prefixes.add("columns[]");
            case "selection" -> prefixes.add("behavior.selection");
            case "sorting" -> {
                prefixes.add("behavior.sorting");
                prefixes.add("columns[].sortable");
            }
            case "filtering" -> {
                prefixes.add("behavior.filtering");
                prefixes.add("columns[].filterable");
            }
            case "pagination" -> prefixes.add("behavior.pagination");
            case "toolbar" -> prefixes.add("toolbar");
            case "appearance" -> prefixes.add("appearance");
            case "actions" -> prefixes.add("actions");
            case "export" -> prefixes.add("export");
            case "messages" -> prefixes.add("messages");
            case "localization" -> prefixes.add("localization");
            case "behavior" -> prefixes.add("behavior");
            case "performance" -> prefixes.add("performance");
            case "interaction" -> prefixes.add("interaction");
            case "data" -> prefixes.add("data");
            case "accessibility" -> prefixes.add("accessibility");
            case "mapping" -> prefixes.add("mapping");
            case "meta" -> prefixes.add("meta");
            default -> {
                // keep only core column identifiers by default
            }
        }
        return prefixes;
    }

    private boolean matchesPrefix(String path, List<String> prefixes) {
        if (path == null || prefixes == null || prefixes.isEmpty()) {
            return false;
        }
        for (String prefix : prefixes) {
            if (prefix == null || prefix.isBlank()) continue;
            if (path.startsWith(prefix)) {
                return true;
            }
        }
        return false;
    }

    private String formatIntentPlan(IntentPlan plan) {
        if (plan == null) {
            return "N/A";
        }
        return objectMapper.valueToTree(plan).toPrettyString();
    }

    private IntentPlan applyDeterministicIntentChecks(
            IntentPlan plan,
            AiActionPlan actionPlan,
            List<ComponentAction> actionCatalog,
            JsonNode currentState,
            boolean isTable,
            List<ColumnDescriptor> columnDescriptors,
            List<String> columnResolverKeys) {
        if (plan == null || actionPlan == null || actionPlan.getActions() == null || actionPlan.getActions().isEmpty()) {
            return plan;
        }
        if (actionCatalog == null || actionCatalog.isEmpty()) {
            return plan;
        }
        AiActionPlan resolvedPlan = isTable
                ? resolveTableActionPlanTargets(actionPlan, columnDescriptors, columnResolverKeys)
                : actionPlan;
        Map<String, ComponentAction> actionById = indexActionCatalog(actionCatalog);
        List<IntentAction> derivedActions = new ArrayList<>();
        int expectedActions = 0;
        for (AiActionPlan.Action action : resolvedPlan.getActions()) {
            if (action == null || action.getType() == null || action.getType().isBlank()) {
                continue;
            }
            expectedActions++;
            ComponentAction def = actionById.get(normalizeActionKey(action.getType()));
            RenderedActionPatch rendered = renderActionPatch(def, action);
            if (rendered == null || rendered.patch == null || !rendered.missingTokens.isEmpty()) {
                IntentAction fallback = buildCreateColumnFallbackChecks(action);
                if (fallback != null) {
                    derivedActions.add(fallback);
                }
                continue;
            }
            List<AiPatchDiff> diffs = buildPatchDiff(currentState, rendered.patch);
            if (diffs == null || diffs.isEmpty()) {
                continue;
            }
            List<ActionCheck> checks = new ArrayList<>();
            for (AiPatchDiff diff : diffs) {
                if (diff == null || diff.getPath() == null || diff.getPath().isBlank()) {
                    continue;
                }
                JsonNode after = diff.getAfter();
                if (after != null && after.isArray() && isConditionalRenderersPath(diff.getPath())) {
                    for (JsonNode item : after) {
                        checks.add(ActionCheck.builder()
                                .type("contains")
                                .path(diff.getPath())
                                .value(item)
                                .build());
                    }
                } else {
                    checks.add(ActionCheck.builder()
                            .type("pathEquals")
                            .path(diff.getPath())
                            .value(after)
                            .build());
                }
            }
            if (!checks.isEmpty()) {
                derivedActions.add(IntentAction.builder()
                        .id(formatActionCheckId(action))
                        .checks(checks)
                        .build());
            }
        }
        if (expectedActions > 0 && derivedActions.size() == expectedActions) {
            plan.setActions(derivedActions);
        }
        return plan;
    }

    private IntentAction buildCreateColumnFallbackChecks(AiActionPlan.Action action) {
        if (action == null || action.getType() == null) {
            return null;
        }
        String type = normalizeActionKey(action.getType());
        if (!"add_column".equals(type) && !"add_column_computed".equals(type)) {
            return null;
        }
        String field = null;
        JsonNode params = action.getParams();
        if (params != null && params.isObject()) {
            String paramField = textOrNull(params.get("field"));
            if (!isBlank(paramField)) {
                field = paramField;
            }
        }
        if (isBlank(field)) {
            field = action.getTarget();
        }
        if (isBlank(field)) {
            return null;
        }
        List<ActionCheck> checks = new ArrayList<>();
        checks.add(ActionCheck.builder()
                .type("pathChanged")
                .path("columns[field=" + field + "]")
                .build());
        if (params != null && params.isObject()) {
            String expression = textOrNull(params.get("expression"));
            if (!isBlank(expression)) {
                checks.add(ActionCheck.builder()
                        .type("pathEquals")
                        .path("columns[field=" + field + "].computed.expression")
                        .value(objectMapper.convertValue(expression, JsonNode.class))
                        .build());
            }
        }
        return IntentAction.builder()
                .id(formatActionCheckId(action))
                .checks(checks)
                .build();
    }

    private String formatActionCheckId(AiActionPlan.Action action) {
        if (action == null) {
            return "action";
        }
        String type = action.getType();
        if (type == null || type.isBlank()) {
            return "action";
        }
        String target = action.getTarget();
        if (target == null || target.isBlank()) {
            return type;
        }
        return type + "[" + target + "]";
    }

    private String buildCompletenessHints(
            IntentPlan plan,
            List<AiPatchDiff> diff,
            List<IntentAction> missingActions) {
        String missing = missingActions != null
                ? objectMapper.valueToTree(missingActions).toPrettyString()
                : "[]";
        String diffJson = diff != null
                ? objectMapper.valueToTree(diff).toPrettyString()
                : "[]";
        String planJson = plan != null
                ? objectMapper.valueToTree(plan).toPrettyString()
                : "N/A";
        return "INTENT_PLAN:\n" + planJson
                + "\nMISSING_ACTIONS:\n" + missing
                + "\nCURRENT_DIFF:\n" + diffJson
                + "\nREGRAS: nao mude o que ja esta correto; apenas complete o que falta.";
    }

    private CompletenessResult evaluateCompleteness(
            IntentPlan plan,
            List<AiPatchDiff> diffs,
            JsonNode currentState,
            JsonNode componentContext,
            List<AiCapability> capabilities,
            boolean allowUnknownColumns) {
        if (plan == null || plan.getActions() == null || plan.getActions().isEmpty()) {
            return CompletenessResult.complete();
        }
        List<String> planQuestions = plan.getQuestions();
        if (planQuestions != null && !planQuestions.isEmpty()) {
            return CompletenessResult.incomplete(List.of(), planQuestions);
        }
        List<IntentAction> missingActions = new ArrayList<>();
        for (IntentAction action : plan.getActions()) {
            if (!isActionComplete(action, diffs)) {
                missingActions.add(action);
            }
        }
        if (missingActions.isEmpty()) {
            return CompletenessResult.complete();
        }
        List<String> questions = buildMissingActionQuestions(
                missingActions,
                currentState,
                componentContext,
                capabilities,
                allowUnknownColumns);
        return CompletenessResult.incomplete(missingActions, questions);
    }

    private boolean isActionComplete(IntentAction action, List<AiPatchDiff> diffs) {
        if (action == null || action.getChecks() == null || action.getChecks().isEmpty()) {
            return false;
        }
        for (ActionCheck check : action.getChecks()) {
            if (!isCheckSatisfied(check, diffs)) {
                return false;
            }
        }
        return true;
    }

    private boolean isCheckSatisfied(ActionCheck check, List<AiPatchDiff> diffs) {
        if (check == null || diffs == null || diffs.isEmpty()) {
            return false;
        }
        String type = check.getType() != null ? check.getType().trim() : "";
        String checkPath = normalizePath(check.getPath());
        JsonNode expected = check.getValue();
        for (AiPatchDiff diff : diffs) {
            if (diff == null) continue;
            String diffPath = normalizePath(diff.getPath());
            if ("pathchanged".equalsIgnoreCase(type)) {
                if (diffPath.equals(checkPath) || diffPath.startsWith(checkPath + ".")) {
                    return true;
                }
                if (checkPath.isBlank() && !diffPath.isBlank()) {
                    return true;
                }
            } else if ("pathequals".equalsIgnoreCase(type)) {
                if (diffPath.equals(checkPath) && expected != null && diff.getAfter() != null) {
                    JsonNode actual = diff.getAfter();
                    JsonNode exp = expected;
                    if (isConditionalRenderersPath(checkPath)) {
                        actual = stripConditionalRendererDescription(actual);
                        exp = stripConditionalRendererDescription(exp);
                    }
                    if (actual != null && exp != null && actual.equals(exp)) {
                        return true;
                    }
                }
            } else if ("contains".equalsIgnoreCase(type)) {
                if (diffPath.equals(checkPath)) {
                    JsonNode actual = diff.getAfter();
                    JsonNode exp = expected;
                    if (isConditionalRenderersPath(checkPath)) {
                        actual = stripConditionalRendererDescription(actual);
                        exp = stripConditionalRendererDescription(exp);
                    }
                    if (containsValue(actual, exp)) {
                        return true;
                    }
                }
            }
        }
        return false;
    }

    private boolean containsValue(JsonNode actual, JsonNode expected) {
        if (actual == null || actual.isNull() || expected == null || expected.isNull()) {
            return false;
        }
        if (actual.isArray()) {
            for (JsonNode item : actual) {
                if (item != null && item.equals(expected)) {
                    return true;
                }
                if (patchContainsExpected(item, expected)) {
                    return true;
                }
            }
            return false;
        }
        return patchContainsExpected(actual, expected);
    }

    private boolean isConditionalRenderersPath(String path) {
        if (path == null || path.isBlank()) {
            return false;
        }
        return path.endsWith("conditionalRenderers");
    }

    private JsonNode stripConditionalRendererDescription(JsonNode node) {
        if (node == null || node.isNull()) {
            return node;
        }
        if (node.isObject()) {
            ObjectNode copy = ((ObjectNode) node).deepCopy();
            copy.remove("description");
            return copy;
        }
        if (!node.isArray()) {
            return node;
        }
        ArrayNode copy = ((ArrayNode) node).deepCopy();
        for (JsonNode item : copy) {
            if (item != null && item.isObject()) {
                ((ObjectNode) item).remove("description");
            }
        }
        return copy;
    }

    private String normalizePath(String path) {
        if (path == null) {
            return "";
        }
        String trimmed = path.trim();
        if ("$".equals(trimmed)) {
            return "";
        }
        if (trimmed.startsWith("$.")) {
            return trimmed.substring(2);
        }
        if (trimmed.startsWith("$")) {
            return trimmed.substring(1);
        }
        return trimmed;
    }

    private String normalizeOptionsPath(String path) {
        String normalized = normalizePath(path);
        return normalized.replaceAll("\\[[^\\]]+\\]", "[]");
    }

    private List<String> buildMissingActionQuestions(
            List<IntentAction> actions,
            JsonNode currentState,
            JsonNode componentContext,
            List<AiCapability> capabilities,
            boolean allowUnknownColumns) {
        if (actions == null || actions.isEmpty()) {
            return List.of();
        }
        java.util.LinkedHashSet<String> questions = new java.util.LinkedHashSet<>();
        List<String> columns = extractColumnNames(currentState);
        for (IntentAction action : actions) {
            if (action == null) continue;
            String actionId = action.getId() != null ? action.getId() : "acao solicitada";
            List<ActionCheck> checks = action.getChecks();
            if (checks == null || checks.isEmpty()) {
                questions.add("Preciso de mais detalhes para completar \"" + actionId + "\".");
                continue;
            }
            for (ActionCheck check : checks) {
                if (check == null) continue;
                String path = normalizePath(check.getPath());
                if (path.startsWith("columns[") && !columns.isEmpty()) {
                    ColumnIdentity identity = parseColumnIdentity(path);
                    if (identity != null && identity.value != null
                            && !hasColumnIdentity(currentState, identity.key, identity.value)) {
                        if (allowUnknownColumns) {
                            continue;
                        }
                        String available = String.join(", ", columns);
                        questions.add("Qual coluna devo usar? Colunas disponiveis: " + available + ".");
                        continue;
                    }
                }
                if ("pathequals".equalsIgnoreCase(check.getType())
                        || "contains".equalsIgnoreCase(check.getType())) {
                    String optionPath = normalizeOptionsPath(check.getPath());
                    List<ContextOption> options = resolveOptionsForPath(
                            componentContext,
                            capabilities,
                            optionPath);
                    if (!options.isEmpty()) {
                        List<String> labels = buildOptionLabels(options);
                        if (!labels.isEmpty()) {
                            questions.add("Qual valor devo usar em \"" + optionPath
                                    + "\"? Opcoes: " + String.join(", ", labels) + ".");
                            continue;
                        }
                    }
                }
                questions.add("Preciso de mais detalhes para completar \"" + actionId + "\".");
            }
        }
        return new ArrayList<>(questions);
    }

    private ColumnIdentity parseColumnIdentity(String path) {
        if (path == null) return null;
        java.util.regex.Matcher matcher =
                java.util.regex.Pattern.compile("columns\\[([^=]+)=([^\\]]+)\\]").matcher(path);
        if (!matcher.find()) {
            return null;
        }
        String key = matcher.group(1);
        String value = matcher.group(2);
        if (key == null || value == null) {
            return null;
        }
        return new ColumnIdentity(key.trim(), value.trim());
    }

    private boolean hasColumnIdentity(JsonNode currentState, String key, String value) {
        if (currentState == null || !currentState.has("columns")) {
            return false;
        }
        JsonNode columns = currentState.get("columns");
        if (columns == null || !columns.isArray()) {
            return false;
        }
        for (JsonNode column : columns) {
            if (column == null || !column.isObject()) continue;
            String found = textOrNull(column.get(key));
            if (value.equals(found)) {
                return true;
            }
        }
        return false;
    }

    private String buildQuestionsMessage(List<String> questions) {
        if (questions == null || questions.isEmpty()) {
            return "Preciso de mais detalhes para continuar.";
        }
        StringBuilder message = new StringBuilder("Preciso de alguns detalhes para continuar:");
        for (String question : questions) {
            if (question == null || question.isBlank()) continue;
            message.append("\n- ").append(question.trim());
        }
        return message.toString();
    }

    private String formatRuntimeMetadata(
            JsonNode dataProfile,
            JsonNode schemaFields,
            JsonNode runtimeState,
            JsonNode contextHints) {
        ObjectNode metadata = objectMapper.createObjectNode();
        JsonNode selectedRecordsContext = resolveSelectedRecordsContext(runtimeState, contextHints);
        if (selectedRecordsContext != null) {
            metadata.set("selectedRecordsContext", selectedRecordsContext);
        }
        JsonNode filterFieldCatalog = resolveFilterFieldCatalogContext(contextHints);
        if (filterFieldCatalog != null) {
            metadata.set("filterFieldCatalog", filterFieldCatalog);
        }
        if (runtimeState != null && !runtimeState.isNull()) {
            metadata.set("runtimeState", runtimeState);
        }
        if (contextHints != null && !contextHints.isNull()) {
            metadata.set("contextHints", contextHints);
        }
        if (schemaFields != null && !schemaFields.isNull()) {
            metadata.set("schemaFields", schemaFields);
        }
        if (dataProfile != null && !dataProfile.isNull()) {
            metadata.set("dataProfile", dataProfile);
        }
        if (metadata.size() == 0) {
            return "N/A";
        }
        return metadata.toPrettyString();
    }

    private JsonNode resolveSelectedRecordsContext(JsonNode runtimeState, JsonNode contextHints) {
        return bestSelectedRecordsContext(
                pathOrMissing(runtimeState, "/selection"),
                pathOrMissing(runtimeState, "/selectedRecordsContext"),
                pathOrMissing(contextHints, "/selectedRecordsContext"),
                pathOrMissing(contextHints, "/authoringContract/consultativeContext/selectedRecordsContext"));
    }

    private JsonNode resolveSelectedRecordsContextWithFilterCandidates(JsonNode runtimeState, JsonNode contextHints) {
        return bestSelectedRecordsContext(
                pathOrMissing(contextHints, "/authoringContract/consultativeContext/selectedRecordsContext"),
                pathOrMissing(contextHints, "/selectedRecordsContext"),
                pathOrMissing(runtimeState, "/selectedRecordsContext"),
                pathOrMissing(runtimeState, "/selection"));
    }

    private boolean isUsefulSelectedRecordsContext(JsonNode node) {
        if (node == null || !node.isObject()) {
            return false;
        }
        return node.path("selectedCount").asInt(0) > 0
                || node.path("sampleRows").isArray()
                || node.path("selectedIds").isArray()
                || node.path("filterCandidates").isArray();
    }

    private JsonNode bestSelectedRecordsContext(JsonNode... candidates) {
        JsonNode best = null;
        int bestScore = -1;
        if (candidates == null) {
            return null;
        }
        for (JsonNode candidate : candidates) {
            if (!isUsefulSelectedRecordsContext(candidate)) {
                continue;
            }
            int score = selectedRecordsContextScore(candidate);
            if (score > bestScore) {
                best = candidate;
                bestScore = score;
            }
        }
        return best;
    }

    private int selectedRecordsContextScore(JsonNode node) {
        if (node == null || !node.isObject()) {
            return 0;
        }
        int score = Math.max(0, node.path("selectedCount").asInt(0));
        JsonNode selectedIds = node.get("selectedIds");
        if (selectedIds != null && selectedIds.isArray()) {
            score += selectedIds.size();
        }
        JsonNode sampleRows = node.get("sampleRows");
        if (sampleRows != null && sampleRows.isArray()) {
            score += sampleRows.size() * 10;
            for (JsonNode row : sampleRows) {
                if (row != null && row.isObject()) {
                    score += row.size();
                }
            }
        }
        JsonNode filterCandidates = node.get("filterCandidates");
        if (filterCandidates != null && filterCandidates.isArray()) {
            score += 1000 + filterCandidates.size() * 20;
        }
        return score;
    }

    private JsonNode resolveFilterFieldCatalogContext(JsonNode contextHints) {
        return firstObjectNode(
                pathOrMissing(contextHints, "/authoringContract/componentEditPlan/filterFieldCatalog"),
                pathOrMissing(contextHints, "/authoringContract/filterFieldCatalog"),
                pathOrMissing(contextHints, "/filterFieldCatalog"));
    }

    private JsonNode firstObjectNode(JsonNode... candidates) {
        if (candidates == null) {
            return null;
        }
        for (JsonNode candidate : candidates) {
            if (candidate != null && candidate.isObject()) {
                return candidate;
            }
        }
        return null;
    }

    private String formatContextHints(JsonNode contextHints) {
        if (contextHints == null || contextHints.isNull()) {
            return "N/A";
        }
        if (contextHints.isTextual()) {
            String text = contextHints.asText();
            return text == null || text.isBlank() ? "N/A" : text;
        }
        return contextHints.toPrettyString();
    }

    private JsonNode extractAuthoringContract(JsonNode contextHints) {
        if (contextHints == null || !contextHints.isObject()) {
            return null;
        }
        JsonNode authoringContract = contextHints.get("authoringContract");
        return authoringContract != null && authoringContract.isObject() ? authoringContract : null;
    }

    private JsonNode resolveAuthoringContract(
            JsonNode contextHints,
            AiContextDTO context,
            JsonNode authoringManifest) {
        if (authoringManifest != null && authoringManifest.isObject()) {
            return mergeRuntimeAuthoringContractHints(
                    buildAuthoringContractFromManifest(context, authoringManifest),
                    extractAuthoringContract(contextHints));
        }
        return extractAuthoringContract(contextHints);
    }

    private JsonNode mergeRuntimeAuthoringContractHints(JsonNode canonicalContract, JsonNode runtimeContract) {
        if (canonicalContract == null || !canonicalContract.isObject()
                || runtimeContract == null || !runtimeContract.isObject()) {
            return canonicalContract;
        }
        ObjectNode merged = ((ObjectNode) canonicalContract).deepCopy();
        copyNodeField(runtimeContract, merged, "responseModes");
        copyNodeField(runtimeContract, merged, "consultativeContext");
        copyNodeField(runtimeContract, merged, "activeResponseMode");
        copyNodeField(runtimeContract, merged, "selectedResponseMode");
        copyNodeField(runtimeContract, merged, "responseMode");
        copyNodeField(runtimeContract, merged, "componentEditPlan");
        copyNodeField(runtimeContract, merged, "runtimeOperations");
        return merged;
    }

    private JsonNode extractAuthoringManifest(JsonNode componentDefinition) {
        if (componentDefinition == null || componentDefinition.isNull() || componentDefinition.isMissingNode()) {
            return null;
        }
        JsonNode manifest = componentDefinition.at("/jsonSchema/authoringManifest");
        if (manifest != null && manifest.isObject() && !manifest.isMissingNode()) {
            return manifest;
        }
        manifest = componentDefinition.at("/componentDefinition/jsonSchema/authoringManifest");
        if (manifest != null && manifest.isObject() && !manifest.isMissingNode()) {
            return manifest;
        }
        manifest = componentDefinition.get("authoringManifest");
        return manifest != null && manifest.isObject() ? manifest : null;
    }

    private JsonNode normalizeAuthoringManifest(String componentId, JsonNode manifest) {
        if (!COMPONENT_ID_TABLE.equals(componentId)
                || manifest == null
                || !manifest.isObject()) {
            return manifest;
        }
        if (findManifestOperation(manifest, "row.conditionalRenderer.add") != null) {
            return manifest;
        }
        ObjectNode normalized = ((ObjectNode) manifest).deepCopy();
        JsonNode operationsNode = normalized.get("operations");
        if (!(operationsNode instanceof ArrayNode operations)) {
            return normalized;
        }
        ObjectNode operation = objectMapper.createObjectNode();
        operation.put("operationId", "row.conditionalRenderer.add");
        operation.put("title", "Adicionar renderizador condicional de linha");
        operation.put("scope", "global");
        operation.put("targetKind", "conditionalRenderer");
        ObjectNode target = operation.putObject("target");
        target.put("kind", "conditionalRenderer");
        target.put("resolver", "conditional-renderer-in-row");
        target.put("ambiguityPolicy", "fail");
        target.put("required", false);
        ObjectNode inputSchema = operation.putObject("inputSchema");
        inputSchema.put("type", "object");
        ArrayNode required = inputSchema.putArray("required");
        required.add("id");
        required.add("condition");
        ObjectNode properties = inputSchema.putObject("properties");
        properties.putObject("id").put("type", "string");
        properties.putObject("condition").put("type", "object");
        properties.putObject("tooltip").put("type", "object");
        properties.putObject("animation").put("type", "object");
        properties.putObject("effects").put("type", "array");
        properties.putObject("enabled").put("type", "boolean");
        properties.putObject("description").put("type", "string");
        ArrayNode anyOf = inputSchema.putArray("anyOf");
        anyOf.addObject().putArray("required").add("tooltip");
        anyOf.addObject().putArray("required").add("animation");
        anyOf.addObject().putArray("required").add("effects");
        ObjectNode effect = operation.putArray("effects").addObject();
        effect.put("kind", "append-unique");
        effect.put("path", "rowConditionalRenderers[]");
        effect.put("key", "id");
        operation.putArray("validators").add("computed-expression-valid");
        ArrayNode affectedPaths = operation.putArray("affectedPaths");
        affectedPaths.add("rowConditionalRenderers[]");
        affectedPaths.add("rowConditionalRenderers[].condition");
        affectedPaths.add("rowConditionalRenderers[].tooltip");
        affectedPaths.add("rowConditionalRenderers[].animation");
        affectedPaths.add("rowConditionalRenderers[].effects");
        operation.put("submissionImpact", "visual-only");
        operation.putArray("preconditions").add("config-initialized");
        operations.add(operation);
        return normalized;
    }

    private JsonNode augmentAuthoringManifestFromRuntimeContract(
            String componentId,
            JsonNode authoringManifest,
            JsonNode authoringContract) {
        if (!COMPONENT_ID_TABLE.equals(componentId)) {
            return authoringManifest;
        }
        ObjectNode manifest = authoringManifest != null && authoringManifest.isObject()
                ? ((ObjectNode) authoringManifest).deepCopy()
                : objectMapper.createObjectNode();
        if (!manifest.hasNonNull("componentId")) {
            manifest.put("componentId", componentId);
        }
        ArrayNode operations = manifest.get("operations") instanceof ArrayNode existingOperations
                ? existingOperations
                : manifest.putArray("operations");
        Set<String> existingOperationIds = new LinkedHashSet<>();
        for (JsonNode operation : operations) {
            String operationId = textOrNull(operation.get("operationId"));
            if (!isBlank(operationId)) {
                existingOperationIds.add(operationId);
            }
        }
        Set<String> operationIdsToMaterialize = tableRuntimeOperationIds(authoringContract);
        operationIdsToMaterialize.addAll(tableComponentEditPlanOperationIds(authoringContract));
        operationIdsToMaterialize.addAll(tableExampleOperationIds(manifest));
        if (operationIdsToMaterialize.isEmpty()) {
            return authoringManifest;
        }
        for (String operationId : operationIdsToMaterialize) {
            if (isBlank(operationId) || existingOperationIds.contains(operationId)) {
                continue;
            }
            ObjectNode operation = tableManifestOperationFromRuntimeContract(operationId);
            if (operation != null) {
                appendManifestEditableTarget(manifest, operation);
                operations.add(operation);
                existingOperationIds.add(operationId);
            }
        }
        return manifest;
    }

    private Set<String> tableComponentEditPlanOperationIds(JsonNode authoringContract) {
        Set<String> operationIds = new LinkedHashSet<>();
        if (authoringContract == null || !authoringContract.isObject()) {
            return operationIds;
        }
        JsonNode allowedOperationIds = authoringContract.at("/componentEditPlan/allowedOperationIds");
        if (allowedOperationIds != null && allowedOperationIds.isArray()) {
            for (JsonNode allowedOperationIdNode : allowedOperationIds) {
                String operationId = canonicalTableRuntimeOperationId(textOrNull(allowedOperationIdNode));
                if (!isBlank(operationId)) {
                    operationIds.add(operationId);
                }
            }
        }
        return operationIds;
    }

    private Set<String> tableRuntimeOperationIds(JsonNode authoringContract) {
        Set<String> operationIds = new LinkedHashSet<>();
        if (authoringContract == null || !authoringContract.isObject()) {
            return operationIds;
        }
        JsonNode allowedOperationIds = authoringContract.at("/runtimeOperations/allowedOperationIds");
        if (allowedOperationIds != null && allowedOperationIds.isArray()) {
            for (JsonNode allowedOperationIdNode : allowedOperationIds) {
                String operationId = textOrNull(allowedOperationIdNode);
                if (!isBlank(operationId)) {
                    operationIds.add(operationId);
                }
            }
        }
        return operationIds;
    }

    private Set<String> tableExampleOperationIds(JsonNode manifest) {
        Set<String> operationIds = new LinkedHashSet<>();
        if (manifest == null || !manifest.isObject()) {
            return operationIds;
        }
        JsonNode examples = manifest.get("examples");
        if (examples != null && examples.isArray()) {
            for (JsonNode example : examples) {
                String operationId = textOrNull(example.get("operationId"));
                if (!isBlank(operationId)) {
                    operationIds.add(operationId);
                }
            }
        }
        return operationIds;
    }

    private void appendManifestEditableTarget(ObjectNode manifest, JsonNode operation) {
        if (manifest == null || operation == null || !operation.isObject()) {
            return;
        }
        String targetKind = textOrNull(operation.at("/target/kind"));
        String resolver = textOrNull(operation.at("/target/resolver"));
        if (isBlank(targetKind) || isBlank(resolver)) {
            return;
        }
        ArrayNode editableTargets = manifest.get("editableTargets") instanceof ArrayNode existingTargets
                ? existingTargets
                : manifest.putArray("editableTargets");
        for (JsonNode target : editableTargets) {
            if (targetKind.equals(textOrNull(target.get("kind")))
                    && resolver.equals(textOrNull(target.get("resolver")))) {
                return;
            }
        }
        ObjectNode target = objectMapper.createObjectNode();
        target.put("kind", targetKind);
        target.put("resolver", resolver);
        editableTargets.add(target);
    }

    private ObjectNode tableManifestOperationFromRuntimeContract(String operationId) {
        return switch (operationId) {
            case "column.renderer.set" -> tableManifestColumnRendererOperation();
            case "column.valueMapping.set" -> tableManifestColumnValueMappingOperation();
            case "column.conditionalRenderer.add" -> tableManifestColumnConditionalRendererOperation();
            case "column.conditionalStyle.add" -> tableManifestColumnConditionalStyleOperation();
            case "table.filter.apply" -> tableManifestRuntimeFilterApplyOperation();
            case "table.export.run" -> tableManifestRuntimeExportRunOperation();
            case "dynamicPage.surface.open" -> tableManifestDynamicPageSurfaceOpenOperation();
            default -> null;
        };
    }

